ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Una cala fondeadero solitaria en el extremo noroccidental de la península de Datça. El fondo es de arena y algas; se permite fondear y no hay servicios en tierra.' FROM locations WHERE slug = 'mersincik-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Уединённая якорная бухта на северо-западной оконечности полуострова Datça. Дно — песок и водоросли; якорная стоянка разрешена, услуг на берегу нет.' FROM locations WHERE slug = 'mersincik-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A natural anchorage bay on the western shore of the Gulf of Göcek, between Sarsala and Taşyaka. The bottom is a mix of sand, mud, rock and weed; anchoring and taking stern lines ashore are practised.' FROM locations WHERE slug = 'siralibuk-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Una cala fondeadero natural en la costa occidental del golfo de Göcek, entre Sarsala y Taşyaka. El fondo es una mezcla de arena, fango, roca y algas; se practica el fondeo y el amarre con cabos a tierra por popa.' FROM locations WHERE slug = 'siralibuk-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Естественная якорная бухта на западном берегу залива Göcek, между Sarsala и Taşyaka. Дно — смесь песка, ила, камня и водорослей; здесь встают на якорь и заводят кормовые швартовы на берег.' FROM locations WHERE slug = 'siralibuk-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A quiet anchorage bay on the western shore of the Gulf of Göcek, south of Boynuzbükü. The bottom is sand; boats anchor and moor with stern lines ashore, and there are no facilities in the bay.' FROM locations WHERE slug = 'kille-buku'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Una cala fondeadero tranquila en la costa occidental del golfo de Göcek, al sur de Boynuzbükü. El fondo es de arena; se fondea y se amarra con cabos a tierra por popa, y no hay instalaciones en la cala.' FROM locations WHERE slug = 'kille-buku'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Тихая якорная бухта на западном берегу залива Göcek, к югу от Boynuzbükü. Дно песчаное; суда встают на якорь и швартуются кормой к берегу, никакой инфраструктуры в бухте нет.' FROM locations WHERE slug = 'kille-buku'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A group of low islands lying off Göcek; boats anchor in the shallow sandy area between the islands or moor with stern lines ashore. The bottom is sand and rock; a small number of visitor buoys have been reported in the area.' FROM locations WHERE slug = 'yassica-adalari'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Un grupo de islas bajas frente a Göcek; las embarcaciones fondean en la zona arenosa poco profunda entre las islas o se amarran con cabos a tierra por popa. El fondo es de arena y roca; se ha informado de un reducido número de boyas para visitantes en la zona.' FROM locations WHERE slug = 'yassica-adalari'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Группа низких островов перед Göcek; суда встают на якорь на мелководном песчаном участке между островами или швартуются кормой к берегу. Дно — песок и камень; сообщается о небольшом числе гостевых буёв в этом районе.' FROM locations WHERE slug = 'yassica-adalari'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'In the bay of Tersane Adası there is a historic anchorage, with the ruins of a Byzantine-Ottoman era shipyard at its entrance. Anchor in about 14 m and moor with stern lines ashore; the holding is good, and the two small inlets at the head of the bay are shallow.' FROM locations WHERE slug = 'tersane-adasi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'En la cala de Tersane Adası hay un fondeadero histórico, con ruinas de unos astilleros de época bizantino-otomana en su entrada. Se fondea en unos 14 m amarrándose con cabos a tierra por popa; el agarre es bueno, y las dos pequeñas bocanas del fondo de la cala son poco profundas.' FROM locations WHERE slug = 'tersane-adasi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'В бухте острова Tersane Adası находится историческая якорная стоянка, у входа в которую сохранились руины верфи византийско-османской эпохи. Якорь отдают на глубине около 14 м со швартовкой кормой к берегу; держит хорошо, а два маленьких заливчика в глубине бухты мелководны.' FROM locations WHERE slug = 'tersane-adasi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Also known as Manastır Koyu, the bay is an anchorage famous for the ruins of the ''Kleopatra Hamamı'' on its shore. Anchor on a sandy bottom in 10-12 m in the southern/western part; the bay is open to the north, and the reef extending from the south-eastern islet is a hazard.' FROM locations WHERE slug = 'hamam-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Conocida también como Manastır Koyu, la cala es un fondeadero famoso por las ruinas del ''Kleopatra Hamamı'' en su orilla. Se fondea sobre fondo de arena en 10-12 m en la parte sur/oeste; la cala está abierta al norte y el arrecife que se extiende desde el islote del sureste supone un peligro.' FROM locations WHERE slug = 'hamam-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта, известная также как Manastır Koyu, — якорная стоянка, знаменитая руинами «Kleopatra Hamamı» на берегу. Якорь отдают на песчаное дно на глубине 10-12 м в южной/западной части; бухта открыта к северу, а риф, тянущийся от юго-восточного островка, представляет опасность.' FROM locations WHERE slug = 'hamam-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A bay on the eastern shore of the Gulf of Fethiye, within a forested nature park. The bottom is mud and anchoring is permitted; there is a beach and a seasonal snack kiosk ashore.' FROM locations WHERE slug = 'katranci-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Una cala en la costa oriental del golfo de Fethiye, dentro de un parque natural boscoso. El fondo es de fango y se permite fondear; en la costa hay una playa y un quiosco de temporada.' FROM locations WHERE slug = 'katranci-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта на восточном берегу залива Fethiye, на территории лесистого природного парка. Дно илистое, якорная стоянка разрешена; на берегу пляж и сезонный киоск.' FROM locations WHERE slug = 'katranci-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'An anchorage bay on the eastern shore of the Gulf of Fethiye, near Katrancı, surrounded by pine forests. The bottom is mud and anchoring is permitted; there is a beach ashore.' FROM locations WHERE slug = 'kucuk-kargi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Una cala fondeadero en la costa oriental del golfo de Fethiye, cerca de Katrancı, rodeada de pinares. El fondo es de fango y se permite fondear; en la costa hay una playa.' FROM locations WHERE slug = 'kucuk-kargi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная бухта на восточном берегу залива Fethiye, недалеко от Katrancı, окружённая сосновыми лесами. Дно илистое, якорная стоянка разрешена; на берегу есть пляж.' FROM locations WHERE slug = 'kucuk-kargi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A bay on the northern shore of the gulf, about 2 miles west of the Fethiye harbour entrance, known for its restaurant. It is usually calm in the summer months and suitable for anchoring; outside the bay the bottom drops steeply to 45-50 m.' FROM locations WHERE slug = 'turunc-pinari-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Una cala en la costa norte del golfo, a unas 2 millas al oeste de la entrada del puerto de Fethiye, conocida por su restaurante. En los meses de verano suele estar tranquila y es apta para fondear; fuera de la cala el fondo cae bruscamente hasta 45-50 m.' FROM locations WHERE slug = 'turunc-pinari-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта на северном берегу залива, примерно в 2 милях к западу от входа в гавань Fethiye, известная своим рестораном. В летние месяцы здесь обычно спокойно, бухта подходит для якорной стоянки; за пределами бухты дно круто обрывается до 45-50 м.' FROM locations WHERE slug = 'turunc-pinari-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Göbün (Kapı Creek) bay, in the south-east of the Kapıdağ Peninsula, is included in the paid mooring system of the Göcek Special Environmental Protection Area. Under the 2025 regime, instead of free anchoring, the bays use the shore ring/stern mooring/buoy systems operated by the Türkiye Çevre Ajansı; the bottom of the bay is sand.' FROM locations WHERE slug = 'gobun-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La cala de Göbün (Kapı Creek), al sureste de la península de Kapıdağ, está incluida en el sistema de amarre de pago de la Zona de Protección Ambiental Especial de Göcek. Con el régimen de 2025, en lugar del fondeo libre, en las calas se utilizan los sistemas de argollas de tierra/muertos/boyas gestionados por la Türkiye Çevre Ajansı; el fondo de la cala es de arena.' FROM locations WHERE slug = 'gobun-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта Göbün (Kapı Creek) на юго-востоке полуострова Kapıdağ входит в платную систему швартовки особой природоохранной зоны Göcek. По режиму 2025 года вместо свободной якорной стоянки в бухтах используются системы береговых рымов/рейдовых бочек/буёв, обслуживаемые агентством Türkiye Çevre Ajansı; дно бухты песчаное.' FROM locations WHERE slug = 'gobun-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The large Sarsala bay on the western shore of the Gulf of Göcek is among the bays where a buoy/stern mooring system has been installed under the 2025 Göcek mooring regime, and the system is operated for a fee by the Türkiye Çevre Ajansı. The bay is open to the north-east.' FROM locations WHERE slug = 'sarsala-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La gran cala de Sarsala, en la costa occidental del golfo de Göcek, figura entre las calas donde se ha instalado un sistema de boyas/muertos con el régimen de amarre de Göcek de 2025, y el sistema lo gestiona de pago la Türkiye Çevre Ajansı. La cala está abierta al nordeste.' FROM locations WHERE slug = 'sarsala-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Большая бухта Sarsala на западном берегу залива Göcek входит в число бухт, где по режиму швартовки Göcek 2025 года установлена система буёв/рейдовых бочек; система платно эксплуатируется агентством Türkiye Çevre Ajansı. Бухта открыта к северо-востоку.' FROM locations WHERE slug = 'sarsala-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Boynuzbükü, a wooded and deep bay in the north-west of the Gulf of Göcek, is included in the paid buoy/stern mooring system under the 2025 Göcek mooring regime; the system is operated by the Türkiye Çevre Ajansı. The bottom of the bay is mud.' FROM locations WHERE slug = 'boynuzbuku-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Boynuzbükü, una cala arbolada y profunda en el noroeste del golfo de Göcek, está incluida en el sistema de pago de boyas/muertos del régimen de amarre de Göcek de 2025; el sistema lo gestiona la Türkiye Çevre Ajansı. El fondo de la cala es de fango.' FROM locations WHERE slug = 'boynuzbuku-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Boynuzbükü — лесистая и глубокая бухта на северо-западе залива Göcek — включена в платную систему буёв/рейдовых бочек по режиму швартовки Göcek 2025 года; система эксплуатируется агентством Türkiye Çevre Ajansı. Дно бухты илистое.' FROM locations WHERE slug = 'boynuzbuku-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Also known as Taşyaka, the bay is famous for its Lycian rock tombs and for the fish figure by Bedri Rahmi Eyüboğlu; under the 2025 Göcek mooring regime it is among the bays where the paid buoy/stern mooring system of the Türkiye Çevre Ajansı has been installed. It offers a wide and sheltered mooring area north-west of the Taşkaya islet.' FROM locations WHERE slug = 'bedri-rahmi-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Conocida también como Taşyaka, la cala es famosa por sus tumbas rupestres licias y por la figura del pez de Bedri Rahmi Eyüboğlu; en el régimen de amarre de Göcek de 2025 figura entre las calas donde se ha instalado el sistema de pago de boyas/muertos de la Türkiye Çevre Ajansı. Ofrece una zona de amarre amplia y abrigada al noroeste del islote de Taşkaya.' FROM locations WHERE slug = 'bedri-rahmi-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта, известная также как Taşyaka, славится ликийскими скальными гробницами и фигурой рыбы работы Bedri Rahmi Eyüboğlu; по режиму швартовки Göcek 2025 года она входит в число бухт, где установлена платная система буёв/рейдовых бочек агентства Türkiye Çevre Ajansı. К северо-западу от островка Taşkaya она предлагает обширную и защищённую зону швартовки.' FROM locations WHERE slug = 'bedri-rahmi-samandira-sahasi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
-- --- i18n_tur2.json (i18n-tur2) ---
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A harbour 1,5 miles from the Black Sea exit of the İstanbul Boğazı, protected by a 470 m main breakwater; boats anchor behind the breakwater or moor to the quay. Holding is good and it is sheltered from all directions. Fuel can reportedly be brought in on request, and minor repair facilities are reported.' FROM locations WHERE slug = 'poyrazkoy-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio a 1,5 millas de la salida del İstanbul Boğazı al mar Negro, protegido por un rompeolas principal de 470 m; las embarcaciones fondean tras el rompeolas o se amarran al muelle. El agarre es bueno y está abrigado de todas las direcciones. Se informa de que se puede traer combustible bajo pedido y de que hay posibilidad de pequeñas reparaciones.' FROM locations WHERE slug = 'poyrazkoy-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань в 1,5 мили от черноморского выхода İstanbul Boğazı, защищённая главным молом длиной 470 м; суда встают на якорь за молом или швартуются к причалу. Якорь держит хорошо, укрытие со всех направлений. Сообщается, что по запросу можно доставить топливо и выполнить мелкий ремонт.' FROM locations WHERE slug = 'poyrazkoy-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'On the southwest of Heybeliada, the only natural anchorage genuinely sheltered from the prevailing north/northeast winds of the Adalar. Holding is good on a sand and weed bottom; on weekends it hosts the 50-60 boats that come from İstanbul.' FROM locations WHERE slug = 'cam-limani-koyu-heybeliada'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'En el suroeste de Heybeliada, el único fondeadero natural realmente abrigado de los vientos dominantes del norte/nordeste de las Adalar. El agarre es bueno sobre fondo de arena y algas; los fines de semana acoge 50-60 embarcaciones procedentes de İstanbul.' FROM locations WHERE slug = 'cam-limani-koyu-heybeliada'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'На юго-западе Heybeliada — единственная естественная якорная стоянка, по-настоящему укрытая от господствующих северных/северо-восточных ветров Adalar. Якорь держит хорошо на песчаном дне с водорослями; по выходным принимает 50-60 судов, приходящих из İstanbul.' FROM locations WHERE slug = 'cam-limani-koyu-heybeliada'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchorage area on the north coast of Büyükada, west of the ferry pier, in 3-5 m depth over a sand and weed bottom. As it is exposed to the prevailing north/northeast winds, it is suitable only in calm weather; overnight stays are not recommended.' FROM locations WHERE slug = 'buyukada-kuzey-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Zona de fondeo en la costa norte de Büyükada, al oeste del embarcadero de los ferris, con 3-5 m de sonda sobre fondo de arena y algas. Al estar expuesta a los vientos dominantes del norte/nordeste, solo es adecuada con tiempo en calma; no se recomienda pernoctar.' FROM locations WHERE slug = 'buyukada-kuzey-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная стоянка у северного берега Büyükada, к западу от паромного причала, на глубине 3-5 м, дно — песок с водорослями. Открыта господствующим северным/северо-восточным ветрам, поэтому подходит только в тихую погоду; ночёвка не рекомендуется.' FROM locations WHERE slug = 'buyukada-kuzey-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'South of the eastern pier on Burgazada there are about 15 mooring buoys laid by the shoreside restaurants; in the lee of the pier there is reasonable shelter. Except in very calm weather it is not suitable for overnight stays; it is mainly a lunch stop.' FROM locations WHERE slug = 'burgazada-restoran-samandiralari'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Al sur del embarcadero oriental de Burgazada hay unas 15 boyas de amarre instaladas por los restaurantes de la costa; a sotavento del embarcadero ofrece un abrigo razonable. Salvo con tiempo muy en calma no es adecuado para pernoctar; es sobre todo una parada para almorzar.' FROM locations WHERE slug = 'burgazada-restoran-samandiralari'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'К югу от восточного пирса Burgazada выставлено около 15 швартовных буёв, установленных прибрежными ресторанами; с подветренной стороны пирса укрытие приемлемое. Кроме совсем тихой погоды для ночёвки не подходит — это в основном остановка на обед.' FROM locations WHERE slug = 'burgazada-restoran-samandiralari'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Harbour on Büyükada with a capacity of about 80 boats and a 115 m breakwater; electricity, water and fuel are reported to be available. It is used mainly by local and fishing boats.' FROM locations WHERE slug = 'buyukada-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio en Büyükada con capacidad para unas 80 embarcaciones y un rompeolas de 115 m; se informa de que dispone de electricidad, agua y combustible. Lo utilizan sobre todo embarcaciones locales y pesqueros.' FROM locations WHERE slug = 'buyukada-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань на Büyükada вместимостью около 80 судов с молом длиной 115 м; сообщается о наличии электричества, воды и топлива. Используется в основном местными и рыбацкими судами.' FROM locations WHERE slug = 'buyukada-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Municipal harbour in the main settlement of Marmara Adası; capacity is about 125 boats, and 6-8 visiting yachts can berth bows-to/stern-to on the north quay. Shelter is good in the prevailing north/northeast winds, though squally gusts can come down off the mountain. Depths alongside the quay are 1,5-2,5 m; deep-draught boats should anchor off the quay.' FROM locations WHERE slug = 'marmara-adasi-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto municipal en el núcleo principal de Marmara Adası; tiene capacidad para unas 125 embarcaciones y en el muelle norte pueden amarrarse de proa/popa 6-8 yates visitantes. El abrigo es bueno con los vientos dominantes del norte/nordeste, aunque pueden bajar rachas violentas desde la montaña. La sonda junto al muelle es de 1,5-2,5 m; los barcos de mucho calado deben fondear frente al muelle.' FROM locations WHERE slug = 'marmara-adasi-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Муниципальный порт в главном посёлке Marmara Adası; вместимость около 125 судов, на северном причале 6-8 гостевых яхт могут швартоваться носом/кормой к причалу. Укрытие хорошее при господствующих северных/северо-восточных ветрах, но с горы могут срываться шквалистые порывы. Глубины у причала 1,5-2,5 м; судам с большой осадкой следует встать на якорь напротив причала.' FROM locations WHERE slug = 'marmara-adasi-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Municipal harbour on the north of Marmara Adası, built of marble blocks; about 50 yachts (maximum 15 m) can berth alongside or stern-to on the eastern breakwater. Holding is good in the mud bottom and shelter is very good. The western quay is shallow (~1,5 m).' FROM locations WHERE slug = 'saraylar-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio municipal en el norte de Marmara Adası, construido con bloques de mármol; unos 50 yates (máximo 15 m) pueden amarrarse abarloados o de popa al rompeolas oriental. El agarre es bueno en fondo de fango y el abrigo es muy bueno. El muelle occidental es poco profundo (~1,5 m).' FROM locations WHERE slug = 'saraylar-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Муниципальная гавань на севере Marmara Adası, построенная из мраморных блоков; около 50 яхт (максимум 15 м) могут швартоваться лагом или кормой к восточному молу. Илистое дно держит якорь хорошо, укрытие очень хорошее. Западный причал мелководный (~1,5 м).' FROM locations WHERE slug = 'saraylar-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Harbour of the village of Yiğitler on the east coast of Avşa Adası; visiting boats berth stern-to on the west wall of the eastern basin or come alongside with two anchors, and a municipal official collects the mooring fee. Holding is good in the sand bottom, and shelter in the eastern basin is good.' FROM locations WHERE slug = 'yigitler-limani-avsa'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto del pueblo de Yiğitler, en la costa este de Avşa Adası; las embarcaciones visitantes se amarran de popa al muro oeste de la dársena oriental o se atracan con dos anclas, y un empleado municipal cobra la tarifa de amarre. El agarre es bueno en fondo de arena y el abrigo en la dársena oriental es bueno.' FROM locations WHERE slug = 'yigitler-limani-avsa'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Порт деревни Yiğitler на восточном берегу Avşa Adası; гостевые суда швартуются кормой к западной стенке восточного бассейна или подходят на двух якорях, плату за стоянку взимает служащий муниципалитета. Песчаное дно держит якорь хорошо, укрытие в восточном бассейне хорошее.' FROM locations WHERE slug = 'yigitler-limani-avsa'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchorage area off the main settlement of Türkeli on the west coast of Avşa Adası; the town offers a wide range of markets, restaurants and guesthouses. There are sea bus/ferry connections to İstanbul. It is exposed to winds from the western sector.' FROM locations WHERE slug = 'avsa-turkeli-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Zona de fondeo frente al núcleo principal de Türkeli, en la costa oeste de Avşa Adası; el pueblo ofrece una amplia oferta de supermercados, restaurantes y pensiones. Hay conexiones de catamarán rápido/ferri con İstanbul. Está expuesta a los vientos del sector oeste.' FROM locations WHERE slug = 'avsa-turkeli-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная стоянка напротив главного посёлка Türkeli на западном берегу Avşa Adası; в городке широкий выбор магазинов, ресторанов и пансионов. Есть сообщение морским автобусом/паромом с İstanbul. Стоянка открыта ветрам западного сектора.' FROM locations WHERE slug = 'avsa-turkeli-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchorage area over a sand bottom off Ekinlik (Koutali) Adası, northwest of Avşa; anchoring is free. Ashore there are a small snack bar and a beach; there is no water and no pier service.' FROM locations WHERE slug = 'ekinlik-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Zona de fondeo sobre fondo de arena frente a Ekinlik (Koutali) Adası, al noroeste de Avşa; el fondeo es libre. En tierra hay un pequeño quiosco y una playa; no hay agua ni servicio de muelle.' FROM locations WHERE slug = 'ekinlik-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная стоянка с песчаным дном у Ekinlik (Koutali) Adası, к северо-западу от Avşa; якорная стоянка свободная. На берегу есть небольшой киоск и пляж; воды и причального сервиса нет.' FROM locations WHERE slug = 'ekinlik-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Open anchorage off Paşalimanı Adası in 5-10 m over a sand and weed bottom; once the anchor sets in the bottom, holding is good. Ashore there are a restaurant and a bakery.' FROM locations WHERE slug = 'pasalimani-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Fondeadero abierto frente a Paşalimanı Adası, en 5-10 m sobre fondo de arena y algas; una vez que el ancla agarra en el fondo, el agarre es bueno. En tierra hay un restaurante y una panadería.' FROM locations WHERE slug = 'pasalimani-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Открытая якорная стоянка у Paşalimanı Adası на глубине 5-10 м, дно — песок с водорослями; когда якорь заберёт за грунт, держит хорошо. На берегу есть ресторан и пекарня.' FROM locations WHERE slug = 'pasalimani-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Harbour at Karabiga, in the district of Biga, working as a fishing and dry-cargo pier; yachts usually berth stern-to on the outer face of the fishing quay, and if necessary the commercial quay to the north is used. In east/northeast winds an uncomfortable swell enters, and anchor holding is reported to be poor. There is no water or electricity.' FROM locations WHERE slug = 'karabiga-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto de Karabiga, dependiente de Biga, que funciona como muelle pesquero y de carga seca; los yates suelen amarrarse de popa a la cara exterior del muelle pesquero y, si es necesario, se utiliza el muelle comercial del norte. Con vientos del este/nordeste entra una marejada incómoda y se ha informado de que el agarre del ancla es deficiente. No hay agua ni electricidad.' FROM locations WHERE slug = 'karabiga-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Порт в Karabiga (район Biga), работающий как рыбацкий и сухогрузный причал; яхты обычно швартуются кормой к внешней стороне рыбацкого причала, при необходимости используется коммерческий причал севернее. При восточных/северо-восточных ветрах заходит неприятная зыбь; сообщается, что якорь держит плохо. Воды и электричества нет.' FROM locations WHERE slug = 'karabiga-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Large harbour with a 695 m breakwater on the east coast of the Kapıdağ Yarımadası, 6 miles northeast of Bandırma; as the quay is full of trawlers, visiting boats anchor at the northern end of the harbour. Holding is good and it is a sheltered stopover point.' FROM locations WHERE slug = 'cakilkoy-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Gran refugio con un rompeolas de 695 m en la costa este de la Kapıdağ Yarımadası, 6 millas al nordeste de Bandırma; como el muelle está lleno de arrastreros, las embarcaciones visitantes fondean en el extremo norte del refugio. El agarre es bueno y es un punto de escala abrigado.' FROM locations WHERE slug = 'cakilkoy-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Большая гавань с молом длиной 695 м на восточном берегу Kapıdağ Yarımadası, в 6 милях к северо-востоку от Bandırma; причал занят траулерами, поэтому гостевые суда встают на якорь в северной части гавани. Якорь держит хорошо, это укрытая промежуточная стоянка.' FROM locations WHERE slug = 'cakilkoy-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Harbour in the district centre of Şarköy; visiting boats can berth stern-to or alongside. Electricity, water, showers, WC and fuel (diesel/petrol) are reported to be available.' FROM locations WHERE slug = 'sarkoy-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto en el centro del municipio de Şarköy; las embarcaciones visitantes pueden amarrarse de popa o abarloadas. Se informa de que dispone de electricidad, agua, duchas, WC y combustible (diésel/gasolina).' FROM locations WHERE slug = 'sarkoy-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Порт в центре района Şarköy; гостевые суда могут швартоваться кормой или лагом. Сообщается о наличии электричества, воды, душа, туалета и топлива (дизель/бензин).' FROM locations WHERE slug = 'sarkoy-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The main harbour in the northeast of Bozcaada, at the foot of the castle. Visiting boats berth stern-to or alongside along the breakwater; ground chain tackle is laid ~40 m off the shore. It provides adequate shelter from all directions except east-southeast winds. There are 13 water/electricity points on the quay. The official yacht capacity is 30 (TKYGM list); together with fishing boats it holds ~125 vessels in total. Maximum draught ~3 m. Fuel supply by tanker, slipway/haul-out, ice and rope supply are reported.' FROM locations WHERE slug = 'bozcaada-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto principal del nordeste de Bozcaada, al pie del castillo. Las embarcaciones visitantes se amarran de popa o abarloadas a lo largo del rompeolas; hay una cadena madre fondeada a ~40 m de la costa. Ofrece abrigo suficiente de todas las direcciones salvo de los vientos del este-sudeste. En el muelle hay 13 tomas de agua/electricidad. La capacidad oficial para yates es de 30 (lista TKYGM); junto con los pesqueros alberga en total ~125 embarcaciones. Calado máximo ~3 m. Se informa de suministro de combustible por camión cisterna, rampa/varadero, hielo y suministro de cabos.' FROM locations WHERE slug = 'bozcaada-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Главный порт на северо-востоке Bozcaada, у подножия крепости. Гостевые суда швартуются кормой или лагом вдоль волнолома; в ~40 м от берега проложена донная цепь для швартовки. Обеспечивает достаточное укрытие со всех направлений, кроме восточно-юго-восточных ветров. На причале 13 точек воды/электричества. Официальная вместимость для яхт — 30 (список TKYGM); вместе с рыбацкими судами всего вмещает ~125 судов. Максимальная осадка ~3 м. Сообщается о заправке топливом с автоцистерны, слипе/подъёме судов, льде и продаже швартовных концов.' FROM locations WHERE slug = 'bozcaada-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The new harbour on the north coast of Gökçeada; the most suitable berthing place for yachts on the island. Boats berth alongside the north breakwater; if it is full, you may have to go alongside fishing boats. Depths are 5,0-5,5 m at the entrance and 3,0-3,5 m at the north quay; at the entrance beware of the sand shoal off the end of the north breakwater. Excellent shelter from all directions. There are water and electricity points along the quay and fish restaurants ashore; there is no fuel. A minibus leaves for the centre every hour.' FROM locations WHERE slug = 'gokceada-kalekoy-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto nuevo de la costa norte de Gökçeada; el lugar de amarre más adecuado para los yates en la isla. Se amarra abarloado al rompeolas norte; si está lleno, puede ser necesario abarloarse a los pesqueros. La sonda es de 5,0-5,5 m en la entrada y de 3,0-3,5 m en el muelle norte; en la entrada hay que prestar atención al bajo de arena junto al extremo del rompeolas norte. Abrigo excelente de todas las direcciones. A lo largo del muelle hay tomas de agua y electricidad y en la costa hay restaurantes de pescado; no hay combustible. Cada hora sale un microbús hacia el centro.' FROM locations WHERE slug = 'gokceada-kalekoy-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Новый порт на северном берегу Gökçeada; самое удобное место швартовки для яхт на острове. Швартуются лагом вдоль северного волнолома; если занято, возможно, придётся вставать лагом к рыбацким судам. Глубины 5,0-5,5 м на входе и 3,0-3,5 м у северного причала; на входе остерегайтесь песчаной отмели у оконечности северного волнолома. Отличное укрытие со всех направлений. Вдоль причала — точки воды и электричества, на берегу — рыбные рестораны; топлива нет. Каждый час в центр отправляется маршрутка.' FROM locations WHERE slug = 'gokceada-kalekoy-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The old main harbour and ferry pier at the northeastern tip of the island, operated by TDİ. It is a cramped harbour with limited facilities for yachts, but it gives good shelter, especially in north-northeast winds, and is used as a harbour of refuge in bad weather. It may be full of local boats. Water supply is limited and there is no fuel station. Kaleköy, 3 miles away, is a better alternative.' FROM locations WHERE slug = 'gokceada-kuzu-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El antiguo puerto principal y embarcadero del ferri en el extremo nordeste de la isla, gestionado por TDİ. Es un puerto angosto con instalaciones limitadas para yates, pero ofrece buen abrigo, sobre todo con vientos del norte-nordeste, y se utiliza como puerto de refugio con mal tiempo. Puede estar lleno de embarcaciones locales. El suministro de agua es limitado y no hay estación de combustible. Kaleköy, a 3 millas, es una alternativa mejor.' FROM locations WHERE slug = 'gokceada-kuzu-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Старый главный порт и паромный причал на северо-восточной оконечности острова; находится в ведении TDİ. Тесный порт с ограниченными возможностями для яхт, но даёт хорошее укрытие, особенно при северо-северо-восточных ветрах; в плохую погоду используется как порт-убежище. Может быть занят местными судами. Снабжение водой ограничено, топливной станции нет. Kaleköy в 3 милях — лучшая альтернатива.' FROM locations WHERE slug = 'gokceada-kuzu-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A small historic stone harbour below the ancient city of Assos; fish restaurants line the quay and visiting boats moor in front of the restaurants. Capacity ~50 boats (mostly local/excursion boats). The breakwaters shut out the north winds; as the entrance is narrow, care is needed on a night approach. It can be uncomfortable in winds from the southwest sector. Electricity, drinking water and WC are available.' FROM locations WHERE slug = 'behramkale-assos-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Pequeño puerto histórico de piedra bajo la ciudad antigua de Assos; los restaurantes de pescado se alinean a lo largo del muelle y las embarcaciones visitantes se amarran frente a los restaurantes. Capacidad ~50 embarcaciones (la mayoría barcos locales/de excursión). Los rompeolas cierran el paso a los vientos del norte; como la entrada es estrecha, hay que tener cuidado en la aproximación nocturna. Puede resultar incómodo con vientos del sector sudoeste. Hay electricidad, agua potable y WC.' FROM locations WHERE slug = 'behramkale-assos-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Маленький исторический каменный порт под античным городом Assos; вдоль причала выстроились рыбные рестораны, и гостевые суда швартуются перед ресторанами. Вместимость ~50 судов (в основном местные/экскурсионные). Волноломы закрывают от северных ветров; вход узкий, поэтому при ночном подходе нужна осторожность. При ветрах юго-западного сектора может быть некомфортно. Есть электричество, питьевая вода и туалет.' FROM locations WHERE slug = 'behramkale-assos-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The breakwater-protected harbour of the town of Küçükkuyu on the northern shore of the Edremit Körfezi, at the foot of Kazdağı. Although it is mainly a shelter for fishing and excursion boats, it is possible to berth at the pier/quay. It is sheltered in winds from the northern sector. Markets and restaurants in the town are within walking distance.' FROM locations WHERE slug = 'kucukkuyu-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto protegido por rompeolas de la localidad de Küçükkuyu, en la costa norte del Edremit Körfezi, a los pies del Kazdağı. Aunque es sobre todo un refugio de pesqueros y barcos de excursión, es posible amarrarse al embarcadero/muelle. Está abrigado con vientos del sector norte. Los supermercados y restaurantes del pueblo quedan a poca distancia a pie.' FROM locations WHERE slug = 'kucukkuyu-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Защищённый волноломом порт посёлка Küçükkuyu на северном берегу Edremit Körfezi, у подножия Kazdağı. Хотя это в основном стоянка рыбацких и прогулочных судов, швартовка к пирсу/причалу возможна. Укрыт при ветрах северного сектора. Магазины и рестораны посёлка — в пешей доступности.' FROM locations WHERE slug = 'kucukkuyu-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Municipally operated yacht harbour and adjoining fishing shelter at Burhaniye İskele/Ören, in the southeast of the Edremit Körfezi. Capacity ~250 boats; the entrance is straightforward and depths inside the harbour are 3-4 m. The main breakwater is 537 m; there is a slipway. Winds from the northern sector prevail in the area, and it is advisable to get assistance when mooring. Renovation works were carried out in 2023-24 and a coastal facility operating licence was obtained. Fuel can be supplied by tanker, and there is a yacht chandlery in the area.' FROM locations WHERE slug = 'burhaniye-oren-yat-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto deportivo de gestión municipal y refugio pesquero contiguo en Burhaniye İskele/Ören, en el sudeste del Edremit Körfezi. Capacidad ~250 embarcaciones; la entrada no presenta problemas y la sonda dentro del puerto es de 3-4 m. El rompeolas principal mide 537 m; hay rampa de varada. En la zona predominan los vientos del sector norte y se recomienda pedir ayuda al amarrar. En 2023-24 se realizaron obras de renovación y se obtuvo la licencia de explotación de instalación costera. Se puede repostar combustible mediante camión cisterna y en los alrededores hay una tienda de efectos navales.' FROM locations WHERE slug = 'burhaniye-oren-yat-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Яхтенный порт под управлением муниципалитета и прилегающая рыбацкая гавань в местечке Burhaniye İskele/Ören, на юго-востоке Edremit Körfezi. Вместимость ~250 судов; вход несложный, глубины в порту 3-4 м. Главный волнолом — 537 м; есть слип. В районе преобладают ветры северного сектора, при швартовке рекомендуется брать помощь. В 2023-24 годах проведены работы по реконструкции и получена лицензия на эксплуатацию берегового объекта. Возможна заправка топливом с автоцистерны, поблизости есть магазин яхтенного снаряжения.' FROM locations WHERE slug = 'burhaniye-oren-yat-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Town quay of Cunda (Alibey) island, in the northwest of the Ayvalık inner sea. For visiting yachts there are 15 ready laid stern moorings tied to the quay plus additional buoys; the quay front is lined with restaurants. Depths inside the harbour are 2-3 m, the anchorage south of the pier is ~5 m and holding is good. Capacity ~145 boats. Being in the inner sea, it is well sheltered from all directions. Haul-out for boats up to 25 m and fuel supply by tanker are reported.' FROM locations WHERE slug = 'alibey-cunda-adasi-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Muelle del pueblo de la isla de Cunda (Alibey), en el noroeste del mar interior de Ayvalık. Para los yates visitantes hay 15 muertos ya instalados con guías al muelle y boyas adicionales; el frente del muelle está rodeado de restaurantes. La sonda dentro del puerto es de 2-3 m, el fondeadero al sur del embarcadero tiene ~5 m y el agarre es bueno. Capacidad ~145 embarcaciones. Al estar en el mar interior, está bien abrigado de todas las direcciones. Se informa de varadero para esloras de hasta 25 m y de suministro de combustible por camión cisterna.' FROM locations WHERE slug = 'alibey-cunda-adasi-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Городской причал острова Cunda (Alibey) на северо-западе внутреннего моря Ayvalık. Для гостевых яхт есть 15 готовых мёртвых якорей с оттяжками к причалу и дополнительные буи; набережная у причала окружена ресторанами. Глубины в порту 2-3 м, якорная стоянка южнее пирса ~5 м, якорь держит хорошо. Вместимость ~145 судов. Благодаря расположению во внутреннем море хорошо укрыт со всех направлений. Сообщается о подъёме судов длиной до 25 м и заправке топливом с автоцистерны.' FROM locations WHERE slug = 'alibey-cunda-adasi-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A large, well-sheltered anchorage bay on the north of Cunda (Alibey) island; in pilot sources it appears as Patricia Liman / Gökçeliman, and locally it is known as Patriça bay. It lies within a natural protected area; there are no facilities ashore, and day-trip boats and yachts anchor here. It is close to the entrance of the Ayvalık inner sea.' FROM locations WHERE slug = 'patrica-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Amplia cala de fondeo bien abrigada en el norte de la isla de Cunda (Alibey); en las fuentes de derrotero figura como Patricia Liman / Gökçeliman y localmente se conoce como cala de Patriça. Se encuentra dentro de un área natural protegida; no hay instalaciones en tierra, y fondean aquí barcos de excursión y yates. Está cerca de la entrada del mar interior de Ayvalık.' FROM locations WHERE slug = 'patrica-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Просторная, хорошо укрытая якорная бухта на севере острова Cunda (Alibey); в лоцманских источниках фигурирует как Patricia Liman / Gökçeliman, у местных известна как бухта Patriça. Находится в границах природоохранной зоны; на берегу нет никакой инфраструктуры, на якорь встают прогулочные суда и яхты. Расположена недалеко от входа во внутреннее море Ayvalık.' FROM locations WHERE slug = 'patrica-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchorage bay on Maden Adası, northwest of Ayvalık, giving good shelter from the meltemi. You anchor in about 5 m on a sand bottom, and holding is good. There is a shoal at the entrance of the bay, so approach with care. There are no facilities ashore.' FROM locations WHERE slug = 'maden-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala de fondeo en Maden Adası, al noroeste de Ayvalık, que ofrece buen abrigo frente al meltemi. Se fondea en unos 5 m sobre fondo de arena y el agarre es bueno. Hay un bajo en la entrada de la cala, por lo que hay que aproximarse con cuidado. No hay instalaciones en tierra.' FROM locations WHERE slug = 'maden-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная бухта на Maden Adası к северо-западу от Ayvalık, дающая хорошее укрытие от мельтеми. Встают на якорь на глубине около 5 м на песчаном дне, якорь держит хорошо. У входа в бухту есть отмель, подходить следует осторожно. На берегу инфраструктуры нет.' FROM locations WHERE slug = 'maden-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchorage in the Ayvalık inner sea, at the southern end of the channel between Moska island and Alibey island. It gives good shelter in winds from the southern sector. There are no facilities ashore; it is used for daytime and overnight anchoring.' FROM locations WHERE slug = 'moska-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Fondeadero en el mar interior de Ayvalık, en el extremo sur del canal entre la isla de Moska y la isla de Alibey. Ofrece buen abrigo con vientos del sector sur. No hay instalaciones en tierra; se utiliza para fondear de día y para pernoctar.' FROM locations WHERE slug = 'moska-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная стоянка во внутреннем море Ayvalık, у южного конца пролива между островами Moska и Alibey. Даёт хорошее укрытие при ветрах южного сектора. На берегу инфраструктуры нет; используется для дневной и ночной якорной стоянки.' FROM locations WHERE slug = 'moska-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A very attractive anchorage bay in the south of the Ayvalık inner sea, completely enclosed by land. It gives shelter from all directions. There are no facilities ashore.' FROM locations WHERE slug = 'kumru-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Una cala de fondeo muy atractiva en el sur del mar interior de Ayvalık, completamente rodeada de tierra. Ofrece abrigo de todas las direcciones. No hay instalaciones en tierra.' FROM locations WHERE slug = 'kumru-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Очень привлекательная якорная бухта на юге внутреннего моря Ayvalık, полностью окружённая сушей. Даёт укрытие со всех направлений. На берегу инфраструктуры нет.' FROM locations WHERE slug = 'kumru-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchorage bay at Çamlık, south of Ayvalık, with a view of Çanak Tepe. It gives good shelter except in wind blowing from the south. There is a restaurant ashore; as its own jetty could not be confirmed, you anchor and go ashore by dinghy.' FROM locations WHERE slug = 'camlik-koyu-demirleme-ayvalik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala de fondeo en Çamlık, al sur de Ayvalık, con vistas a Çanak Tepe. Ofrece buen abrigo salvo con viento del sur. En la costa hay un restaurante; como no se ha podido confirmar que tenga embarcadero propio, se fondea y se desembarca con el auxiliar.' FROM locations WHERE slug = 'camlik-koyu-demirleme-ayvalik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная бухта в местечке Çamlık к югу от Ayvalık с видом на Çanak Tepe. Даёт хорошее укрытие, кроме ветра, дующего с юга. На берегу есть ресторан; наличие собственного причала не подтверждено, поэтому встают на якорь и высаживаются на тузике.' FROM locations WHERE slug = 'camlik-koyu-demirleme-ayvalik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'District harbour of Dikili, opposite the island of Midilli; in the shelter section next to the commercial pier there is room for 6-7 visiting yachts. You drop anchor and berth stern-to/bows-to the quay; there are no ready laid moorings. Depths inside the harbour are 4-5 m; the approach is clear and easy. Electricity, drinking water and fuel are available on the quay; there are fish restaurants along the waterfront. Total capacity ~160 boats.' FROM locations WHERE slug = 'dikili-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto del municipio de Dikili, frente a la isla de Midilli; en la zona de refugio junto al muelle comercial hay sitio para 6-7 yates visitantes. Se fondea el ancla y se amarra de popa/proa al muelle; no hay muertos instalados. La sonda dentro del puerto es de 4-5 m; la aproximación es limpia y fácil. En el muelle se puede obtener electricidad, agua potable y combustible; en el paseo marítimo hay restaurantes de pescado. Capacidad total ~160 embarcaciones.' FROM locations WHERE slug = 'dikili-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Порт района Dikili напротив острова Midilli; в гаванной части рядом с коммерческим пирсом есть место для 6-7 гостевых яхт. Отдают якорь и швартуются кормой/носом к причалу; готовых мёртвых якорей нет. Глубины в порту 4-5 м; подход свободный и лёгкий. На причале можно взять электричество, питьевую воду и топливо; на набережной — рыбные рестораны. Общая вместимость ~160 судов.' FROM locations WHERE slug = 'dikili-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchorage bay on the Bademli coast of Dikili, just north of Kalem Adası. You anchor on a mixed sand and rock bottom; lines can be taken ashore. It has a beach that can be reached by dinghy; there are no facilities, water or pier ashore. It is known for its shallow thermal springs.' FROM locations WHERE slug = 'bademli-deniz-ilicasi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala de fondeo en la costa de Bademli, en Dikili, justo al norte de Kalem Adası. Se fondea sobre un fondo mixto de arena y roca; se pueden dar cabos a tierra. Tiene una playa a la que se llega con el auxiliar; en tierra no hay instalaciones, agua ni embarcadero. Es conocida por sus manantiales termales someros.' FROM locations WHERE slug = 'bademli-deniz-ilicasi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная бухта у побережья Bademli в районе Dikili, сразу к северу от Kalem Adası. Встают на якорь на смешанном песчано-каменистом дне; можно завести концы на берег. Есть пляж, доступный на тузике; на берегу нет инфраструктуры, воды и причала. Известна мелководными термальными источниками.' FROM locations WHERE slug = 'bademli-deniz-ilicasi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchorage bay of the privately run Kalem Adası, ~450 m off the mainland, off Bademli in Dikili; it is referred to as the ''Maldives of the Aegean''. Different sides of the island offer different shelter; the west side faces the open sea. On the island there are a hotel, a beach club and a restaurant (going ashore is subject to the operator''s permission). Markets and restaurants can be reached in the village of Bademli.' FROM locations WHERE slug = 'kalem-adasi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala de fondeo de Kalem Adası, isla de gestión privada situada a ~450 m de tierra firme, frente a Bademli, en Dikili; se la conoce como las ''Maldivas del Egeo''. Las distintas caras de la isla ofrecen distinto abrigo; la cara oeste mira al mar abierto. En la isla hay un hotel, un club de playa y un restaurante (el desembarco está sujeto al permiso del operador). En el pueblo de Bademli se puede acceder a supermercados y restaurantes.' FROM locations WHERE slug = 'kalem-adasi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная бухта частного острова Kalem Adası, в ~450 м от материка, напротив Bademli в районе Dikili; его называют ''Мальдивами Эгейского моря''. Разные стороны острова дают разное укрытие; западная сторона обращена к открытому морю. На острове есть отель, пляжный клуб и ресторан (высадка на берег — с разрешения администрации). В деревне Bademli доступны магазины и рестораны.' FROM locations WHERE slug = 'kalem-adasi-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Town harbour in the Çandarlı Körfezi, at the foot of the famous Genoese castle. In the anchorage off the castle you anchor in 4-8 m on a mud bottom; holding is very good, though plough-type anchors may drag in the soft mud. It gives shelter from all directions except the southern sector; the prevailing northerlies do not raise a sea. Electricity, pressurised water, drinking water and fuel are available on the quay; in the town there are restaurants, markets, repair workshops, a diving centre and a sailing club.' FROM locations WHERE slug = 'candarli-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto del pueblo en el Çandarlı Körfezi, al pie del famoso castillo genovés. En el fondeadero frente al castillo se fondea en 4-8 m sobre fondo de fango; el agarre es muy bueno, aunque las anclas de tipo arado pueden garrear en el fango blando. Ofrece abrigo de todas las direcciones salvo del sector sur; los vientos dominantes del norte no levantan mar. En el muelle hay electricidad, agua a presión, agua potable y combustible; en el pueblo hay restaurantes, supermercados, talleres de reparación, un centro de buceo y un club de vela.' FROM locations WHERE slug = 'candarli-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Городской порт в Çandarlı Körfezi, у подножия знаменитой генуэзской крепости. На якорной стоянке перед крепостью встают на якорь на глубине 4-8 м на илистом дне; держит очень хорошо, но в мягком иле плуговые якоря могут ползти. Даёт укрытие со всех направлений, кроме южного сектора; господствующие северные ветры волну не разводят. На причале есть электричество, вода под давлением, питьевая вода и топливо; в городке — рестораны, магазины, ремонтные мастерские, дайвинг-центр и парусный клуб.' FROM locations WHERE slug = 'candarli-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The new harbour of Mordoğan, built in 2003; the old harbour is for fishing boats, and although the new harbour is unfinished it can be used for shelter. It provides protection behind the breakwater. There are numerous reefs on the approach between the harbour and the town of Mordoğan, so approach carefully. No electricity or water services are reported.' FROM locations WHERE slug = 'mordogan-yeni-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El nuevo refugio de Mordoğan, construido en 2003; el puerto viejo es para los pesqueros y, aunque el puerto nuevo está sin terminar, puede utilizarse para abrigarse. Ofrece protección tras el rompeolas. En la aproximación entre el puerto y el pueblo de Mordoğan hay numerosos arrecifes, por lo que hay que aproximarse con cuidado. No se informa de servicios de electricidad ni de agua.' FROM locations WHERE slug = 'mordogan-yeni-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Новая гавань Mordoğan, построенная в 2003 году; старый порт предназначен для рыбацких судов, а новая гавань, хотя и не достроена, пригодна для укрытия. Защиту даёт мол. На подходе между гаванью и посёлком Mordoğan множество рифов, подходить следует осторожно. Об электричестве и воде не сообщается.' FROM locations WHERE slug = 'mordogan-yeni-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Natural anchorage bay on the west coast of the Karaburun peninsula, at the mouth of the Gerence Körfezi. It gives shelter from almost every direction, including the meltemi; however, in strong north and south winds swell can enter the bay. The entrance is about 300 m wide, with 20 m depth at the entrance; there are reefs around and three rocky islets offshore, so a night entry is not recommended. The bottom is mud and weed; the bottom shelves steeply, so beware of the sudden change in depth.' FROM locations WHERE slug = 'egri-liman-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala de fondeo natural en la costa oeste de la península de Karaburun, en la boca del Gerence Körfezi. Ofrece abrigo de casi todas las direcciones, incluido el meltemi; sin embargo, con vientos fuertes del norte y del sur puede entrar marejada en la cala. La entrada tiene unos 300 m de ancho, con 20 m de sonda en la entrada; alrededor hay arrecifes y, mar afuera, tres islotes rocosos, por lo que no se recomienda entrar de noche. El fondo es de fango y algas; la pendiente del fondo es pronunciada: atención al cambio brusco de profundidad.' FROM locations WHERE slug = 'egri-liman-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Естественная якорная бухта на западном берегу полуострова Karaburun, у входа в Gerence Körfezi. Даёт укрытие почти со всех направлений, включая мельтеми; однако при сильных северных и южных ветрах в бухту может заходить зыбь. Вход шириной около 300 м, глубина на входе 20 м; вокруг рифы, а мористее — три скалистых островка, ночной заход не рекомендуется. Дно — ил и водоросли; свал глубин крутой, остерегайтесь резкого изменения глубины.' FROM locations WHERE slug = 'egri-liman-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A private marina that has come into service in the old yacht harbour at Yeni Foça; it serves boats from 8-30 m. It offers 7/24 mooring assistance, electricity and water, security/CCTV, showers-WC, laundry, fuel and waste-water station, haul-out and maintenance services. It has sea border gate (Port of Entry) status. The bay is open to the west; the marina is sheltered inside the breakwater.' FROM locations WHERE slug = 'oasis-marina-yeni-foca'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto deportivo privado que ha entrado en servicio en el antiguo puerto de yates de Yeni Foça; atiende embarcaciones de 8-30 m. Dispone de servicio de amarradores 7/24, electricidad y agua, seguridad/cámaras, duchas-WC, lavandería, estación de combustible y de aguas residuales, varadero y servicios de mantenimiento. Tiene estatus de puesto fronterizo marítimo (Port of Entry). La cala está abierta al oeste; el puerto deportivo queda abrigado dentro del rompeolas.' FROM locations WHERE slug = 'oasis-marina-yeni-foca'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Частная марина, открывшаяся в старом яхтенном порту Yeni Foça; обслуживает суда длиной 8-30 м. Есть швартовная команда 7/24, электричество и вода, охрана/видеонаблюдение, душ и туалет, прачечная, топливная станция и приём сточных вод, подъём судов и сервисное обслуживание. Имеет статус морского пункта пропуска (Port of Entry). Бухта открыта к западу; марина укрыта за молом.' FROM locations WHERE slug = 'oasis-marina-yeni-foca'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchorage area off the public beach in the bay of Yeni Foça. The bottom is a mix of sand and seagrass; avoid the weed bands and anchor in the sandy patches. The town centre and the snack bars can be reached by dinghy. The bay is open to the west-southwest; in the meltemi the part close inshore is relatively calm.' FROM locations WHERE slug = 'yeni-foca-halk-plaji-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Zona de fondeo frente a la playa pública en la cala de Yeni Foça. El fondo es una mezcla de arena y praderas marinas; hay que evitar las franjas de algas y fondear en las manchas de arena. Al centro del pueblo y a los quioscos se llega con el auxiliar. La cala está abierta al oeste-sudoeste; con meltemi la zona más cercana a la costa queda relativamente tranquila.' FROM locations WHERE slug = 'yeni-foca-halk-plaji-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная стоянка перед общественным пляжем в бухте Yeni Foça. Дно — смесь песка и морской травы; полос травы следует избегать, вставая на якорь на песчаных пятнах. До центра посёлка и киосков можно добраться на тузике. Бухта открыта к западу-юго-западу; при мельтеми участок ближе к берегу относительно спокоен.' FROM locations WHERE slug = 'yeni-foca-halk-plaji-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Harbour in the İskele quarter of Urla, south of Karantina Adası and the Çiçek Adaları. It is used by fishing boats and local boat owners; it is usually full every season and finding a free berth is difficult. Beware of the shoals in the passage between the islands and the mainland. There are restaurants and cafes around it.' FROM locations WHERE slug = 'urla-iskele-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto en el barrio de İskele de Urla, al sur de Karantina Adası y de las Çiçek Adaları. Lo utilizan pesqueros y propietarios de embarcaciones locales; suele estar lleno todas las temporadas y es difícil encontrar sitio libre. Hay que prestar atención a los bajos en el paso entre las islas y tierra firme. En los alrededores hay restaurantes y cafeterías.' FROM locations WHERE slug = 'urla-iskele-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Порт в квартале İskele города Urla, к югу от Karantina Adası и островов Çiçek Adaları. Используется рыбацкими судами и местными владельцами; обычно каждый сезон заполнен, свободное место найти трудно. В проходе между островами и материком остерегайтесь отмелей. Вокруг есть рестораны и кафе.' FROM locations WHERE slug = 'urla-iskele-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchorage with a sand bottom in Dalyanköy bay, north of Çeşme; it lies near Alev Adası. The beach and snack bars can be reached by dinghy. The bay is open to the north-northwest sector; its inner part provides reasonable shelter in the meltemi. Dalyanköy''s fish restaurants are on the shore.' FROM locations WHERE slug = 'dalyankoy-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Fondeadero de fondo de arena en la cala de Dalyanköy, al norte de Çeşme; se encuentra cerca de Alev Adası. Se puede llegar a la playa y a los chiringuitos en bote auxiliar. La cala está abierta al sector norte-noroeste; su parte interior ofrece una protección razonable con el meltemi. Los restaurantes de pescado de Dalyanköy están en la orilla.' FROM locations WHERE slug = 'dalyankoy-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная стоянка с песчаным дном в бухте Dalyanköy к северу от Çeşme; расположена рядом с Alev Adası. До пляжа и закусочных можно добраться на тузике. Бухта открыта северо-северо-западному сектору; её внутренняя часть даёт умеренную защиту при мельтеми. Рыбные рестораны Dalyanköy находятся на берегу.' FROM locations WHERE slug = 'dalyankoy-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Small yacht harbour at Dalyanköy; boats moor to the quay/pier, and anchoring inside the harbour is prohibited. Water and pier services are available; there are restaurants on the shore. Entry is through the narrow fish-weir (dalyan) channel; the inner harbour is sheltered.' FROM locations WHERE slug = 'dalyankoy-yat-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Pequeño puerto deportivo en Dalyanköy; se amarra al muelle/pantalán y está prohibido fondear dentro del puerto. Hay agua y servicio de pantalán; en la orilla hay restaurantes. Se entra por el estrecho canal del dalyan (pesquera fija); el interior del puerto está abrigado.' FROM locations WHERE slug = 'dalyankoy-yat-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Небольшая яхтенная гавань в Dalyanköy; швартовка к причалу/пирсу, якорная стоянка внутри гавани запрещена. Есть вода и причальный сервис; на берегу — рестораны. Вход через узкий проход далиана (рыбной запруды); внутренняя акватория гавани хорошо укрыта.' FROM locations WHERE slug = 'dalyankoy-yat-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Mersin Körfezi, on the southern coast of the Çeşme peninsula, east of the entrance to Alaçatı bay. A natural anchorage offering good shelter from all directions; it is safe in the meltemi. There are no facilities ashore.' FROM locations WHERE slug = 'mersin-korfezi-demirleme-cesme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Mersin Körfezi, en la costa sur de la península de Çeşme, al este de la entrada de la cala de Alaçatı. Es un fondeadero natural bien protegido de todas las direcciones; es seguro con el meltemi. No hay servicios en tierra.' FROM locations WHERE slug = 'mersin-korfezi-demirleme-cesme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Mersin Körfezi на южном берегу полуострова Çeşme, к востоку от входа в бухту Alaçatı. Естественная якорная стоянка с хорошей защитой со всех направлений; безопасна при мельтеми. На берегу нет инфраструктуры.' FROM locations WHERE slug = 'mersin-korfezi-demirleme-cesme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A natural harbour of three arms (west cove, east cove and Nergis) on the Zeytineli coast of Urla. The bottom is sand with occasional weed patches; holding is good, depth about 4 m. It gives good shelter in the meltemi; in strong northerly winds an uncomfortable short chop can build up in the Nergis arm. There are no facilities ashore.' FROM locations WHERE slug = 'sarpdere-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto natural de tres brazos (cala oeste, cala este y Nergis) en la costa de Zeytineli, en Urla. El fondo es de arena con algunas manchas de algas; el agarre es bueno, con unos 4 m de profundidad. Ofrece buena protección con el meltemi; con vientos fuertes del norte puede formarse en el brazo de Nergis una ola corta e incómoda. No hay servicios en tierra.' FROM locations WHERE slug = 'sarpdere-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Естественная гавань из трёх рукавов (западная бухта, восточная бухта и Nergis) на побережье Zeytineli в Urla. Дно песчаное, местами пятна водорослей; якорь держит хорошо, глубина около 4 м. Даёт хорошую защиту при мельтеми; при сильных северных ветрах в рукаве Nergis может подниматься неприятная короткая волна. На берегу нет инфраструктуры.' FROM locations WHERE slug = 'sarpdere-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A deeply indented natural harbour on the southern coast between Çeşme and Sığacık (Zeytineli shore). Anchor in about 7 m; holding is good. It gives very good shelter from the meltemi. There are no facilities ashore.' FROM locations WHERE slug = 'kirkdilim-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto natural de entrada profunda en la costa sur entre Çeşme y Sığacık (litoral de Zeytineli). Se fondea en unos 7 m; el agarre es bueno. Ofrece muy buena protección del meltemi. No hay servicios en tierra.' FROM locations WHERE slug = 'kirkdilim-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Глубоко врезанная естественная гавань на южном берегу между Çeşme и Sığacık (побережье Zeytineli). Якорь отдают на глубине около 7 м; держит хорошо. Очень хорошая защита от мельтеми. На берегу нет инфраструктуры.' FROM locations WHERE slug = 'kirkdilim-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The natural harbour of the ancient city of Teos, south of Sığacık. It gives excellent shelter from the meltemi but is open to the south. The bottom is dense posidonia meadow; holding is good when anchored on the sand patches. The eastern part of the bay shoals. It is 1-2 miles from Teos Marina.' FROM locations WHERE slug = 'teos-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto natural de la antigua ciudad de Teos, al sur de Sığacık. Ofrece una protección excelente del meltemi, pero está abierto al sur. El fondo es una densa pradera de posidonia; el agarre es bueno si se fondea en las manchas de arena. La parte oriental de la cala pierde profundidad. Está a 1-2 millas de Teos Marina.' FROM locations WHERE slug = 'teos-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Естественная гавань античного города Teos к югу от Sığacık. Отличная защита от мельтеми, но стоянка открыта югу. Дно — густые луга посидонии; якорь держит хорошо, если встать на песчаные пятна. Восточная часть бухты мелеет. До Teos Marina 1-2 мили.' FROM locations WHERE slug = 'teos-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Ahmetbeyli bay (the shore of the ancient city of Claros), about 5 miles northwest of Kuşadası. It gives shelter from the northerly meltemi and from the westerly swell, but is open to the south. Sand bottom in about 5 m; the sand is hard, and several attempts may be needed for the anchor to bite. It is the main anchorage usable by boat along the Gümüldür-Özdere coastal strip.' FROM locations WHERE slug = 'ahmetbeyli-claros-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La cala de Ahmetbeyli (el litoral de la antigua ciudad de Claros), a unas 5 millas al noroeste de Kuşadası. Protege del meltemi del norte y de la mar de fondo del oeste, pero está abierta al sur. Fondo de arena en unos 5 m; la arena es dura y pueden hacer falta varios intentos para que el ancla agarre. Es el principal fondeadero utilizable por embarcaciones en la franja costera de Gümüldür-Özdere.' FROM locations WHERE slug = 'ahmetbeyli-claros-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта Ahmetbeyli (берег античного города Claros) примерно в 5 милях к северо-западу от Kuşadası. Защищает от северного мельтеми и от западной зыби, открыта югу. Песчаное дно на глубине около 5 м; песок плотный, и якорю может понадобиться несколько попыток, чтобы забрать. Это главная пригодная для судов якорная стоянка на прибрежной полосе Gümüldür-Özdere.' FROM locations WHERE slug = 'ahmetbeyli-claros-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A natural anchorage off the Kuşadası town waterfront, north of Güvercinada; it is recorded as a natural harbour for anchoring only, with no pier moorings. It is open to the west-southwest. The main port is for cruise ships and fishing boats and is closed to yachts; yachts use Setur Marina. When approaching from the south, beware of the reefs off Yılancı Burnu.' FROM locations WHERE slug = 'kusadasi-sahil-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Fondeadero natural frente al litoral urbano de Kuşadası, al norte de Güvercinada; figura registrado como puerto natural solo para fondear, sin amarres de pantalán. Está abierto al oeste-suroeste. El puerto principal es para cruceros y barcos de pesca y está cerrado a los yates; los yates utilizan Setur Marina. Al aproximarse desde el sur hay que prestar atención a los arrecifes frente a Yılancı Burnu.' FROM locations WHERE slug = 'kusadasi-sahil-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Естественная якорная стоянка у городской набережной Kuşadası, к северу от Güvercinada; числится как естественная гавань только для якорной стоянки, без швартовки к пирсу. Открыта западу-юго-западу. Главный порт предназначен для круизных и рыболовных судов и закрыт для яхт; яхты используют Setur Marina. При подходе с юга следует остерегаться рифов у Yılancı Burnu.' FROM locations WHERE slug = 'kusadasi-sahil-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Two historic natural anchorages on the southern shore of the western tip of the Dilek Peninsula (Samsun Dağı); of the two, Saint Nikolo gives the better shelter. The area lies within the marine zone of the Dilek Yarımadası-Büyük Menderes Deltası National Park; the anchoring/entry conditions for private boats (fees, permits, mooring-buoy arrangements) could not be verified from official sources — confirm with the National Park directorate before using them.' FROM locations WHERE slug = 'port-saint-paul-saint-nikolo'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Dos fondeaderos naturales históricos en la costa sur del extremo occidental de la península de Dilek (Samsun Dağı); de los dos, Saint Nikolo ofrece mejor protección. La zona se encuentra dentro del área marina del Parque Nacional Dilek Yarımadası-Büyük Menderes Deltası; las condiciones de fondeo/acceso para embarcaciones privadas (tarifas, permisos, sistema de boyas) no han podido verificarse en fuentes oficiales — deben confirmarse con la dirección del Parque Nacional antes de utilizarlos.' FROM locations WHERE slug = 'port-saint-paul-saint-nikolo'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Две исторические естественные якорные стоянки на южном берегу западной оконечности полуострова Dilek (Samsun Dağı); из двух лучшую защиту даёт Saint Nikolo. Район находится в морской зоне национального парка Dilek Yarımadası-Büyük Menderes Deltası; условия якорной стоянки и захода для частных судов (плата, разрешения, буйковая система) не удалось подтвердить по официальным источникам — перед использованием следует уточнить в дирекции национального парка.' FROM locations WHERE slug = 'port-saint-paul-saint-nikolo'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A small marina and mooring facility inside Akbük bay (north of the Mandalya/Güllük gulf); it offers anchor plus stern-to quay berthing, and berths can be reserved. Akbük bay is sheltered in northerly winds and open to the southern sector.' FROM locations WHERE slug = 'didim-akbuk-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Pequeño puerto deportivo e instalación de amarre dentro de la cala de Akbük (al norte del golfo de Mandalya/Güllük); ofrece amarre de popa al muelle con ancla, y se pueden reservar plazas. La cala de Akbük está abrigada con vientos del norte y abierta al sector sur.' FROM locations WHERE slug = 'didim-akbuk-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Небольшая марина и стояночный комплекс в бухте Akbük (север залива Mandalya/Güllük); швартовка кормой к причалу с отдачей якоря, места можно бронировать. Бухта Akbük укрыта при северных ветрах и открыта южному сектору.' FROM locations WHERE slug = 'didim-akbuk-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Private marina at Büyükçekmece; with a capacity of 250 wet berths and 120 dry-storage places, it accepts yachts up to 60 m.' FROM locations WHERE slug = 'guzelce-marina'
