SELECT id, 'es', NULL, 'Puerto deportivo inaugurado en 2021 en la cala de Pedi, en la isla de Symi; a 2 km de Gialos. Conexión de electricidad y agua en cada amarre, Wi-Fi gratuito, duchas/WC. Frente a la costa de Datça-Bozburun.' FROM locations WHERE slug = 'marina-symi-pedi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Марина, открытая в 2021 году в бухте Pedi на острове Symi; 2 км до Gialos. На каждом стояночном месте подключение электричества и воды, бесплатный Wi-Fi, душ/туалет. Напротив побережья Datça-Bozburun.' FROM locations WHERE slug = 'marina-symi-pedi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Town quay in Gialos, Symi''s iconic main harbour; stern-to mooring, the harbour attendant directs you to a berth. Watch out for the ferry wash. There are water/electricity points on the quay, but availability varies — confirm on arrival.' FROM locations WHERE slug = 'symi-gialos-rihtimi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Muelle del pueblo en Gialos, el icónico puerto principal de Symi; amarre de popa, el encargado del puerto indica el sitio. Atención a la marejada de los ferris. Hay puntos de agua/electricidad en el muelle, pero su disponibilidad es variable — confírmelo a la llegada.' FROM locations WHERE slug = 'symi-gialos-rihtimi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Городская набережная в Gialos, знаменитой главной гавани Symi; швартовка кормой, место указывает служащий порта. Остерегайтесь волны от паромов. На причале есть точки воды/электричества, но их доступность непостоянна — уточняйте по прибытии.' FROM locations WHERE slug = 'symi-gialos-rihtimi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'In the sheltered bay of the famous Panormitis Monastery in the south of Symi, a C-shaped pier (70 m) and a quay (120 m). Calm berthing for yachts and sailboats; depth up to 5 m at the pier head.' FROM locations WHERE slug = 'symi-panormitis-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'En la cala protegida del famoso Monasterio de Panormitis, al sur de Symi, un pantalán en forma de C (70 m) y un muelle (120 m). Atraque tranquilo para yates y veleros; profundidad de hasta 5 m en la cabecera del pantalán.' FROM locations WHERE slug = 'symi-panormitis-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'В защищённой бухте знаменитого монастыря Panormitis на юге Symi — пирс C-образной формы (70 м) и причал (120 м). Спокойная стоянка для яхт и парусников; глубина у оконечности пирса до 5 м.' FROM locations WHERE slug = 'symi-panormitis-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The historic yacht harbour of Rodos — on the site of the ancient Kolossos, with a view of three windmills. Stern-to mooring; water + 220V on the quay, fuel by tanker truck, WC/hot showers next to the office. Reserving a berth at least 48 hours in advance is recommended; there are old mooring lines on the bottom, so leave plenty of scope.' FROM locations WHERE slug = 'rodos-mandraki-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El histórico puerto de yates de Rodos — en el emplazamiento del antiguo Kolossos, con vistas a tres molinos de viento. Amarre de popa; agua + 220V en el muelle, combustible por camión cisterna, WC/duchas de agua caliente junto a la oficina. Se recomienda reservar plaza con al menos 48 horas de antelación; en el fondo hay antiguas líneas de amarre, así que deje bastante cadena.' FROM locations WHERE slug = 'rodos-mandraki-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Исторический яхтенный порт Rodos — на месте античного Kolossos, с видом на три ветряные мельницы. Швартовка кормой; на причале вода + 220V, топливо с автоцистерны, туалет/горячий душ рядом с офисом. Рекомендуется бронировать место минимум за 48 часов; на дне лежат старые муринги, поэтому потравите побольше цепи.' FROM locations WHERE slug = 'rodos-mandraki-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The colourful town quay of Meis island, 2 nautical miles across from Kaş; 82 m pier, -6,3 m depth. It is a PORT OF ENTRY into Greece (customs/passport formalities are handled) — the first stop for boats crossing over from Turkey. Electricity, water, Wi-Fi, showers/WC on the quay.' FROM locations WHERE slug = 'kastellorizo-meis-rihtimi'
