INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El colorido muelle del pueblo de la isla de Meis, a 2 millas náuticas frente a Kaş; pantalán de 82 m, profundidad de -6,3 m. Es PUERTO DE ENTRADA a Grecia (se realizan trámites de aduana/pasaporte) — primera escala para las embarcaciones que cruzan desde Turquía. Electricidad, agua, Wi-Fi, duchas/WC en el muelle.' FROM locations WHERE slug = 'kastellorizo-meis-rihtimi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Колоритная городская набережная острова Meis в 2 морских милях напротив Kaş; пирс 82 м, глубина -6,3 м. Это ПОРТ ВХОДА в Грецию (оформляются таможенные/паспортные формальности) — первая остановка для судов, идущих из Турции. На причале электричество, вода, Wi-Fi, душ/туалет.' FROM locations WHERE slug = 'kastellorizo-meis-rihtimi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
