SELECT id, 'es', NULL, 'Muelle municipal en Livadia, el puerto principal de la isla de Tilos; sitio para hasta 35 embarcaciones, agua dulce y conexión eléctrica. El brazo sur del pantalán mide ~50 m, con una profundidad utilizable de -8 m. Bien protegido dentro del muro del puerto; el espacio para atracar de costado es limitado.' FROM locations WHERE slug = 'tilos-livadia-rihtimi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Муниципальный причал в Livadia, главной гавани острова Tilos; места до 35 судов, пресная вода и подключение электричества. Южное плечо пирса ~50 м, рабочая глубина -8 м. Внутри портовой стены хорошая защита; мест для швартовки лагом мало.' FROM locations WHERE slug = 'tilos-livadia-rihtimi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
