ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The bay of ancient Myndos, at the western tip of the Bodrum peninsula. 15-16 m in the middle, 5-10 m towards the shore and the head of the bay; holding is good once you get through the layer of weed. Sheltered from the west and north-west; a strong northerly wind sends in swell. It is an archaeological site — building on the shore is strictly controlled. You can walk to Tavşan Adası along the ancient causeway.' FROM locations WHERE slug = 'gumusluk-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La cala de la antigua Myndos, en el extremo occidental de la península de Bodrum. Hay 15-16 m en el centro y 5-10 m hacia la orilla y el fondo de la cala; el agarre es bueno una vez atravesada la capa de algas. Está abrigada del oeste y del noroeste; el viento fuerte del norte mete marejada. Es zona arqueológica — la construcción en la costa está estrictamente controlada. Se puede caminar hasta Tavşan Adası por la antigua calzada.' FROM locations WHERE slug = 'gumusluk-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта античного Myndos на западной оконечности полуострова Bodrum. В середине 15-16 м, к берегу и к вершине бухты 5-10 м; якорь держит хорошо, если пробить слой водорослей. Защищена с запада и северо-запада; сильный северный ветер заводит зыбь. Археологическая зона — застройка берега строго контролируется. До Tavşan Adası можно дойти пешком по античной дороге.' FROM locations WHERE slug = 'gumusluk-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Wooden jetties on the eastern shore of the bay; berthing is stern-to or bows-to. They take about 8 boats; water and electricity connections are available. The source notes that the overnight mooring fee is kept high. Fish restaurants line the shore.' FROM locations WHERE slug = 'gumusluk-iskeleleri'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Pantalanes de madera en la orilla oriental de la cala; se atraca de popa o de proa. Admiten unos 8 barcos; hay conexión de agua y electricidad. La fuente señala que la tarifa de amarre por noche es elevada. Los restaurantes de pescado se alinean en la orilla.' FROM locations WHERE slug = 'gumusluk-iskeleleri'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Деревянные пирсы на восточном берегу бухты; швартовка кормой или носом. Принимают около 8 судов; есть подключение воды и электричества. Источник отмечает, что плата за ночную стоянку держится высокой. Вдоль берега — рыбные рестораны.' FROM locations WHERE slug = 'gumusluk-iskeleleri'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The fishing cooperative harbour next to Yalıkavak Marina; capacity 65 boats. Water, electricity and bilge-water pump-out are available; there are a Coast Guard station and customs. The harbour entrance faces west; the strong meltemi coming down off the mountains can raise a short, confused chop. Caution: the Karataş rocks lie ~650 m off the shore; the bottom is weedy — check carefully that your anchor has set.' FROM locations WHERE slug = 'yalikavak-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto de la cooperativa de pescadores junto a Yalıkavak Marina; capacidad para 65 barcos. Hay agua, electricidad y servicio de achique de sentinas; cuenta con puesto de la Guardia Costera y aduana. La bocana mira al oeste; el fuerte meltemi que baja de las montañas puede levantar una ola corta y confusa. Atención: las rocas de Karataş están a ~650 m de la costa; el fondo tiene algas — compruebe bien que el ancla haya agarrado.' FROM locations WHERE slug = 'yalikavak-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Кооперативный рыбацкий порт рядом с Yalıkavak Marina; вместимость 65 судов. Есть вода, электричество и приём трюмных вод; имеются пост береговой охраны и таможня. Вход в порт обращён на запад; сильный мельтеми, скатывающийся с гор, может разводить короткую беспорядочную волну. Внимание: скалы Karataş лежат в ~650 м от берега; дно заросло водорослями — тщательно проверяйте, забрал ли якорь.' FROM locations WHERE slug = 'yalikavak-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The cooperative harbour right next to D-Marin Turgutreis; 85 boats. The depth alongside the quay is about 3 m. Water and electricity can be connected; bilge-water pump-out, ice and bottled gas are available; there is a Coast Guard station. The northern shores are shallow and windy; the approach is easier from the south.' FROM locations WHERE slug = 'turgutreis-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto de la cooperativa justo al lado de D-Marin Turgutreis; 85 barcos. La profundidad junto al muelle es de unos 3 m. Se conectan agua y electricidad; hay achique de sentinas y venta de hielo y gas en bombona; cuenta con puesto de la Guardia Costera. Las costas del norte son someras y ventosas; la aproximación es más cómoda por el sur.' FROM locations WHERE slug = 'turgutreis-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Кооперативный порт вплотную к D-Marin Turgutreis; 85 судов. Глубина у причала около 3 м. Подключаются вода и электричество; есть приём трюмных вод, продажа льда и баллонного газа; имеется пост береговой охраны. Северные берега мелководны и открыты ветру; подходить удобнее с юга.' FROM locations WHERE slug = 'turgutreis-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A bay near Akyarlar with castle ruins on the hilltop. Anchor in 7 m; holding is reasonable. It is closed to north-westerly winds. There are restaurants ashore; fresh water can be obtained. Crowding (per the source): during the day many day-trip boats come over from Bodrum and leave in the evening hours — nights are quieter; in the evenings music may be heard from the shore establishments.' FROM locations WHERE slug = 'aspat-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala cerca de Akyarlar con ruinas de un castillo en lo alto. Se fondea en 7 m; el agarre es aceptable. Está cerrada a los vientos del noroeste. Hay restaurantes en la orilla; se puede conseguir agua dulce. Afluencia (según la fuente): de día llegan numerosas embarcaciones de excursión desde Bodrum y se marchan al atardecer — la noche es más tranquila; por las tardes puede oírse música de los locales de la costa.' FROM locations WHERE slug = 'aspat-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта близ Akyarlar с руинами крепости на вершине холма. Якорь отдают на 7 м; держит приемлемо. Закрыта от северо-западных ветров. На берегу рестораны; можно пополнить запас пресной воды. Загруженность (по источнику): днём из Bodrum приходит много прогулочных судов, к вечеру они уходят — ночью спокойнее; по вечерам с береговых заведений бывает слышна музыка.' FROM locations WHERE slug = 'aspat-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'An anchorage off the beach 4 km north of Turgutreis, between it and Gümüşlük. There are wooden jetties and fish restaurants ashore; the remains of a Hellenistic castle and a Byzantine church are the landmark of the bay. The morning hours are calm; in the afternoon the west-north-westerly wind increases noticeably.' FROM locations WHERE slug = 'kadikalesi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Fondeadero frente a la playa 4 km al norte de Turgutreis, entre esta y Gümüşlük. En la orilla hay pantalanes de madera y restaurantes de pescado; los restos de un castillo helenístico y de una iglesia bizantina son el emblema de la cala. Las mañanas son tranquilas; por la tarde el viento del oeste-noroeste arrecia notablemente.' FROM locations WHERE slug = 'kadikalesi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная стоянка у пляжа в 4 км к северу от Turgutreis, между ним и Gümüşlük. На берегу деревянные пирсы и рыбные рестораны; руины эллинистической крепости и византийской церкви — символ бухты. Утренние часы спокойны; после полудня западо-северо-западный ветер заметно усиливается.' FROM locations WHERE slug = 'kadikalesi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A lighthouse island lying ~1,5 miles off Turgutreis. Anchor in 4-6 m on a sand-and-weed bottom on the beach side between the hills; the southern side is more sheltered. In a strong meltemi, swell works into the beach side; the current in the area is noticeable. CAUTION: there are unmarked rocks and shoals on the northern side, and reefs around the nearby islets (Çobanada, Tüllüceada, Sarıot) — night passage is not recommended.' FROM locations WHERE slug = 'catal-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Isla con faro situada a ~1,5 millas de Turgutreis. Se fondea en 4-6 m sobre fondo de arena y algas por el lado de la playa situada entre las colinas; el lado sur es el más abrigado. Con meltemi fuerte entra marejada por el lado de la playa; la corriente en la zona es apreciable. ATENCIÓN: en el lado norte hay rocas y bajos sin balizar, y arrecifes en los islotes cercanos (Çobanada, Tüllüceada, Sarıot) — no se recomienda navegar de noche.' FROM locations WHERE slug = 'catal-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Остров с маяком в ~1,5 милях от Turgutreis. Якорь отдают на 4-6 м на песчано-водорослевом дне со стороны пляжа между холмами; южная сторона более защищена. При сильном мельтеми к пляжу заходит зыбь; течение в районе заметное. ВНИМАНИЕ: с северной стороны — необозначенные скалы и отмели, у соседних островков (Çobanada, Tüllüceada, Sarıot) — рифы; ночной переход не рекомендуется.' FROM locations WHERE slug = 'catal-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The cooperative fishing shelter of Türkbükü bay; 55 boats, 143 m main breakwater. Depths of 3-4 m on the breakwater side; the shore side is shallow. Water, electricity and fuel supply BY TANKER TRUCK are available; there is a hauling-out yard. In calm weather you can anchor in 6-10 m in the east of the bay; 12-18 m in the middle with a weedy bottom. The surrounding hills and islands protect against the afternoon meltemi and the north-easterly wind. CAUTION: there are buoyed fish farms between the islands and the mainland.' FROM locations WHERE slug = 'golturkbuku-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio pesquero de la cooperativa de la cala de Türkbükü; 55 barcos, rompeolas principal de 143 m. Del lado del rompeolas hay 3-4 m de sonda; el lado de tierra es somero. Hay agua, electricidad y suministro de combustible POR CAMIÓN CISTERNA; dispone de varadero. Con tiempo en calma se fondea en 6-10 m en el este de la cala; en el centro hay 12-18 m y fondo de algas. Las colinas e islas circundantes protegen del meltemi de la tarde y del viento del noreste. ATENCIÓN: entre las islas y tierra firme hay piscifactorías balizadas con boyas.' FROM locations WHERE slug = 'golturkbuku-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Кооперативная рыбацкая гавань бухты Türkbükü; 55 судов, главный мол 143 м. Со стороны мола глубины 3-4 м; прибрежная сторона мелководна. Есть вода, электричество и заправка топливом С АВТОЦИСТЕРНЫ; имеется место для подъёма судов на берег. В тихую погоду в восточной части бухты встают на якорь на 6-10 м; в середине 12-18 м и заросшее водорослями дно. Окрестные холмы и острова прикрывают от послеполуденного мельтеми и северо-восточного ветра. ВНИМАНИЕ: между островами и материком — обозначенные буями рыбные фермы.' FROM locations WHERE slug = 'golturkbuku-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A cooperative fishing shelter in a sheltered bay 5 km north-east of Bodrum centre; 85 boats. Berth stern-to on the outer breakwater in 6-10 m; in the bay, anchor in 5-10 m on a sandy bottom. Water, electricity, bilge-water pump-out and fuel by tanker truck are available. The meltemi coming down off the hills can set up an uncomfortable swell in the bay.' FROM locations WHERE slug = 'torba-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio pesquero de cooperativa en una cala abrigada 5 km al noreste del centro de Bodrum; 85 barcos. Se atraca de popa al rompeolas exterior en 6-10 m; en la cala se fondea en 5-10 m sobre fondo de arena. Hay agua, electricidad, achique de sentinas y combustible por camión cisterna. El meltemi que baja de las colinas puede provocar una marejada incómoda en la cala.' FROM locations WHERE slug = 'torba-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Кооперативная рыбацкая гавань в защищённой бухте в 5 км к северо-востоку от центра Bodrum; 85 судов. К внешнему молу швартуются кормой на 6-10 м; в бухте встают на якорь на 5-10 м на песчаном дне. Есть вода, электричество, приём трюмных вод и заправка топливом с автоцистерны. Мельтеми, скатывающийся с холмов, может разводить в бухте неприятную зыбь.' FROM locations WHERE slug = 'torba-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A large island north of Bodrum, covered in pine and olive. There is more than one anchoring option; shelter is good. According to the source, the best spot for visiting boats is the cove with the ''white house'' in the south-east — it is also good for swimming. There are summer houses in the southern inlet.' FROM locations WHERE slug = 'salih-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Gran isla al norte de Bodrum, cubierta de pinos y olivos. Ofrece varias posibilidades de fondeo; el abrigo es bueno. Según la fuente, el mejor punto para las embarcaciones visitantes es la cala de la ''casa blanca'' del sureste — también es apta para el baño. En la ensenada sur hay casas de veraneo.' FROM locations WHERE slug = 'salih-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Большой остров к северу от Bodrum, покрытый соснами и оливами. Есть несколько мест для якорной стоянки; укрытие хорошее. По данным источника, лучшая точка для гостевых яхт — юго-восточная бухта с ''белым домом''; она подходит и для купания. В южной заводи стоят летние дома.' FROM locations WHERE slug = 'salih-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A municipal/cooperative harbour on the eastern side of the Güllük gulf; 8 km from Milas-Bodrum Airport. Call ''Güllük Marina'' on VHF 16. 7-8 m in the turning area, good holding on a sand-and-mud bottom; the anchoring area is ~20 m. Water, electricity, bilge-water pump-out and fuel by tanker truck are available. According to the source (2016) it is a customs port of entry and exit.' FROM locations WHERE slug = 'gulluk-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto municipal/de cooperativa en la orilla oriental del golfo de Güllük; a 8 km del aeropuerto de Milas-Bodrum. Se llama a ''Güllük Marina'' por VHF 16. En la zona de reviro hay 7-8 m, con buen agarre en fondo de arena y fango; la zona de fondeo tiene ~20 m. Hay agua, electricidad, achique de sentinas y combustible por camión cisterna. Según la fuente (2016), es puerto de entrada y salida con aduana.' FROM locations WHERE slug = 'gulluk-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Муниципальный/кооперативный порт на восточном берегу залива Güllük; 8 км до аэропорта Milas-Bodrum. Вызов ''Güllük Marina'' по VHF 16. В зоне разворота 7-8 м, хорошая держащая способность на песчано-илистом дне; на якорном месте ~20 м. Есть вода, электричество, приём трюмных вод и топливо с автоцистерны. По данным источника (2016), это порт с таможенным оформлением входа и выхода.' FROM locations WHERE slug = 'gulluk-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The bay of the village of Mesudiye, on the southern face of the Datça peninsula; 5 km from Palamutbükü. Anchor in 4-5 m on the western side of the bay. Fish restaurants, a bakery and guesthouses ashore; the village has a PTT post office, a health clinic and a laundry. A small, sheltered bay ringed by green slopes.' FROM locations WHERE slug = 'ovabuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La cala de la aldea de Mesudiye, en la cara sur de la península de Datça; a 5 km de Palamutbükü. Se fondea en 4-5 m en el lado oeste de la cala. En la orilla hay restaurantes de pescado, panadería y pensiones; en el pueblo hay oficina de correos PTT, consultorio médico y lavandería. Es una cala pequeña y abrigada, rodeada de laderas verdes.' FROM locations WHERE slug = 'ovabuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта деревни Mesudiye на южной стороне полуострова Datça; 5 км до Palamutbükü. Якорь отдают на 4-5 м у западного берега бухты. На берегу рыбные рестораны, пекарня и пансионы; в деревне есть почта PTT, медпункт и прачечная. Маленькая, защищённая бухта в окружении зелёных склонов.' FROM locations WHERE slug = 'ovabuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A T-shaped pier in the middle of a round bay ~800 m across, in the south-east corner of Gökova. Berth stern-to, or anchor and take lines ashore; the depth increases quickly towards the middle of the bay. Water, electricity, showers/WC, a laundry, a grocery and a restaurant are available. Shelter is good; short gusts come down from time to time. According to the source, since a small-marina setup has been established, it is also used for wintering.' FROM locations WHERE slug = 'karacasogut-halk-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Pantalán en T en el centro de una cala redonda de ~800 m de diámetro, en el rincón sureste de Gökova. Se atraca de popa, o se fondea pasando amarras a tierra; la profundidad aumenta rápidamente hacia el centro de la cala. Hay agua, electricidad, duchas/WC, lavandería, tienda de comestibles y restaurante. El abrigo es bueno; de vez en cuando bajan rachas breves (gust). Según la fuente, como se ha montado la estructura de un pequeño puerto deportivo, también se usa para la invernada.' FROM locations WHERE slug = 'karacasogut-halk-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Т-образный пирс посреди круглой бухты диаметром ~800 м в юго-восточном углу Gökova. Швартуются кормой либо встают на якорь с заводкой концов на берег; к середине бухты глубина быстро растёт. Есть вода, электричество, душ/WC, прачечная, магазин и ресторан. Укрытие хорошее; временами с гор скатываются короткие шквалистые порывы. По данным источника, здесь налажен порядок небольшой марины, поэтому место используется и для зимовки.' FROM locations WHERE slug = 'karacasogut-halk-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The cooperative fishing shelter of Akyaka, at the innermost end of the Gökova gulf; capacity 170 boats. Right beside it the Azmak stream meets the sea — boats can go some way up the deep watercourse; restaurants line the stream. A stop famous for its geranium-coloured Ula houses and its fine-sand public beach.' FROM locations WHERE slug = 'akyaka-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio pesquero de la cooperativa de Akyaka, en el fondo del golfo de Gökova; capacidad para 170 barcos. Justo al lado, el arroyo Azmak desemboca en el mar — las embarcaciones pueden remontar un trecho su cauce profundo; los restaurantes se alinean a lo largo del arroyo. Es una escala famosa por sus casas de Ula color geranio y su playa pública de arena fina.' FROM locations WHERE slug = 'akyaka-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Кооперативная рыбацкая гавань Akyaka в самой вершине залива Gökova; вместимость 170 судов. Рядом впадает в море речка Azmak — по её глубокому руслу суда могут пройти немного вверх; вдоль речки тянутся рестораны. Стоянка знаменита домами Ula цвета герани и общественным пляжем с мелким песком.' FROM locations WHERE slug = 'akyaka-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A quiet bay on the southern shore of Gökova, surrounded by dense pine forest; a small stream empties into it. 27 km to Marmaris, 55 km to Datça. The nearby Ada beach has showers, WC and changing cabins; there are walking trails through the forest.' FROM locations WHERE slug = 'bordubet-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala tranquila en la costa sur de Gökova, rodeada de un denso pinar; en ella desemboca un pequeño arroyo. A 27 km de Marmaris y a 55 km de Datça. En la cercana playa de Ada hay duchas, WC y casetas; en el bosque hay senderos para caminar.' FROM locations WHERE slug = 'bordubet-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Тихая бухта на южном берегу Gökova в окружении густого соснового леса; в неё впадает небольшой ручей. До Marmaris 27 км, до Datça 55 км. На соседнем пляже Ada есть душ, WC и кабинки для переодевания; в лесу проложены пешеходные тропы.' FROM locations WHERE slug = 'bordubet-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'On the western side of the gulf of Fethiye, east of the Kapıdağı peninsula, ~1 mile north of İnce Burun. Anchor in 8-12 m in the main part (10-15 m in the northern arm); holding is good on a sand-and-weed bottom — take lines ashore. Well sheltered from the prevailing winds; open to the south-east and east. Crowding (per the source): a frequent gulet stop, crowded in season. The ancient city of Lydae is a ~30 min walk away.' FROM locations WHERE slug = 'kizilkuyruk-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'En la orilla occidental del golfo de Fethiye, al este de la península de Kapıdağı, ~1 milla al norte de İnce Burun. Se fondea en 8-12 m en la parte principal (10-15 m en el brazo norte); el agarre es bueno en fondo de arena y algas — pase amarras a tierra. Muy abrigada de los vientos dominantes; queda abierta al sureste y al este. Afluencia (según la fuente): escala habitual de goletas, concurrida en temporada. La ciudad antigua de Lydae queda a ~30 min a pie.' FROM locations WHERE slug = 'kizilkuyruk-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'На западной стороне залива Fethiye, к востоку от полуострова Kapıdağı, в ~1 миле к северу от İnce Burun. В основной части якорь отдают на 8-12 м (в северном рукаве 10-15 м); на песчано-водорослевом дне держит хорошо — заводите концы на берег. Хорошо укрыта от господствующих ветров; открыта с юго-востока и востока. Загруженность (по источнику): частая стоянка гулет, в сезон многолюдно. До античного города Lydae ~30 мин пешком.' FROM locations WHERE slug = 'kizilkuyruk-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'An island 3 miles west of Ölüdeniz, covered in Byzantine ruins. In the crescent-shaped cove on the northern side, anchor in 15-20 m and take lines ashore; the bottom is a mix of weed, sand and rock — a buoyed trip line is recommended so the anchor can be recovered easily. In settled weather it is a lovely stop. CAUTION: ancient remains extend underwater up to 15-20 m off the shore.' FROM locations WHERE slug = 'gemiler-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Isla 3 millas al oeste de Ölüdeniz, cubierta de ruinas bizantinas. En la cala en forma de media luna del lado norte se fondea en 15-20 m pasando amarras a tierra; el fondo es una mezcla de algas, arena y roca — se recomienda un orinque con boya (trip line) para poder levar el ancla con facilidad. Con tiempo asentado es una escala preciosa. ATENCIÓN: los restos antiguos se extienden bajo el agua hasta 15-20 m de la orilla.' FROM locations WHERE slug = 'gemiler-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Остров в 3 милях к западу от Ölüdeniz, покрытый византийскими руинами. В серповидной бухте на северной стороне встают на якорь на 15-20 м с заводкой концов на берег; дно — смесь водорослей, песка и камня; чтобы легко выбрать якорь, рекомендуется буйреп с томбуем (trip line). В устойчивую погоду — прекрасная стоянка. ВНИМАНИЕ: под водой на расстоянии до 15-20 м от берега тянутся античные руины.' FROM locations WHERE slug = 'gemiler-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A deserted, wide bay in the Hisarönü gulf, south of Koca Ada. The indentation between the two headlands gives relative protection from westerly winds. Anchor in 7-12 m and take lines ashore. The village of Germe is 1 mile to the south-east; there is a 2,5 km road link to Bozburun.' FROM locations WHERE slug = 'kuzbuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala amplia y solitaria en el golfo de Hisarönü, al sur de Koca Ada. La entrante entre las dos puntas ofrece protección relativa frente a los vientos del oeste. Se fondea en 7-12 m pasando amarras a tierra. El pueblo de Germe queda 1 milla al sureste; hay una carretera de 2,5 km hasta Bozburun.' FROM locations WHERE slug = 'kuzbuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Безлюдная просторная бухта в заливе Hisarönü к югу от Koca Ada. Углубление между двумя мысами даёт относительную защиту от западных ветров. Якорь отдают на 7-12 м с заводкой концов на берег. Деревня Germe в 1 миле к юго-востоку; до Bozburun ведёт дорога длиной 2,5 км.' FROM locations WHERE slug = 'kuzbuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A deserted, south-west-facing cove in Hisarönü, south of Kargı Adası. In calm weather, anchor close inshore off the flat valley. WARNING (per the source): because of motor-yacht traffic and swell, OVERNIGHT ANCHORING IS NOT RECOMMENDED — it is suitable for a daytime stop.' FROM locations WHERE slug = 'girneyit-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala solitaria orientada al suroeste en Hisarönü, al sur de Kargı Adası. Con tiempo en calma se fondea cerca de la orilla, frente al valle llano. AVISO (según la fuente): por el tráfico de yates a motor y la marejada, NO SE RECOMIENDA FONDEAR DE NOCHE — es adecuada para una parada diurna.' FROM locations WHERE slug = 'girneyit-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Безлюдная бухта в Hisarönü, к югу от Kargı Adası, открытая на юго-запад. В тихую погоду встают на якорь близко к берегу перед ровной долиной. ПРЕДУПРЕЖДЕНИЕ (по источнику): из-за трафика моторных яхт и зыби НОЧНАЯ ЯКОРНАЯ СТОЯНКА НЕ РЕКОМЕНДУЕТСЯ — подходит для дневной остановки.' FROM locations WHERE slug = 'girneyit-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
-- --- i18n_tur4.json (i18n-tur4) ---
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A narrow bay in the north of the Gulf of Sığacık, indenting northwards and ending in a sandy beach. Anchor in 4-5 m; as the inlet is narrow, a line can be taken to the rocks; there is room for only a few boats on the eastern side. Strong winds can sweep down from the mountains to the sea.' FROM locations WHERE slug = 'ilica-koyu-sigacik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala estrecha al norte del golfo de Sığacık, que se adentra hacia el norte y termina en una playa de arena. Se fondea en 4-5 m; al ser estrecha la ensenada, puede darse un cabo a las rocas; en el lado este hay sitio solo para unas pocas embarcaciones. Desde las montañas puede bajar viento fuerte hacia el mar.' FROM locations WHERE slug = 'ilica-koyu-sigacik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Узкая бухта в северной части залива Sığacık, вдающаяся к северу и заканчивающаяся песчаным пляжем. Якорь отдают на глубине 4-5 м; так как заводь узкая, можно завести конец на скалы; на восточной стороне есть место лишь для нескольких яхт. С гор к морю может срываться сильный ветер.' FROM locations WHERE slug = 'ilica-koyu-sigacik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A beautiful bay in the northwest of the Gulf of Sığacık; a safe shelter except in southerly winds. Depths of 8-10 m; the inlet at the eastern end has room for only 2-3 boats. Known for the mineral water spring and mud just off the shore.' FROM locations WHERE slug = 'papaz-bogazi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Hermosa cala al noroeste del golfo de Sığacık; refugio seguro salvo con vientos del sur. Profundidades de 8-10 m; en la ensenada del extremo este solo hay sitio para 2-3 embarcaciones. Conocida por el manantial de agua mineral y el barro frente a la costa.' FROM locations WHERE slug = 'papaz-bogazi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Красивая бухта на северо-западе залива Sığacık; надёжное укрытие, кроме южных ветров. Глубины 8-10 м; в заводи у восточной оконечности есть место лишь для 2-3 яхт. Известна источником минеральной воды и грязями недалеко от берега.' FROM locations WHERE slug = 'papaz-bogazi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'In the north of the Gulf of Sığacık; it takes its name from the rock in the middle of the entrance. Enter the bay to the WEST of this rock — reefs extend from the east of the rock. In the bay, which ends in a sandy beach, anchor in 4-5 m; it gives adequate shelter from northerly winds and is open to the south.' FROM locations WHERE slug = 'tas-ada-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Al norte del golfo de Sığacık; toma su nombre de la roca situada en medio de la entrada. Se entra en la cala por el OESTE de esta roca — al este de la roca se extienden arrecifes. En la cala, que termina en una playa de arena, se fondea en 4-5 m; ofrece abrigo suficiente frente a los vientos del norte y está abierta al sur.' FROM locations WHERE slug = 'tas-ada-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'В северной части залива Sığacık; название получила от скалы посреди входа. В бухту входят к ЗАПАДУ от этой скалы — к востоку от скалы тянутся рифы. В бухте, заканчивающейся песчаным пляжем, якорь отдают на 4-5 м; она даёт достаточное укрытие от северных ветров и открыта к югу.' FROM locations WHERE slug = 'tas-ada-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A small cove on the Demircili (Urla) coast. Anchor off the beach in 3-5 m on a bottom of weed and sand; the inner basin is 2-3 m. Strong northerly winds send in a swell.' FROM locations WHERE slug = 'kapikaya-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Pequeña cala en la costa de Demircili (Urla). Se fondea frente a la playa en 3-5 m sobre fondo de algas y arena; la dársena interior tiene 2-3 m. Los vientos fuertes del norte meten mar de fondo.' FROM locations WHERE slug = 'kapikaya-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Небольшая бухта на побережье Demircili (Urla). Якорь отдают перед пляжем на 3-5 м, грунт — песок с водорослями; во внутренней акватории 2-3 м. Сильные северные ветры нагоняют зыбь.' FROM locations WHERE slug = 'kapikaya-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A bay in the north of the Gulf of Sığacık, ending in an oval sandy beach. Enter the bay to the EAST of the easily identified rocks at water level. Anchor in 3-4 m; it gives shelter from every direction except the south. There is a cafe on the hill to the north; a walking path leads to Demirci Limanı.' FROM locations WHERE slug = 'yarimada-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala al norte del golfo de Sığacık que termina en una playa de arena ovalada. Se entra en la cala por el ESTE de las rocas a flor de agua, fáciles de distinguir. Se fondea en 3-4 m; ofrece abrigo de todas las direcciones salvo del sur. En la colina norte hay una cafetería; un sendero a pie conduce a Demirci Limanı.' FROM locations WHERE slug = 'yarimada-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта в северной части залива Sığacık, заканчивающаяся овальным песчаным пляжем. В бухту входят к ВОСТОКУ от хорошо заметных скал у поверхности воды. Якорь отдают на 3-4 м; укрытие от всех направлений, кроме южного. На северном холме есть кафе; к Demirci Limanı ведёт пешеходная тропа.' FROM locations WHERE slug = 'yarimada-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A bay in the northwest of the Gulf of Sığacık, ending in a sandy beach. Anchor in 4-6 m on a bottom of sand and weed; lines can be taken ashore. Good shelter from northerly winds, open to the south. Famous for its ancient steps carved into the rocks, leading down to the sea.' FROM locations WHERE slug = 'duverlik-merdivenli-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala al noroeste del golfo de Sığacık que termina en una playa de arena. Se fondea en 4-6 m sobre fondo de arena y algas; pueden darse cabos a tierra. Buen abrigo frente a los vientos del norte, abierta al sur. Es famosa por sus antiguas escaleras talladas en las rocas que bajan al mar.' FROM locations WHERE slug = 'duverlik-merdivenli-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта на северо-западе залива Sığacık, заканчивающаяся песчаным пляжем. Якорь отдают на 4-6 м, грунт — песок с водорослями; можно завести концы на берег. Хорошее укрытие от северных ветров, открыта к югу. Знаменита древними лестницами, высеченными в скалах и спускающимися к морю.' FROM locations WHERE slug = 'duverlik-merdivenli-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A deep, fjord-like bay about 2 miles northeast of Teke Burnu; it gives shelter from ALL directions. North creek: 9-11 m in the middle, shoaling towards the shore — anchor in 4-6 m on a sand bottom and take a bow line to the eastern shore; the holding is good (fish farms spoil the view). East creek: ~10 m, 1-2 boats; the holding is weaker than in the north creek. CAUTION: there is a ship''s mooring buoy at the entrance — take care at night.' FROM locations WHERE slug = 'gok-liman-kokar-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala profunda, semejante a un fiordo, a unas 2 millas al noreste de Teke Burnu; ofrece abrigo en TODAS las direcciones. Brazo norte: 9-11 m en el centro, perdiendo fondo hacia la costa — fondee en 4-6 m sobre fondo de arena y dé un cabo de proa a la orilla este; el agarre es bueno (las piscifactorías estropean la vista). Brazo este: ~10 m, 1-2 embarcaciones; el agarre es más débil que en el brazo norte. ATENCIÓN: hay una boya de amarre de buques en la entrada — precaución de noche.' FROM locations WHERE slug = 'gok-liman-kokar-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Глубокая, похожая на фьорд бухта примерно в 2 милях к северо-востоку от Teke Burnu; даёт укрытие от ВСЕХ направлений. Северный рукав: в середине 9-11 м, к берегу мелеет — встаньте на якорь на 4-6 м на песчаном грунте и заведите носовой конец на восточный берег; грунт держит хорошо (рыбные фермы портят вид). Восточный рукав: ~10 м, 1-2 яхты; держащая способность слабее, чем в северном рукаве. ВНИМАНИЕ: у входа стоит судовой швартовный буй — будьте осторожны ночью.' FROM locations WHERE slug = 'gok-liman-kokar-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A bay near Sarpdere, indenting to the north. Anchor in 4 m on a sand bottom with patches of weed; the holding is good, but the sand is hard in places — set the anchor with engine power. It gives shelter from all directions; in a strong northerly an uncomfortable chop develops because of the ~1 mile fetch. The bottom is so clear that you can count the shades of blue; there is a lovely beach inside.' FROM locations WHERE slug = 'nergis-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala cerca de Sarpdere, que se adentra hacia el norte. Se fondea en 4 m sobre fondo de arena con manchas de algas; el agarre es bueno, pero la arena es dura en algunos puntos — asiente el ancla con la fuerza del motor. Ofrece abrigo de todas las direcciones; con norte fuerte se forma un oleaje molesto debido al alcance de ~1 milla. El fondo es tan nítido que se pueden contar los tonos de azul; en el interior hay una bonita playa.' FROM locations WHERE slug = 'nergis-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта возле Sarpdere, вдающаяся к северу. Якорь отдают на 4 м на песчаном грунте с пятнами водорослей; держит хорошо, но местами песок плотный — усаживайте якорь на моторе. Укрытие от всех направлений; при сильном северном ветре из-за разгона волны около 1 мили возникает неприятная толчея. Дно настолько прозрачно просматривается, что можно считать оттенки синего; в глубине бухты есть красивый пляж.' FROM locations WHERE slug = 'nergis-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The gulf between İnmece Burnu and Böğürtlen Burnu; near Böğürtlen Adası and the Dümbelek Adaları. The area is known for its crystal-clear waters and its succession of coves.' FROM locations WHERE slug = 'zeytineli-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Golfo entre İnmece Burnu y Böğürtlen Burnu; cerca de Böğürtlen Adası y de las Dümbelek Adaları. La zona es conocida por sus aguas cristalinas y sus calas sucesivas.' FROM locations WHERE slug = 'zeytineli-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Залив между мысами İnmece Burnu и Böğürtlen Burnu; рядом с островом Böğürtlen Adası и островами Dümbelek Adaları. Район известен кристально чистой водой и чередой бухт.' FROM locations WHERE slug = 'zeytineli-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The bay between the Dümbelek Adaları and Dümbelek Dağı; it lies near Böğürtlen Adası. Together with Zeytineli, it is on the line of Urla''s open-sea coves.' FROM locations WHERE slug = 'bogurtlen-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala situada entre las Dümbelek Adaları y el Dümbelek Dağı; se encuentra cerca de Böğürtlen Adası. Junto con Zeytineli, forma parte de la línea de calas de mar abierto de Urla.' FROM locations WHERE slug = 'bogurtlen-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта между островами Dümbelek Adaları и горой Dümbelek Dağı; расположена рядом с островом Böğürtlen Adası. Вместе с Zeytineli входит в цепочку открытых морских бухт района Urla.' FROM locations WHERE slug = 'bogurtlen-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Twin coves, north and south, off Urla. They lie on the secluded anchoring stretch between Sarpdere and Teke Burnu.' FROM locations WHERE slug = 'lakoz-koylari-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Calas gemelas, una norte y otra sur, frente a Urla. Se encuentran en el tramo de fondeo solitario entre Sarpdere y Teke Burnu.' FROM locations WHERE slug = 'lakoz-koylari-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Парные бухты — северная и южная — у побережья Urla. Расположены на уединённом участке якорных стоянок между Sarpdere и Teke Burnu.' FROM locations WHERE slug = 'lakoz-koylari-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'An island at the entrance to the Ayvalık channel, west of the Sarımsaklı peninsula. In the southern cove, anchor in 2-5 m on a sand bottom; it gives shelter from northerly winds — calm at night; it is mostly a lunch stop. Characteristics of the island''s lighthouse: 18 m focal plane, a red flash every 3 s, visibility 8 miles.' FROM locations WHERE slug = 'ciplak-ada-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Isla en la entrada del canal de Ayvalık, al oeste de la península de Sarımsaklı. En la cala sur se fondea en 2-5 m sobre fondo de arena; ofrece abrigo frente a los vientos del norte — tranquila de noche; suele ser una parada para el almuerzo. Características del faro de la isla: plano focal de 18 m, un destello rojo cada 3 s, visibilidad de 8 millas.' FROM locations WHERE slug = 'ciplak-ada-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Остров у входа в канал Ayvalık, к западу от полуострова Sarımsaklı. В южной бухте якорь отдают на 2-5 м на песчаном грунте; укрытие от северных ветров — ночью спокойно; чаще всего это стоянка на обед. Характеристики маяка острова: фокальная плоскость 18 м, красный проблеск каждые 3 с, видимость 8 миль.' FROM locations WHERE slug = 'ciplak-ada-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The waters off Ayvalık''s famous beach, which reaches 7 km in length. In 2-5 m the sand bottom holds well; the depth decreases rapidly towards the shore. It is an anchorage ONLY IN GOOD WEATHER — in bad weather the shelter is limited. Hotels, restaurants and cafes line the shore.' FROM locations WHERE slug = 'sarimsakli-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Frente a la famosa playa de Ayvalık, que alcanza 7 km de longitud. En 2-5 m el fondo de arena agarra bien; la profundidad disminuye rápidamente hacia la costa. Es un fondeadero SOLO CON BUEN TIEMPO — con mal tiempo el abrigo es limitado. Hoteles, restaurantes y cafeterías se alinean en la costa.' FROM locations WHERE slug = 'sarimsakli-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Акватория перед знаменитым пляжем Ayvalık протяжённостью до 7 км. На 2-5 м песчаный грунт держит хорошо; глубина быстро уменьшается к берегу. Якорная стоянка ТОЛЬКО В ХОРОШУЮ ПОГОДУ — в плохую погоду укрытие ограничено. Вдоль берега тянутся отели, рестораны и кафе.' FROM locations WHERE slug = 'sarimsakli-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'South of Ayvalık, the cooperative fishing harbour of Altınova; 85 boats. Protected by a natural breakwater; water and electricity connections are available. Kum Ada, joined to the mainland by a 450 m bridge, is right next to it. In the town there are a market, a health centre, hotels and restaurants, and shops selling local olive oil.' FROM locations WHERE slug = 'altinova-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Al sur de Ayvalık, el refugio pesquero cooperativo de Altınova; 85 embarcaciones. Está protegido por un rompeolas natural; dispone de conexión de agua y electricidad. Kum Ada, unida a tierra firme por un puente de 450 m, está justo al lado. En el pueblo hay supermercado, centro de salud, hoteles y restaurantes, así como tiendas de aceite de oliva local.' FROM locations WHERE slug = 'altinova-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'К югу от Ayvalık — кооперативная рыбацкая гавань Altınova; 85 судов. Защищена естественным волноломом; есть подключение воды и электричества. Рядом расположен остров Kum Ada, соединённый с материком мостом длиной 450 м. В посёлке есть магазин, медицинский центр, отели и рестораны, а также лавки местного оливкового масла.' FROM locations WHERE slug = 'altinova-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'One of the two islands off Bademli (Dikili) (357 thousand m²); it stretches on a north-south line with Kalem Adası, opposite Midilli. In the village of Bademli (1 km from the harbour) there are guesthouses, restaurants, a bakery, a health centre and a Tuesday market.' FROM locations WHERE slug = 'garip-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Una de las dos islas frente a Bademli (Dikili) (357 mil m²); se extiende en línea norte-sur con Kalem Adası, frente a Midilli. En el pueblo de Bademli (a 1 km del puerto) hay pensiones, restaurantes, panadería, centro de salud y mercado los martes.' FROM locations WHERE slug = 'garip-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Один из двух островов у побережья Bademli (Dikili) (357 тыс. м²); вытянут по линии север–юг вместе с островом Kalem Adası, напротив Midilli. В деревне Bademli (1 км от гавани) есть пансионы, рестораны, пекарня, медицинский центр и рынок по вторникам.' FROM locations WHERE slug = 'garip-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A bay on the Bademli (Dikili) coast, opposite the islands of Kalem and Garip. The village of Bademli, known for its long sandy beaches, is nearby; the village has accommodation, restaurants and health services.' FROM locations WHERE slug = 'pissa-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala en la costa de Bademli (Dikili), frente a las islas Kalem y Garip. El pueblo de Bademli, conocido por sus largas playas de arena, está cerca; en el pueblo hay alojamiento, restaurantes y servicios sanitarios.' FROM locations WHERE slug = 'pissa-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта на побережье Bademli (Dikili), напротив островов Kalem и Garip. Рядом находится деревня Bademli, известная длинными песчаными пляжами; в деревне есть жильё, рестораны и медицинские услуги.' FROM locations WHERE slug = 'pissa-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The harbour of the ancient city of İasos; 18 km to Milas. Call ''Kıyıkışlacık Harbour'' on VHF 16. Average depth 8 m; anchoring in 4 m is recommended in the harbour — the mud and sand bottom holds well. The remains of the ancient breakwater protect from southerly swell; the bay is sheltered from all directions. Electricity and drinking water on the quay; for more than 500 litres, fuel is arranged by tanker. In the village there are a restaurant, a cafe, guesthouses, a fish market and a pharmacy. Port İasos Marina is a separate facility.' FROM locations WHERE slug = 'kiyikislacik-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto de la antigua ciudad de İasos; a 18 km de Milas. Se llama a ''Kıyıkışlacık Harbour'' por VHF 16. Profundidad media de 8 m; se recomienda fondear en 4 m dentro del puerto — el fondo de fango y arena agarra bien. Los restos del antiguo rompeolas protegen del oleaje del sur; la cala está abrigada de todas las direcciones. Electricidad y agua potable en el muelle; para más de 500 litros el combustible se organiza con camión cisterna. En el pueblo hay restaurante, cafetería, pensiones, mercado de pescado y farmacia. Port İasos Marina es una instalación aparte.' FROM locations WHERE slug = 'kiyikislacik-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань античного города İasos; 18 км до Milas. Вызов ''Kıyıkışlacık Harbour'' на VHF 16. Средняя глубина 8 м; в гавани рекомендуется вставать на якорь на 4 м — илисто-песчаный грунт держит хорошо. Остатки античного волнолома защищают от южной волны; бухта укрыта от всех направлений. На причале электричество и питьевая вода; при объёме свыше 500 литров топливо доставляется автоцистерной. В деревне есть ресторан, кафе, пансионы, рыбный рынок и аптека. Port İasos Marina — отдельный объект.' FROM locations WHERE slug = 'kiyikislacik-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The village harbour of a wooded bay stretching east along the Pina peninsula, 18 km from Bodrum and 12 km from the airport. Anchor off the village in 4-9 m on a sand bottom; the holding is good — take a line ashore against the prevailing westerly. In the village there are guesthouses, an ATM, a pharmacy, a state clinic and a gendarmerie post; fresh sea bass can be bought from the farms in the bay. The ruins of ancient Karyanda are at the road entrance.' FROM locations WHERE slug = 'guvercinlik-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio del pueblo en una cala boscosa que se extiende hacia el este a lo largo de la península de Pina, a 18 km de Bodrum y a 12 km del aeropuerto. Se fondea frente al pueblo en 4-9 m sobre fondo de arena; el agarre es bueno — dé un cabo a tierra contra el viento dominante del oeste. En el pueblo hay pensiones, cajero automático, farmacia, clínica estatal y puesto de gendarmería; en las granjas de la cala puede comprarse lubina fresca. Las ruinas de la antigua Karyanda están a la entrada del camino.' FROM locations WHERE slug = 'guvercinlik-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Деревенская гавань лесистой бухты, тянущейся на восток вдоль полуострова Pina, в 18 км от Bodrum и в 12 км от аэропорта. Якорь отдают перед деревней на 4-9 м на песчаном грунте; держит хорошо — заведите конец на берег против преобладающего западного ветра. В деревне есть пансионы, банкомат, аптека, государственная клиника и пост жандармерии; на фермах в бухте можно купить свежего сибаса. Руины античной Karyanda находятся у начала дороги.' FROM locations WHERE slug = 'guvercinlik-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Between the capes of Çomca and Gök, locally known as ''Cennet Koyu''. SHALLOW ROCKY PATCHES extend from the tips of both capes — enter the bay through the channel in the middle. Anchor in 3-6 m, the holding is good; take a line ashore for safety. The southwest inlet is sheltered from the prevailing winds; a strong northerly sends in a swell. Pine-covered slopes and a running trail; the well waters that give the bay its name are on the shore.' FROM locations WHERE slug = 'ilicabuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Entre los cabos Çomca y Gök, conocida localmente como ''Cennet Koyu''. De las puntas de ambos cabos se extienden PLACAS ROCOSAS SOMERAS — entre en la cala por el canal central. Se fondea en 3-6 m, el agarre es bueno; dé un cabo a tierra por seguridad. La ensenada suroeste está abrigada de los vientos dominantes; el norte fuerte mete mar de fondo. Laderas cubiertas de pinos y senda para correr; las aguas de pozo que dan nombre a la cala están en la orilla.' FROM locations WHERE slug = 'ilicabuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Между мысами Çomca и Gök, местное название — ''Cennet Koyu''. От оконечностей обоих мысов тянутся МЕЛКОВОДНЫЕ СКАЛЬНЫЕ УЧАСТКИ — входите в бухту по срединному каналу. Якорь отдают на 3-6 м, держит хорошо; для надёжности заведите конец на берег. Юго-западная заводь укрыта от преобладающих ветров; сильный северный ветер нагоняет зыбь. Склоны, поросшие соснами, и беговая тропа; колодезные источники, давшие бухте имя, находятся на берегу.' FROM locations WHERE slug = 'ilicabuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A ''hidden cove'' south of Gök Burnu, 2,5 miles north of Torba. The depth drops quickly from 18-20 m to 7 m; anchor in 8-10 m. Well protected from the meltemi. CAUTION: keep clear of the reefs on the right-hand side at the entrance; in the north of the bay there is a sunken rock with 4 m of water over it. The shore is lined with palms; there are a private house and a private jetty.' FROM locations WHERE slug = 'demir-liman-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Una ''cala escondida'' al sur de Gök Burnu, a 2,5 millas al norte de Torba. La profundidad cae rápidamente de 18-20 m a 7 m; se fondea en 8-10 m. Bien protegida del meltemi. ATENCIÓN: manténgase alejado de los arrecifes del lado derecho en la entrada; al norte de la cala hay una roca sumergida con 4 m de agua encima. La orilla está bordeada de palmeras; hay una casa privada y un embarcadero privado.' FROM locations WHERE slug = 'demir-liman-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, '«Скрытая бухта» к югу от Gök Burnu, в 2,5 милях к северу от Torba. Глубина быстро падает с 18-20 м до 7 м; якорь отдают на 8-10 м. Хорошо защищена от мелтеми. ВНИМАНИЕ: на входе держитесь дальше от рифов с правой стороны; в северной части бухты есть подводная скала с глубиной 4 м над ней. Берег усажен пальмами; есть частный дом и частный причал.' FROM locations WHERE slug = 'demir-liman-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A pine-clad natural harbour in the east of the Gulf of Güllük, between Salih Adası and Kimse Burnu; sheltered from ALL winds. You can anchor in two creeks, northwest and northeast; the middle waterway gives shelter in any weather. In the northwest creek you can come alongside the hotel jetty. CAUTION: watch out for the mooring lines of the fish farms on both sides of the entrance; one section is marshy and must not be entered.' FROM locations WHERE slug = 'kuyucakbuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto natural cubierto de pinos al este del golfo de Güllük, entre Salih Adası y Kimse Burnu; abrigado de TODOS los vientos. Se fondea en dos brazos, el noroeste y el noreste; el canal central da refugio con cualquier tiempo. En el brazo noroeste puede atracarse al embarcadero del hotel. ATENCIÓN: cuidado con los cabos de amarre de las piscifactorías a ambos lados de la entrada; una parte es pantanosa y no debe entrarse en ella.' FROM locations WHERE slug = 'kuyucakbuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Поросшая соснами естественная гавань в восточной части залива Güllük, между Salih Adası и Kimse Burnu; укрыта от ВСЕХ ветров. Встать на якорь можно в двух рукавах — северо-западном и северо-восточном; срединный фарватер даёт убежище в любую погоду. В северо-западном рукаве можно ошвартоваться у причала отеля. ВНИМАНИЕ: остерегайтесь швартовных тросов рыбных ферм по обе стороны входа; один участок заболочен — заходить туда нельзя.' FROM locations WHERE slug = 'kuyucakbuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A bay in the Gulf of Güllük extending south, shoaling from the middle and ending in the Bükgöl marsh. Anchor in 3 m on a mud bottom. The meltemi and westerly winds send in a swell. The jetty of the fishing village of Boğaziçi takes ~4 boats; water and electricity are available; the village has a warden and fish restaurants. The ruins of ancient Bargylia are on the western shore.' FROM locations WHERE slug = 'ulelibuk-varvil-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala del golfo de Güllük que se extiende hacia el sur, perdiendo fondo desde su parte media y terminando en la marisma de Bükgöl. Se fondea en 3 m sobre fondo de fango. El meltemi y los vientos del oeste meten mar de fondo. El embarcadero del pueblo pesquero de Boğaziçi admite ~4 embarcaciones; hay agua y electricidad; en el pueblo hay un encargado y restaurantes de pescado. Las ruinas de la antigua Bargylia están en la orilla oeste.' FROM locations WHERE slug = 'ulelibuk-varvil-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта в заливе Güllük, вытянутая к югу; с середины мелеет и заканчивается болотом Bükgöl. Якорь отдают на 3 м на илистом грунте. Мелтеми и западные ветры нагоняют зыбь. Причал рыбацкой деревни Boğaziçi принимает ~4 яхты; есть вода и электричество; в деревне есть смотритель и рыбные рестораны. Руины античной Bargylia — на западном берегу.' FROM locations WHERE slug = 'ulelibuk-varvil-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'In Hisarönü, between the capes of Kargacık and Ayı, a narrowing bay indenting half a mile to the southwest. Anchor in 10-20 m; it shoals towards the shore. The stream-mouth side in the south is in the lee of the meltemi; a strong northerly both sends in a swell and funnels down from the mountain. CAUTION: reefs extend from the tip of the Kargacık cape at the entrance. The wooden restaurant jetty in the bay is a separate entry.' FROM locations WHERE slug = 'kocabahce-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'En Hisarönü, entre los cabos Kargacık y Ayı, una cala que se estrecha y se adentra media milla hacia el suroeste. Se fondea en 10-20 m; pierde fondo hacia la costa. El lado de la desembocadura del arroyo, al sur, queda al socaire del meltemi; el norte fuerte mete mar de fondo y además baja de la montaña como por un embudo. ATENCIÓN: en la entrada se extienden arrecifes desde la punta del cabo Kargacık. El embarcadero de madera del restaurante de la cala es un registro aparte.' FROM locations WHERE slug = 'kocabahce-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'В Hisarönü, между мысами Kargacık и Ayı, сужающаяся бухта, вдающаяся на полмили к юго-западу. Якорь отдают на 10-20 м; к берегу мелеет. Южная сторона у устья ручья находится под прикрытием от мелтеми; сильный северный ветер и нагоняет зыбь, и, как по воронке, срывается с горы. ВНИМАНИЕ: на входе от оконечности мыса Kargacık тянутся рифы. Деревянный ресторанный причал в бухте — отдельная запись.' FROM locations WHERE slug = 'kocabahce-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The wooden jetty inside Kocabahçe bay; berthing capacity for up to 11 boats. There are laid moorings and floating mooring lines. Ashore there are a restaurant and toilets; electricity is supplied by a generator.' FROM locations WHERE slug = 'kocabahce-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Embarcadero de madera dentro de la cala de Kocabahçe; capacidad de atraque para hasta 11 embarcaciones. Dispone de muertos con amarras preinstaladas (laid mooring) y amarres flotantes. En tierra hay restaurante y aseos; la electricidad se suministra con generador.' FROM locations WHERE slug = 'kocabahce-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Деревянный причал внутри бухты Kocabahçe; вместимость — до 11 яхт. Есть готовые швартовные бочки (laid mooring) и плавучие швартовы. На берегу — ресторан и туалет; электричество подаётся от генератора.' FROM locations WHERE slug = 'kocabahce-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A large bay near Bozburun; Tavşanbükü Adası lies in its middle — enter the bay to the west or to the east of the island. Anchor in 5-10 m; east of Değirmen Burnu, lines can be taken ashore. It is a stop for day-trip boats from Bozburun. CAUTION: the passage between the island and the mainland MUST NOT be attempted.' FROM locations WHERE slug = 'tavsanbuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Gran cala cerca de Bozburun; en su centro se encuentra Tavşanbükü Adası — se entra en la cala por el oeste o por el este de la isla. Se fondea en 5-10 m; al este de Değirmen Burnu pueden darse cabos a tierra. Es escala de las excursiones diarias en barco desde Bozburun. ATENCIÓN: el paso entre la isla y tierra NO DEBE INTENTARSE.' FROM locations WHERE slug = 'tavsanbuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Большая бухта возле Bozburun; в её центре расположен остров Tavşanbükü Adası — в бухту входят к западу или к востоку от острова. Якорь отдают на 5-10 м; к востоку от Değirmen Burnu можно завести концы на берег. Сюда заходят яхты однодневных прогулок из Bozburun. ВНИМАНИЕ: НЕ ПЫТАЙТЕСЬ проходить проливом между островом и берегом.' FROM locations WHERE slug = 'tavsanbuku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A wide, deserted bay open to the south, northeast of Ortaca Burnu at Bozburun; a spur divides the bay into two creeks. In the eastern creek anchor in 10-15 m or take lines ashore; it gives shelter from westerly winds. The shore is covered with scrub and thyme. CAUTION: keep clear of the rocks at the tip of the spur.' FROM locations WHERE slug = 'ayaca-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala amplia y solitaria, abierta al sur, al noreste de Ortaca Burnu en Bozburun; un saliente divide la cala en dos brazos. En el brazo este se fondea en 10-15 m o se dan cabos a tierra; ofrece abrigo frente a los vientos del oeste. La orilla está cubierta de matorral y tomillo. ATENCIÓN: manténgase alejado de las rocas de la punta del saliente.' FROM locations WHERE slug = 'ayaca-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Широкая безлюдная бухта, открытая к югу, к северо-востоку от Ortaca Burnu в районе Bozburun; выступ делит бухту на два рукава. В восточном рукаве якорь отдают на 10-15 м или заводят концы на берег; укрытие от западных ветров. Берег покрыт кустарником и тимьяном. ВНИМАНИЕ: держитесь дальше от скал у оконечности выступа.' FROM locations WHERE slug = 'ayaca-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A narrow bay extending half a mile east of Tavşanbükü Adası; it gives shelter from ALL directions but has room for only ~2 boats — anchor in 18-22 m and, if there is room, take a line ashore. In the valley on the shore there are almond trees and ruins. Bozen Koyu, right next to it, offers relative shelter from the prevailing wind in 10-13 m.' FROM locations WHERE slug = 'mercimek-buku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala estrecha que se extiende media milla al este de Tavşanbükü Adası; ofrece abrigo en TODAS las direcciones, pero solo hay sitio para ~2 embarcaciones — fondee en 18-22 m y, si hay sitio, dé un cabo a tierra. En el valle de la orilla hay almendros y ruinas. La contigua Bozen Koyu ofrece abrigo relativo del viento dominante en 10-13 m.' FROM locations WHERE slug = 'mercimek-buku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Узкая бухта, протянувшаяся на полмили к востоку от острова Tavşanbükü Adası; даёт укрытие от ВСЕХ направлений, но места хватает лишь на ~2 яхты — встаньте на якорь на 18-22 м и, если есть место, заведите конец на берег. В долине на берегу — миндальные деревья и руины. Соседняя бухта Bozen Koyu с глубинами 10-13 м даёт относительное укрытие от преобладающего ветра.' FROM locations WHERE slug = 'mercimek-buku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A harbour at Yeşilköy with a 350 m outer + 150 m inner breakwater; the fishing section takes 95 boats. Call ''Yeşilköy Marina'' on VHF 16. Water, electricity and a fuel pump on the quay; there are WC-showers and an administration office. The shelter is adequate; the wash of large commercial ships can be a nuisance. Entry and exit formalities for the country are handled at the Karaköy Yolcu Salonu. Characteristics of the lighthouse next to it: 18 m tower, a white flash every 10 s, 15 miles.' FROM locations WHERE slug = 'yesilkoy-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto en Yeşilköy con rompeolas exterior de 350 m + interior de 150 m; la sección pesquera admite 95 embarcaciones. Se llama a ''Yeşilköy Marina'' por VHF 16. Agua, electricidad y surtidor de combustible en el muelle; hay aseos con ducha y oficina de administración. El abrigo es suficiente; la estela de los grandes buques mercantes puede resultar molesta. Los trámites de entrada y salida del país se realizan en la Karaköy Yolcu Salonu. Características del faro contiguo: torre de 18 m, un destello blanco cada 10 s, 15 millas.' FROM locations WHERE slug = 'yesilkoy-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань в Yeşilköy с внешним молом 350 м + внутренним 150 м; рыбацкая часть вмещает 95 судов. Вызов ''Yeşilköy Marina'' на VHF 16. На причале вода, электричество и топливная колонка; есть туалеты с душем и офис администрации. Укрытие достаточное; волна от крупных торговых судов может беспокоить. Формальности въезда в страну и выезда из неё оформляются в Karaköy Yolcu Salonu. Характеристики соседнего маяка: башня 18 м, белый проблеск каждые 10 с, 15 миль.' FROM locations WHERE slug = 'yesilkoy-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'One of the busiest fishing harbours on the Anatolian side; 520 m main breakwater, 100 boats. There are electricity, drinking water, a fuel pump, a cold store, a hauling-out yard and a fish market. Metro, minibus, commuter train and sea bus connections are right next to it.' FROM locations WHERE slug = 'bostanci-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Uno de los refugios pesqueros más concurridos de la orilla anatolia; rompeolas principal de 520 m, 100 embarcaciones. Dispone de electricidad, agua potable, surtidor de combustible, cámara frigorífica, varadero y lonja de pescado. Las conexiones de metro, microbús, tren de cercanías y catamarán marítimo están justo al lado.' FROM locations WHERE slug = 'bostanci-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Одна из самых оживлённых рыбацких гаваней анатолийского берега; главный мол 520 м, 100 судов. Есть электричество, питьевая вода, топливная колонка, холодильный склад, слип для подъёма судов и рыбный рынок. Рядом — метро, маршрутки, пригородная электричка и морской автобус.' FROM locations WHERE slug = 'bostanci-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A cooperative fishing harbour at Maltepe Küçükyalı with a 250 m main breakwater; 100 boats. There are electricity, drinking water, a fuel pump, a cold store, a hauling-out yard and a fish market. The fish restaurants on the shore work according to the fish of the season.' FROM locations WHERE slug = 'kucukyali-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio pesquero cooperativo en Maltepe Küçükyalı con rompeolas principal de 250 m; 100 embarcaciones. Dispone de electricidad, agua potable, surtidor de combustible, cámara frigorífica, varadero y lonja de pescado. Los restaurantes de pescado de la costa trabajan según el pescado de temporada.' FROM locations WHERE slug = 'kucukyali-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Кооперативная рыбацкая гавань в Maltepe Küçükyalı с главным молом 250 м; 100 судов. Есть электричество, питьевая вода, топливная колонка, холодильный склад, слип и рыбный рынок. Рыбные рестораны на берегу работают по сезонной рыбе.' FROM locations WHERE slug = 'kucukyali-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The cooperative fishing harbour of Heybeliada, the second largest of the Adalar; 70 boats. The breakwater light shows a red flash every 2 s (7 miles). On the island there are restaurants, hotels, repair shops, health and banking services; sea buses run to Bostancı and Kabataş, and ferries to Kadıköy. Çam Limanı bay, on the southwest of the island, is a separate entry.' FROM locations WHERE slug = 'heybeliada-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio pesquero cooperativo de Heybeliada, la segunda más grande de las Adalar; 70 embarcaciones. El faro del rompeolas emite un destello rojo cada 2 s (7 millas). En la isla hay restaurantes, hoteles, talleres de reparación, servicios sanitarios y bancarios; salen catamaranes a Bostancı y Kabataş, y ferris a Kadıköy. La cala de Çam Limanı, al suroeste de la isla, es un registro aparte.' FROM locations WHERE slug = 'heybeliada-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Кооперативная рыбацкая гавань Heybeliada, второго по величине из островов Adalar; 70 судов. Огонь на молу даёт красный проблеск каждые 2 с (7 миль). На острове есть рестораны, отели, ремонтные мастерские, медицинские и банковские услуги; в Bostancı и Kabataş ходит морской автобус, в Kadıköy — паром. Бухта Çam Limanı на юго-западе острова — отдельная запись.' FROM locations WHERE slug = 'heybeliada-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A fishing harbour with a 265 m main breakwater at Silivri Selimpaşa, 50 km west of İstanbul. Call ''Selimpaşa Harbour'' on VHF 16. 2-3,5 m at the entrance; 0,5-1,5 m at the western and northern quays — BOATS WITH DEEP DRAUGHT BEWARE. Good shelter from all directions except the east. There are drinking water, electricity, fuel and a hauling-out yard; there is a restaurant on the northern side.' FROM locations WHERE slug = 'selimpasa-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio con rompeolas principal de 265 m en Silivri Selimpaşa, a 50 km al oeste de İstanbul. Se llama a ''Selimpaşa Harbour'' por VHF 16. En la entrada, 2-3,5 m; en los muelles oeste y norte, 0,5-1,5 m — ATENCIÓN EMBARCACIONES DE MUCHO CALADO. Buen abrigo de todas las direcciones salvo del este. Dispone de agua potable, electricidad, combustible y varadero; en el lado norte hay un restaurante.' FROM locations WHERE slug = 'selimpasa-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань с главным молом 265 м в Silivri Selimpaşa, в 50 км к западу от İstanbul. Вызов ''Selimpaşa Harbour'' на VHF 16. На входе 2-3,5 м; у западного и северного причалов 0,5-1,5 м — ВНИМАНИЕ СУДАМ С БОЛЬШОЙ ОСАДКОЙ. Хорошее укрытие от всех направлений, кроме восточного. Есть питьевая вода, электричество, топливо и слип; с северной стороны находится ресторан.' FROM locations WHERE slug = 'selimpasa-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A municipally operated harbour at Büyükçekmece Mimarsinan; 290 m outer breakwater. Call ''Mimarsinan Marina'' on VHF 73. There are electricity, drinking water, fuel, a hauling-out yard and a shore parking area. Breakwater light: 7 m tower, 3 miles visibility.' FROM locations WHERE slug = 'mimarsinan-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio de gestión municipal en Büyükçekmece Mimarsinan; rompeolas exterior de 290 m. Se llama a ''Mimarsinan Marina'' por VHF 73. Dispone de electricidad, agua potable, combustible, varadero y explanada de estacionamiento en tierra. Faro del rompeolas: torre de 7 m, visibilidad de 3 millas.' FROM locations WHERE slug = 'mimarsinan-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань в муниципальном управлении в Büyükçekmece Mimarsinan; внешний мол 290 м. Вызов ''Mimarsinan Marina'' на VHF 73. Есть электричество, питьевая вода, топливо, слип и береговая площадка для стоянки судов. Огонь на молу: башня 7 м, видимость 3 мили.' FROM locations WHERE slug = 'mimarsinan-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Municipal marina at the eastern end of the Gulf of İzmit, ~100 km from İstanbul; capacity for 400 yachts, depths of 7-10 m. Call ''İzmit Marina'' on VHF 16. Drinking water, electricity, a fuel station, telephone/internet, cable TV, a boatyard with haul-out and maintenance-repair services are available. Shipyards, hotels, hospitals and shopping facilities are found in the surroundings.' FROM locations WHERE slug = 'izmit-belediye-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto deportivo municipal en el extremo oriental del golfo de İzmit, a ~100 km de İstanbul; capacidad para 400 yates, calados de 7-10 m. Se llama a ''İzmit Marina'' por VHF 16. Dispone de agua potable, electricidad, estación de combustible, teléfono/internet, TV por cable, varadero y servicios de mantenimiento y reparación. En los alrededores hay astilleros, hoteles, hospitales y zonas comerciales.' FROM locations WHERE slug = 'izmit-belediye-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Муниципальная марина в восточной оконечности залива İzmit, в ~100 км от İstanbul; вместимость 400 яхт, глубины 7-10 м. Вызов ''İzmit Marina'' на VHF 16. Есть питьевая вода, электричество, топливная станция, телефон/интернет, кабельное ТВ, место для подъёма судов и услуги по техобслуживанию и ремонту. В окрестностях верфи, отели, больницы и магазины.' FROM locations WHERE slug = 'izmit-belediye-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Municipally operated fishing shelter plus yacht harbour in Darıca; 300 boats. Drinking water, electricity, fuel, technical service, a boatyard, an administration building, a net-repair workshop and a fish market are available. The entrance is marked by the Yelkenkaya lighthouse, visible for 18 miles. The shore is famous for its fish restaurants.' FROM locations WHERE slug = 'darica-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio pesquero y puerto deportivo de gestión municipal en Darıca; 300 embarcaciones. Dispone de agua potable, electricidad, combustible, servicio técnico, varadero, edificio de administración, taller de reparación de redes y lonja de pescado. La entrada está señalizada por el faro de Yelkenkaya, visible a 18 millas. La costa es famosa por sus restaurantes de pescado.' FROM locations WHERE slug = 'darica-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Рыбацкая гавань и яхтенный порт под управлением муниципалитета в Darıca; 300 судов. Есть питьевая вода, электричество, топливо, технический сервис, место для подъёма судов, здание администрации, мастерская по ремонту сетей и рыбный рынок. Вход обозначает маяк Yelkenkaya с дальностью видимости 18 миль. Побережье славится рыбными ресторанами.' FROM locations WHERE slug = 'darica-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Cooperative-run fishing shelter in Eskihisar, Gebze, next to the Topçular (Yalova) ferry pier; 95 boats. VHF 16. Drinking water, electricity, fuel, WC-showers and a customs office are available. Seaside fish restaurants, the Osman Hamdi Bey Museum and the castle are nearby.' FROM locations WHERE slug = 'eskihisar-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio pesquero de cooperativa en Eskihisar, Gebze, junto al embarcadero del ferry de Topçular (Yalova); 95 embarcaciones. VHF 16. Dispone de agua potable, electricidad, combustible, WC y duchas, y oficina de aduanas. Cerca hay restaurantes de pescado junto al mar, el museo Osman Hamdi Bey y el castillo.' FROM locations WHERE slug = 'eskihisar-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Кооперативная рыбацкая гавань в Eskihisar (Gebze), рядом с паромным причалом Topçular (Yalova); 95 судов. VHF 16. Есть питьевая вода, электричество, топливо, туалеты с душем и таможенный офис. Рядом прибрежные рыбные рестораны, музей Osman Hamdi Bey и крепость.' FROM locations WHERE slug = 'eskihisar-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Shipyard-marina in Eskihisar operating year-round. Call ''Atabay Marina'' on VHF 16. Fuel, fresh water and electricity; engine, propeller and hull repairs, fibreglass/wood repair, electronics, lathe and paint workshops; there are two 100-ton cranes. Capacity for ~100 boats ashore; a 25-room hotel, restaurant and bar.' FROM locations WHERE slug = 'atabay-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Astillero-marina en Eskihisar que opera todo el año. Se llama a ''Atabay Marina'' por VHF 16. Combustible, agua dulce y electricidad; reparación de motores, hélices y cascos, reparaciones de fibra de vidrio y madera, talleres de electrónica, torno y pintura; hay dos grúas de 100 toneladas. Capacidad en tierra para ~100 embarcaciones; hotel de 25 habitaciones, restaurante y bar.' FROM locations WHERE slug = 'atabay-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Верфь-марина в Eskihisar, работающая круглый год. Вызов ''Atabay Marina'' на VHF 16. Топливо, пресная вода и электричество; ремонт двигателей, гребных винтов и корпусов, ремонт стеклопластика и дерева, мастерские электроники, токарных и малярных работ; есть два крана по 100 тонн. Вместимость на берегу ~100 судов; отель на 25 номеров, ресторан и бар.' FROM locations WHERE slug = 'atabay-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Cooperative fishing shelter of Hereke — famous for its silk carpets — on the northern shore of the Gulf of İzmit; 60 boats. Electricity, drinking water, a fuel station and an administration office are available; the fish of the day can be bought at the fish market inside the shelter.' FROM locations WHERE slug = 'hereke-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio pesquero de cooperativa de Hereke, famosa por sus alfombras de seda, en la costa norte del golfo de İzmit; 60 embarcaciones. Dispone de electricidad, agua potable, estación de combustible y oficina de administración; el pescado del día puede comprarse en la lonja del refugio.' FROM locations WHERE slug = 'hereke-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Кооперативная рыбацкая гавань Hereke, знаменитого своими шёлковыми коврами, на северном берегу залива İzmit; 60 судов. Есть электричество, питьевая вода, топливная станция и офис администрации; рыбу дня можно купить на рыбном рынке в гавани.' FROM locations WHERE slug = 'hereke-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Fishing shelter of the village of Ereğli on the southern shore of the Gulf of İzmit, 4 km from Karamürsel; 85 boats. Call ''Ereğli Marina'' on VHF 16. Electricity, drinking water, a fuel station, a fish restaurant, a fish market and a cold-storage facility are available. There is a sea-bus connection to Yenikapı.' FROM locations WHERE slug = 'karamursel-eregli-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio pesquero del pueblo de Ereğli en la costa sur del golfo de İzmit, a 4 km de Karamürsel; 85 embarcaciones. Se llama a ''Ereğli Marina'' por VHF 16. Dispone de electricidad, agua potable, estación de combustible, restaurante de pescado, lonja y cámara frigorífica. Hay conexión de catamarán rápido (sea bus) con Yenikapı.' FROM locations WHERE slug = 'karamursel-eregli-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань деревни Ereğli на южном берегу залива İzmit, в 4 км от Karamürsel; 85 судов. Вызов ''Ereğli Marina'' на VHF 16. Есть электричество, питьевая вода, топливная станция, рыбный ресторан, рыбный рынок и холодильный склад. Имеется сообщение морским автобусом с Yenikapı.' FROM locations WHERE slug = 'karamursel-eregli-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The former Setur Gökova Ören Marina on the northern shore of the Gulf of Gökova has been converted into the ''Ören Rib & Refit Park'', a haul-out and maintenance-refit facility. It offers a 150-boat dry park, a 240-ton amphibious lift for boats up to 50 m, a 70-ton travel lift and three covered hangars. It does not provide sea berths for visiting boats; services cover haul-out, winter storage and refit.' FROM locations WHERE slug = 'gokova-oren-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La antigua Setur Gökova Ören Marina, en la costa norte del golfo de Gökova, se ha convertido en el ''Ören Rib & Refit Park'', una instalación de varada y mantenimiento-refit. Dispone de parque en seco para 150 embarcaciones, un elevador anfibio de 240 toneladas para barcos de hasta 50 m, un travel lift de 70 toneladas y tres hangares cubiertos. No ofrece amarres en el agua para embarcaciones visitantes; sus servicios son varada, invernaje y refit.' FROM locations WHERE slug = 'gokova-oren-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бывшая марина Setur Gökova Ören на северном берегу залива Gökova преобразована в «Ören Rib & Refit Park» — комплекс подъёма и ремонта судов. Здесь сухая стоянка на 150 судов, амфибийный подъёмник на 240 тонн для судов до 50 м, травел-лифт на 70 тонн и три крытых ангара. Стоянка на воде для приходящих судов не предоставляется; услуги — подъём, зимнее хранение и рефит.' FROM locations WHERE slug = 'gokova-oren-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Marina in Altınyunus bay between Boyalık and Ilıca in Çeşme: 186 boats afloat, 60 ashore; maximum length 45 m, depths up to 4 m. Electricity, water, Wi-Fi, security, fuel and diver service; WC-showers, laundry, ATM, restaurant-bar and a beach. The bay is considered one of the world''s favourable bays for windsurfing — the afternoon thermal wind is pronounced.' FROM locations WHERE slug = 'setur-altinyunus-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto deportivo en la cala de Altınyunus, entre Boyalık e Ilıca, en Çeşme: 186 embarcaciones a flote y 60 en tierra; eslora máxima 45 m, calados de hasta 4 m. Electricidad, agua, Wi-Fi, seguridad, combustible y servicio de buzo; WC y duchas, lavandería, cajero automático, restaurante-bar y playa. La cala está considerada una de las bahías más favorables del mundo para el windsurf: por la tarde el viento térmico es pronunciado.' FROM locations WHERE slug = 'setur-altinyunus-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Марина в бухте Altınyunus между Boyalık и Ilıca в Çeşme: 186 судов на воде, 60 на берегу; максимальная длина 45 м, глубины до 4 м. Электричество, вода, Wi-Fi, охрана, топливо и услуги водолаза; туалеты с душем, прачечная, банкомат, ресторан-бар и пляж. Бухта считается одной из самых благоприятных в мире для виндсёрфинга — после полудня заметен термический ветер.' FROM locations WHERE slug = 'setur-altinyunus-marina'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The harbour of ancient Samos, directly opposite Kuşadası and the Dilek peninsula. Depth inside the harbour ~5 m; mud bottom, good holding with 25 m of chain. The inner harbour is safe in all weather; the outer quay is open to the southeast — with strong E/SE winds two anchors are recommended. Water and electricity on the quay; fuel by mini-tanker or from Samos Marina, 1,5 miles to the north. Harbour fee ~10 € per night (2017). CAUTION: near the middle of the inner harbour entrance there is a DANGEROUS ROCK marked by a buoy — enter along the northern side; anchoring in the inner harbour has been prohibited since 2021. At night the quayside cafés can be noisy until morning.' FROM locations WHERE slug = 'pythagorio-limani-samos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto de la antigua Samos, justo enfrente de Kuşadası y la península de Dilek. Profundidad dentro del puerto ~5 m; fondo de fango, buen agarre con 25 m de cadena. El puerto interior es seguro con cualquier tiempo; el muelle exterior está abierto al sureste: con viento fuerte de E/SE se recomiendan dos anclas. Agua y electricidad en el muelle; combustible con minicisterna o en Samos Marina, a 1,5 millas al norte. Tarifa portuaria ~10 € por noche (2017). ATENCIÓN: cerca del centro de la entrada del puerto interior hay una ROCA PELIGROSA señalizada con una boya; entre por el lado norte; desde 2021 está prohibido fondear en el puerto interior. De noche, los cafés del muelle pueden ser ruidosos hasta la madrugada.' FROM locations WHERE slug = 'pythagorio-limani-samos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань античного Samos; прямо напротив Kuşadası и полуострова Dilek. Глубина внутри гавани ~5 м; илистое дно, хорошо держит при 25 м цепи. Внутренняя гавань безопасна в любую погоду; внешний причал открыт на юго-восток — при сильном ветре В/ЮВ рекомендуются два якоря. Вода и электричество на причале; топливо мини-танкером или в Samos Marina в 1,5 мили к северу. Портовый сбор ~10 € за ночь (2017). ВНИМАНИЕ: близ середины входа во внутреннюю гавань есть ОПАСНАЯ СКАЛА, обозначенная буем — входите вдоль северной кромки; с 2021 года якорная стоянка во внутренней гавани запрещена. Ночью кафе на набережной могут шуметь до самого утра.' FROM locations WHERE slug = 'pythagorio-limani-samos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The harbour of Vathy, the capital of Samos. There is ~3 m of water almost everywhere along the quay; berth well away from the ferry quay. The main bay is fully open to the north-northwest — in the meltemi a noticeable cross swell enters; the small marina in the southeast corner is protected from the meltemi (with slight swell). Water in the marina; fuel by mini-tanker. In town, the supermarket, bank and restaurants line the waterfront.' FROM locations WHERE slug = 'samos-vathy-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto de Vathy, la capital de Samos. Hay ~3 m de agua casi en todo el muelle; hay que amarrar lejos del muelle del ferry. La bahía principal está completamente abierta al nor-noroeste: con el meltemi entra una notable mar cruzada; el pequeño puerto deportivo del rincón sureste queda protegido del meltemi (con ligera marejada). Agua en el puerto deportivo; combustible con minicisterna. En el pueblo, el supermercado, el banco y los restaurantes se alinean a lo largo del muelle.' FROM locations WHERE slug = 'samos-vathy-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань Vathy, столицы Samos. Почти повсюду вдоль причала глубина ~3 м; швартуйтесь подальше от паромного причала. Главный залив полностью открыт на северо-северо-запад — при мельтеми заходит заметная перекрёстная волна; маленькая марина в юго-восточном углу защищена от мельтеми (с лёгкой зыбью). Вода в марине; топливо мини-танкером. В городке супермаркет, банк и рестораны — вдоль набережной.' FROM locations WHERE slug = 'samos-vathy-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The only harbour of little Agathonisi, opposite the Didim-Datça stretch of coast. The ferry quay takes 3-4 monohulls (fewer if a catamaran is present); anchoring room in the bay is limited — anchor in 7-12 m in the western and eastern arms, holding is good. Well protected from the meltemi; open to the south; strong gusts occur between July and September. CAUTION: in summer swimming buoys are laid and strictly enforced. The village has 3 restaurants and grocery shops; DO NOT DRINK THE WATER (it is not drinking water).' FROM locations WHERE slug = 'agathonisi-agios-georgios'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El único puerto de la pequeña Agathonisi, frente a la línea Didim-Datça. En el muelle del ferry caben 3-4 monocascos (menos si hay un catamarán); el espacio para fondear en la cala es limitado: se fondea en 7-12 m en los brazos oeste y este, con buen agarre. Bien protegido del meltemi; abierto al sur; entre julio y septiembre se producen fuertes rachas de viento. ATENCIÓN: en verano se colocan boyas de baño y se vigilan estrictamente. En el pueblo hay 3 restaurantes y tiendas de comestibles; NO BEBA EL AGUA (no es potable).' FROM locations WHERE slug = 'agathonisi-agios-georgios'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Единственная гавань маленького Agathonisi, напротив линии Didim-Datça. У паромного причала помещаются 3-4 однокорпусные яхты (меньше, если стоит катамаран); мест для якорной стоянки в бухте немного — становятся на якорь на 7-12 м в западном и восточном рукавах, держит хорошо. Хорошо защищена от мельтеми; открыта к югу; с июля по сентябрь бывают сильные шквалистые порывы ветра. ВНИМАНИЕ: летом выставляются купальные буи, и за этим строго следят. В деревне 3 ресторана и продуктовые лавки; НЕ ПЕЙТЕ ВОДУ (она не питьевая).' FROM locations WHERE slug = 'agathonisi-agios-georgios'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The main harbour of Amorgos. Drop anchor to the north and moor stern-to the quay. The wide bay is open to the north-northeast; in strong westerly winds the waves in the bay can reach 1,5 m. Electricity on the quay; fuel by mini-tanker; there are a boatyard, supermarket, bank and restaurants. Harbour fee ~14 €/night (12 m boat, 2017), water ~5 €. The opposite (northern) side of the bay is the fishing harbour of Xilokeratidi.' FROM locations WHERE slug = 'katapola-limani-amorgos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto principal de Amorgos. Se fondea el ancla hacia el norte y se amarra de popa al muelle. La amplia bahía está abierta al nor-nordeste; con viento fuerte del oeste las olas en la bahía pueden alcanzar 1,5 m. Electricidad en el muelle; combustible con minicisterna; hay astillero, supermercado, banco y restaurantes. Tarifa portuaria ~14 €/noche (barco de 12 m, 2017), agua ~5 €. La orilla opuesta (norte) de la bahía es el puerto pesquero de Xilokeratidi.' FROM locations WHERE slug = 'katapola-limani-amorgos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Главная гавань Amorgos. Якорь отдают к северу и швартуются кормой к причалу. Широкая бухта открыта на северо-северо-восток; при сильном западном ветре волна в бухте может достигать 1,5 м. Электричество на причале; топливо мини-танкером; есть верфь, супермаркет, банк и рестораны. Портовый сбор ~14 €/ночь (яхта 12 м, 2017), вода ~5 €. Противоположный (северный) берег бухты — рыбацкий порт Xilokeratidi.' FROM locations WHERE slug = 'katapola-limani-amorgos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The yacht section of Mykonos''s new port; ~40 pontoon berths, maximum length 25 m, depths 3-5 m. There are two entrances (southern with a red light, northern with a green light); the southern quay is more sheltered. Water and electricity on the pontoons; fuel by mini-tanker; Wi-Fi, showers-WC and mechanical repairs are available. CAUTION: the meltemi blows straight into the marina from the N/NW — Mykonos is among the windiest islands of the Cyclades. 20 min walk to town, or take the bus.' FROM locations WHERE slug = 'tourlos-marina-mykonos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La sección para yates del nuevo puerto de Mykonos; ~40 amarres en pantalanes, eslora máxima 25 m, calados de 3-5 m. Hay dos entradas (la sur con luz roja, la norte con luz verde); el muelle sur está más resguardado. Agua y electricidad en los pantalanes; combustible con minicisterna; hay Wi-Fi, duchas y WC, y reparaciones mecánicas. ATENCIÓN: el meltemi sopla directamente hacia el puerto deportivo desde el N/NO; Mykonos es una de las islas más ventosas de las Cícladas. Al pueblo, 20 min a pie o en autobús.' FROM locations WHERE slug = 'tourlos-marina-mykonos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Яхтенная часть нового порта Mykonos; ~40 мест у понтонов, максимальная длина 25 м, глубины 3-5 м. Есть два входа (южный — красный огонь, северный — зелёный); южный причал лучше защищён. Вода и электричество на понтонах; топливо мини-танкером; есть Wi-Fi, душ и туалеты, механический ремонт. ВНИМАНИЕ: мельтеми дует с С/СЗ прямо в марину — Mykonos входит в число самых ветреных островов Киклад. До городка 20 мин пешком или автобусом.' FROM locations WHERE slug = 'tourlos-marina-mykonos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A charming fishing town in the north of Paros. 3-5 m at the quay, 4-10 m in the outer part; the mud-sand-weed bottom holds well; there are ~70 places. Well protected from the meltemi; but strong wind from any direction makes mooring uncomfortable. CAUTION: some sections of the quay have an underwater rock ledge and a chain running east-west; the ferry area must be left clear; most of the space is taken by local fishing boats. Fuel by mini-tanker; repairs/boatyard, supermarket and restaurants are available. The surrounding bays (Langeri, Ag. Ioannou, Plastira) offer alternative anchorages.' FROM locations WHERE slug = 'naoussa-limani-paros'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Encantador pueblo pesquero del norte de Paros. 3-5 m en el muelle, 4-10 m en la parte exterior; el fondo de fango, arena y algas agarra bien; hay ~70 plazas. Bien protegido del meltemi; pero el viento fuerte de cualquier dirección incomoda el amarre. ATENCIÓN: en algunos tramos del muelle hay un saliente rocoso sumergido y una cadena tendida de este a oeste; la zona del ferry debe dejarse libre; la mayoría de las plazas las ocupan barcos pesqueros locales. Combustible con minicisterna; hay reparaciones/astillero, supermercado y restaurantes. Las calas de los alrededores (Langeri, Ag. Ioannou, Plastira) ofrecen fondeaderos alternativos.' FROM locations WHERE slug = 'naoussa-limani-paros'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Живописный рыбацкий городок на севере Paros. У причала 3-5 м, во внешней части 4-10 м; дно из ила, песка и водорослей держит хорошо; всего ~70 мест. Хорошо защищён от мельтеми; но сильный ветер с любого направления делает стоянку у причала беспокойной. ВНИМАНИЕ: на некоторых участках причала есть подводный скальный выступ и цепь, протянутая с востока на запад; зону парома оставляют свободной; большинство мест занимают местные рыбацкие лодки. Топливо мини-танкером; есть ремонт/верфь, супермаркет и рестораны. Соседние бухты (Langeri, Ag. Ioannou, Plastira) предлагают альтернативные якорные стоянки.' FROM locations WHERE slug = 'naoussa-limani-paros'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The stone harbour of İdra, the car-free island that is the pearl of the Saronic. VHF 12. Water, electricity and fuel are available. CAUTION: the bottom is a mix of weed, rock and mud and the HOLDING IS POOR; northwesterly wind creates a dangerous surge — in N/NE winds the northern breakwater is preferred. Crowding (per sources): extremely crowded in the summer months, boats lie alongside the quay THREE DEEP; ferries and hydrofoils pass fast through the narrow entrance. Arrive early.' FROM locations WHERE slug = 'hydra-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto de piedra de İdra, la isla sin coches, perla del Sarónico. VHF 12. Hay agua, electricidad y combustible. ATENCIÓN: el fondo es una mezcla de algas, roca y fango y el AGARRE ES DÉBIL; el viento del noroeste crea una resaca peligrosa: con viento de N/NE se prefiere el rompeolas norte. Aglomeración (según fuentes): en los meses de verano está sumamente abarrotado, los barcos se abarloan al muelle en TRES FILAS; por la estrecha bocana los ferris y los hidroalas pasan rápido. Llegue temprano.' FROM locations WHERE slug = 'hydra-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Каменная гавань İdra, острова без автомобилей, жемчужины Саронического залива. VHF 12. Есть вода, электричество и топливо. ВНИМАНИЕ: дно — смесь травы, камня и ила, и ЯКОРЬ ДЕРЖИТ ПЛОХО; северо-западный ветер создаёт опасную толчею — при ветре С/СВ предпочтителен северный мол. Загруженность (по источникам): в летние месяцы гавань переполнена, суда швартуются лагом к причалу В ТРИ РЯДА; в узком входе быстро проходят паромы и суда на подводных крыльях. Приходите пораньше.' FROM locations WHERE slug = 'hydra-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The main harbour of Egina, one of the islands closest to Athens; the white chapel on the western breakwater can be made out from afar. 8-9 m in the channel; rock-and-mud bottom. At the entrance the starboard side is the marina; boats berth perpendicular to the pontoons; on the quay there is mooring with laid buoys (the southern breakwater is reserved for charter boats). VHF 12. Water, electricity and fuel by mini-tanker. Well protected from all directions; southerly wind sends in an uncomfortable swell; in strong NW winds mooring in the ESE section is dangerous — veer out the chain fully. CAUTION: ferry/hydrofoil traffic is fast. To the north a shoal extends toward N. Metopi.' FROM locations WHERE slug = 'aegina-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto principal de Egina, una de las islas más cercanas a Atenas; la capilla blanca del rompeolas oeste se distingue desde lejos. 8-9 m en el canal; fondo de roca y fango. En la entrada, el lado de estribor es el puerto deportivo; se amarra en perpendicular a los pantalanes; en el muelle hay amarre con boyas (el rompeolas sur se reserva a los barcos de chárter). VHF 12. Agua, electricidad y combustible con minicisterna. Bien protegido de todas las direcciones; el viento del sur mete una marejada incómoda; con viento fuerte del NO el amarre en el sector ESE es peligroso: largue toda la cadena. ATENCIÓN: el tráfico de ferris e hidroalas es rápido. Al norte se extiende un bajío hacia N. Metopi.' FROM locations WHERE slug = 'aegina-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Главная гавань Egina, одного из ближайших к Афинам островов; белая часовня на западном молу видна издалека. В канале 8-9 м; дно — камень и ил. При входе марина по правому борту; к понтонам швартуются носом или кормой; у причала — швартовка на выложенных буях (южный мол отведён чартерным яхтам). VHF 12. Вода, электричество и топливо мини-танкером. Хорошо защищена со всех направлений; южный ветер заводит неприятную зыбь; при сильном СЗ ветре стоянка в секторе ВЮВ опасна — вытравите цепь полностью. ВНИМАНИЕ: паромы и суда на подводных крыльях ходят быстро. К северу в сторону N. Metopi тянется отмель.' FROM locations WHERE slug = 'aegina-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The old harbour of Spetses, surrounded by traditional caique boatyards; the eastern entrance is marked by the Ak Fanari light. The inner basin holds well on a mud bottom and gives COMPLETE shelter; lines can be taken ashore. The outer harbour is uncomfortable in strong NW winds; in its southwest corner lies a large abandoned chain — do not drop your anchor there. Fuel, water and electricity are available. In season the inner basin gets jammed full. CAUTION: there are numerous reefs between Spetses and the island of Spetsopoula.' FROM locations WHERE slug = 'spetses-baltiza-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto viejo de Spetses, rodeado de astilleros tradicionales de caiques; la entrada este está señalizada por el faro de Ak Fanari. La dársena interior agarra bien sobre fondo de fango y ofrece un abrigo TOTAL; se pueden llevar amarras a tierra. El puerto exterior resulta incómodo con viento fuerte del NO; en su rincón suroeste hay una gran cadena abandonada: no fondee el ancla allí. Hay combustible, agua y electricidad. En temporada la dársena interior se abarrota. ATENCIÓN: entre Spetses y la isla de Spetsopoula hay numerosos arrecifes.' FROM locations WHERE slug = 'spetses-baltiza-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Старая гавань Spetses, окружённая традиционными верфями каиков; восточный вход обозначает маяк Ak Fanari. Во внутренней акватории илистое дно хорошо держит якорь, укрытие ПОЛНОЕ; можно заводить швартовы на берег. Внешняя гавань неспокойна при сильном СЗ ветре; в её юго-западном углу лежит большая бесхозная цепь — не бросайте там якорь. Есть топливо, вода и электричество. В сезон внутренняя акватория забита. ВНИМАНИЕ: между Spetses и островом Spetsopoula множество рифов.' FROM locations WHERE slug = 'spetses-baltiza-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The traditional harbour of butterfly-shaped Astypalaia, at the foot of the Chora. The main ferry traffic has moved to the new port of Agios Andreas; in recent years a small marina arrangement for sailing yachts has been set up at Pera Gialos; the local ferry from Kalymnos calls here. The white houses of the Chora and the castle stand right above the harbour.' FROM locations WHERE slug = 'astypalaia-pera-gialos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto tradicional de Astypalaia, la isla con forma de mariposa, al pie de la Chora. El tráfico principal de ferris se ha trasladado al nuevo puerto de Agios Andreas; en los últimos años se ha instalado en Pera Gialos una pequeña estructura de puerto deportivo para veleros; atraca el ferry local de Kalymnos. Las casas blancas de la Chora y el castillo se alzan justo sobre el puerto.' FROM locations WHERE slug = 'astypalaia-pera-gialos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Традиционная гавань похожего на бабочку острова Astypalaia у подножия Chora. Основной паромный трафик перенесён в новый порт Agios Andreas; в последние годы в Pera Gialos обустроена небольшая марина для парусных яхт; сюда подходит местный паром с Kalymnos. Белые дома Chora и крепость возвышаются прямо над гаванью.' FROM locations WHERE slug = 'astypalaia-pera-gialos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Restaurant jetty on the northwestern side of Çiftlik bay, Marmaris. The T-shaped jetty has laid moorings (mooring lines); water and electricity can be connected. Call ''Azmak Jetty'' on VHF 16. According to the source, capacity is ~100 boats, maximum length 10 m, maximum draught 5 m. A restaurant and a bar provide service.' FROM locations WHERE slug = 'azmak-iskelesi-ciftlik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Embarcadero de restaurante en el lado noroeste de la cala de Çiftlik, en Marmaris. El pantalán en forma de T dispone de muertos con guías (mooring lines); se conectan agua y electricidad. Se llama a ''Azmak Jetty'' por VHF 16. Según la fuente, la capacidad es de ~100 embarcaciones, eslora máxima 10 m y calado máximo 5 m. Dan servicio un restaurante y un bar.' FROM locations WHERE slug = 'azmak-iskelesi-ciftlik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Ресторанный причал на северо-западной стороне бухты Çiftlik под Marmaris. Т-образный пирс оборудован готовыми швартовными концами (mooring lines); подключаются вода и электричество. Вызов ''Azmak Jetty'' на VHF 16. По данным источника, вместимость ~100 судов, максимальная длина 10 м, максимальная осадка 5 м. Работают ресторан и бар.' FROM locations WHERE slug = 'azmak-iskelesi-ciftlik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Hotel-restaurant jetty in Bozburun; you come alongside the pontoons and are hosted at the restaurant. The main building has 16 rooms, and the Beach House, three minutes away by boat, has 10 rooms + 1 suite. The centre of Bozburun village is a few minutes away by boat.' FROM locations WHERE slug = 'karia-bel-iskelesi-bozburun'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Embarcadero de hotel-restaurante en Bozburun; se atraca a los pantalanes y le atienden en el restaurante. El edificio principal tiene 16 habitaciones, y la Beach House, a tres minutos en barco, tiene 10 habitaciones + 1 suite. Al centro del pueblo de Bozburun se llega en pocos minutos en barco.' FROM locations WHERE slug = 'karia-bel-iskelesi-bozburun'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Причал отеля-ресторана в Bozburun; яхты швартуются к понтонам, гостей принимают в ресторане. В главном здании 16 номеров, в Beach House — в трёх минутах хода на лодке — 10 номеров + 1 сюит. До центра деревни Bozburun несколько минут на лодке.' FROM locations WHERE slug = 'karia-bel-iskelesi-bozburun'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Beach-restaurant jetty in Limanağzı bay, Kaş; there is no road from land, it can be reached only by sea. The jetty is FREE FOR ALL BOATS; electricity, water, showers, WC and changing cabins are also free; Wi-Fi is available. It serves Mediterranean and Turkish cuisine; there are bungalow accommodation and a beach bar; caretta turtles can be seen in the bay.' FROM locations WHERE slug = 'nuris-beach-iskelesi-kas'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Embarcadero de playa-restaurante en la cala de Limanağzı, en Kaş; no hay camino por tierra, solo se llega por mar. El embarcadero es GRATUITO PARA TODAS LAS EMBARCACIONES; la electricidad, el agua, las duchas, los WC y los vestuarios también son gratuitos; hay Wi-Fi. Ofrece cocina mediterránea y turca; hay alojamiento en bungalós y bar de playa; en la cala pueden verse tortugas caretta.' FROM locations WHERE slug = 'nuris-beach-iskelesi-kas'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Пляжно-ресторанный причал в бухте Limanağzı у Kaş; дороги с суши нет, добраться можно только морем. Причал БЕСПЛАТЕН ДЛЯ ВСЕХ СУДОВ; электричество, вода, душ, туалеты и кабинки для переодевания тоже бесплатны; есть Wi-Fi. Предлагает средиземноморскую и турецкую кухню; есть размещение в бунгало и пляжный бар; в бухте можно увидеть черепах каретта.' FROM locations WHERE slug = 'nuris-beach-iskelesi-kas'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Private marina on the Adaköy peninsula, Marmaris; 200 berths — stern-to or alongside for boats up to 150 m. VHF 73. Electrical infrastructure of 400 amperes, drinking water, a travel lift with 75-ton capacity and a 15.000 m² concrete hardstanding area; 24/7 security and CCTV. There are a yacht club, restaurant-bar, pool, gym and tennis courts.' FROM locations WHERE slug = 'adakoy-marina-marmaris'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto deportivo privado en la península de Adaköy, en Marmaris; 200 amarres, de popa o abarloado, para barcos de hasta 150 m. VHF 73. Infraestructura eléctrica de 400 amperios, agua potable, travel lift con capacidad de 75 toneladas y explanada de hormigón de 15.000 m²; seguridad 24/7 y CCTV. Hay club náutico, restaurante-bar, piscina, gimnasio y pistas de tenis.' FROM locations WHERE slug = 'adakoy-marina-marmaris'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Частная марина на полуострове Adaköy в Marmaris; 200 швартовных мест — кормой или лагом для судов длиной до 150 м. VHF 73. Электроснабжение на 400 ампер, питьевая вода, травел-лифт грузоподъёмностью 75 тонн и бетонная береговая площадка 15.000 м²; охрана 24/7 и видеонаблюдение. Есть яхт-клуб, ресторан-бар, бассейн, спортзал и теннисные корты.' FROM locations WHERE slug = 'adakoy-marina-marmaris'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The harbour of ancient Kelenderis, 75 km west of Silifke; 110 boats, 3,8-4 m of water at the quay; sand-and-mud bottom. Call ''Aydıncık Harbour'' on VHF 73. Drinking water, electricity, fuel, a boatyard, WC-showers and shops are available. The lighthouse is visible for 9,5 miles. It is the main refuge midway along the Alanya-Taşucu stretch.' FROM locations WHERE slug = 'aydincik-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto de la antigua Kelenderis, 75 km al oeste de Silifke; 110 embarcaciones, 3,8-4 m de agua en el muelle; fondo de arena y fango. Se llama a ''Aydıncık Harbour'' por VHF 73. Dispone de agua potable, electricidad, combustible, varadero, WC y duchas, y tiendas. El faro es visible a 9,5 millas. Es el refugio principal a mitad del tramo Alanya-Taşucu.' FROM locations WHERE slug = 'aydincik-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань античного Kelenderis в 75 км к западу от Silifke; 110 судов, у причала 3,8-4 м воды; дно — песок и ил. Вызов ''Aydıncık Harbour'' на VHF 73. Есть питьевая вода, электричество, топливо, место для подъёма судов, туалеты с душем и магазины. Дальность видимости маяка 9,5 мили. Это главное укрытие посередине линии Alanya-Taşucu.' FROM locations WHERE slug = 'aydincik-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Town pier east of Anamur Burnu, Turkey''s southernmost point. Call ''Anamur İskele'' on VHF 16. The town has a repair workshop, technical supply shops, hotels and guesthouses, restaurants, a pharmacy and a bank; the ancient city of Anemurion and Mamure Kalesi are nearby. CAUTION: the area is a caretta caretta nesting ground — night restrictions may apply on the beaches.' FROM locations WHERE slug = 'anamur-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Embarcadero del pueblo al este de Anamur Burnu, el punto más meridional de Turquía. Se llama a ''Anamur İskele'' por VHF 16. En el pueblo hay taller de reparaciones, tiendas de material técnico, hoteles y pensiones, restaurantes, farmacia y banco; cerca están la antigua ciudad de Anemurion y el castillo Mamure Kalesi. ATENCIÓN: la zona es área de anidación de la tortuga caretta caretta; en las playas puede haber restricciones nocturnas.' FROM locations WHERE slug = 'anamur-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Городской причал к востоку от мыса Anamur Burnu — самой южной точки Турции. Вызов ''Anamur İskele'' на VHF 16. В городке есть ремонтная мастерская, магазины технических товаров, отели и пансионы, рестораны, аптека и банк; рядом античный город Anemurion и крепость Mamure Kalesi. ВНИМАНИЕ: район является местом гнездования черепах caretta caretta — на пляжах возможны ночные ограничения.' FROM locations WHERE slug = 'anamur-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Municipal fishing harbour below the Alanya castle; 550 m outer + 240 m inner breakwater, 125 boats. Water, electricity and a diesel-petrol pump on the quay; depth ~3 m. Call ''Alanya Harbour'' on VHF 16. The Alanya lighthouse, with a focal plane of 209 m, is visible from 20 miles. Alanya Marina is 2,5 miles to the west (separate entry).' FROM locations WHERE slug = 'alanya-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto pesquero municipal bajo el castillo de Alanya; rompeolas exterior de 550 m + interior de 240 m, 125 embarcaciones. En el muelle hay agua, electricidad y surtidor de gasóleo y gasolina; profundidad ~3 m. Se llama a ''Alanya Harbour'' por VHF 16. El faro de Alanya, con plano focal a 209 m, es visible desde 20 millas. Alanya Marina está a 2,5 millas al oeste (registro aparte).' FROM locations WHERE slug = 'alanya-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Муниципальный рыбацкий порт под крепостью Alanya; внешний мол 550 м + внутренний 240 м, 125 судов. На причале вода, электричество и колонка с дизтопливом и бензином; глубина ~3 м. Вызов ''Alanya Harbour'' на VHF 16. Маяк Alanya с фокальной плоскостью 209 м виден с 20 миль. Alanya Marina находится в 2,5 мили к западу (отдельная запись).' FROM locations WHERE slug = 'alanya-balikci-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Open anchorage off the medieval castle of Mamure, which stands right at the water''s edge east of Anamur. The Anamur pier is ~2 miles to the west. The area is a caretta caretta nesting ground — night restrictions may apply to the use of the shore.' FROM locations WHERE slug = 'mamure-kalesi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Fondeadero abierto frente al castillo medieval de Mamure, situado a pie de mar al este de Anamur. El embarcadero de Anamur está a ~2 millas al oeste. La zona es área de anidación de la tortuga caretta caretta; puede haber restricciones nocturnas para el uso de la costa.' FROM locations WHERE slug = 'mamure-kalesi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Открытая якорная стоянка перед средневековой крепостью Mamure, стоящей у самой воды к востоку от Anamur. Причал Anamur находится в ~2 милях к западу. Район — место гнездования черепах caretta caretta; возможны ночные ограничения на использование берега.' FROM locations WHERE slug = 'mamure-kalesi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A wide, shallow bay at the inner end of the Gulf of Hisarönü, off the village that gives the gulf its name; the tile-coloured sandy sea stays waist-deep for a long way out. Ashore there are a jetty, supermarket, cafeteria, restaurant, WC-showers and a village market; right next door is the Çubucak forest campsite with 5.000 tent pitches. The area is windy — a favourite of windsurfers; allow for the meltemi when anchoring. Neighbouring stops: İnbükü, Kartal bay, Tavşan island, Bencik.' FROM locations WHERE slug = 'hisaronu-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala amplia y poco profunda en el fondo del golfo de Hisarönü, frente al pueblo que da nombre al golfo; el mar de arena color teja sigue a la altura de la cintura durante un largo trecho. En la costa hay embarcadero, supermercado, cafetería, restaurante, WC y duchas, y mercado del pueblo; justo al lado está el camping forestal de Çubucak, de 5.000 tiendas de campaña. La zona es ventosa, la preferida de los windsurfistas; tenga en cuenta el meltemi al fondear. Escalas vecinas: İnbükü, la cala Kartal, la isla Tavşan y Bencik.' FROM locations WHERE slug = 'hisaronu-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Широкая мелководная бухта во внутреннем конце залива Hisarönü, перед деревней, давшей заливу имя; море с песком кирпичного цвета долго остаётся по пояс. На берегу причал, супермаркет, кафетерий, ресторан, туалеты с душем и деревенский рынок; сразу рядом — лесной кемпинг Çubucak на 5.000 палаток. Район ветреный — любимое место сёрферов; при постановке на якорь учитывайте мельтеми. Соседние стоянки: İnbükü, бухта Kartal, остров Tavşan, Bencik.' FROM locations WHERE slug = 'hisaronu-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A bay between Fethiye and Göcek that takes its name from the sweetgum (günlük) forest lining its shore. Anchor in ~10 m; beyond the fine-shingle-and-sand beach the sea deepens quickly. Ashore there are a fresh-water well and water filling for boats; a camping area, showers-WC and The Bay Beach Club (46 bungalows, pool, spa). At weekends it gets busy with local visitors.' FROM locations WHERE slug = 'gunluklu-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala entre Fethiye y Göcek que toma su nombre del bosque de liquidámbar (günlük) que bordea su orilla. Se fondea en ~10 m; tras la playa de grava fina y arena, el mar gana profundidad rápidamente. En la costa hay un pozo de agua dulce y llenado de agua para embarcaciones; zona de acampada, duchas y WC, y The Bay Beach Club (46 bungalós, piscina, spa). Los fines de semana se llena de visitantes locales.' FROM locations WHERE slug = 'gunluklu-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта между Fethiye и Göcek, получившая имя от рощи ликвидамбара (günlük), окаймляющей её берег. Встают на якорь на ~10 м; после пляжа из мелкой гальки и песка море быстро углубляется. На берегу колодец с пресной водой и заправка судов водой; кемпинг, душ и туалеты, а также The Bay Beach Club (46 бунгало, бассейн, спа). По выходным бухта заполняется местными отдыхающими.' FROM locations WHERE slug = 'gunluklu-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Fish restaurant in Mazı bay on the northern shore of Gökova, serving since 1959; before tourism it was the village''s fishing jetty. It offers a country breakfast, fish of the day and local olive-oil dishes. A well-known meal stop on Gökova cruises.' FROM locations WHERE slug = 'kayabasi-restaurant-mazi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Restaurante de pescado en la cala de Mazı, en la costa norte de Gökova, que atiende desde 1959; antes del turismo era el embarcadero pesquero del pueblo. Ofrece desayuno rural, pescado del día y platos locales con aceite de oliva. Es una conocida parada gastronómica de las rutas por Gökova.' FROM locations WHERE slug = 'kayabasi-restaurant-mazi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Рыбный ресторан в бухте Mazı на северном берегу Gökova, работающий с 1959 года; до эпохи туризма здесь был рыбацкий причал деревни. Предлагает деревенский завтрак, рыбу дня и местные блюда на оливковом масле. Известная гастрономическая остановка на маршрутах по Gökova.' FROM locations WHERE slug = 'kayabasi-restaurant-mazi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Hotel-restaurant jetty on the Turgutköy shore in the Gulf of Hisarönü; boat guests mooring at the jetty use the hotel facilities. The 14-room establishment has a restaurant (Turkish-Mediterranean cuisine, fish), a pool and a beach. To Marmaris it is 50 miles by sea and 25 km by land; 15 miles to Symi and 20 to Datça.' FROM locations WHERE slug = 'cennet-marine-yacht-club'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Embarcadero de hotel-restaurante en la costa de Turgutköy, en el golfo de Hisarönü; los huéspedes de las embarcaciones amarradas al embarcadero usan las instalaciones del hotel. El establecimiento, de 14 habitaciones, cuenta con restaurante (cocina turco-mediterránea, pescado), piscina y playa. A Marmaris hay 50 millas por mar y 25 km por tierra; a Symi, 15 millas, y a Datça, 20.' FROM locations WHERE slug = 'cennet-marine-yacht-club'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Причал отеля-ресторана на берегу Turgutköy в заливе Hisarönü; гости с яхт, ошвартованных у причала, пользуются услугами отеля. В комплексе на 14 номеров есть ресторан (турецко-средиземноморская кухня, рыба), бассейн и пляж. До Marmaris — 50 миль морем и 25 км по суше; до Symi 15 миль, до Datça 20.' FROM locations WHERE slug = 'cennet-marine-yacht-club'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Restaurant-lounge with a jetty in Kuzbükü bay, Hisarönü. Called on VHF 77. It is the shore facility of the secluded Kuzbükü anchorage (separate entry); there is a 2,5 km road connection to Bozburun.' FROM locations WHERE slug = 'kuzbuku-yacht-club'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Restaurante-lounge con embarcadero en la cala de Kuzbükü, en Hisarönü. Se llama por VHF 77. Es la instalación costera del solitario fondeadero de Kuzbükü (registro aparte); hay una conexión por carretera de 2,5 km con Bozburun.' FROM locations WHERE slug = 'kuzbuku-yacht-club'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Ресторан-лаунж с причалом в бухте Kuzbükü, Hisarönü. Вызов на VHF 77. Это береговое заведение уединённой якорной стоянки Kuzbükü (отдельная запись); есть дорога длиной 2,5 км до Bozburun.' FROM locations WHERE slug = 'kuzbuku-yacht-club'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A sheltered bay in the southeast of Gökova, near Sedir Adası. IMPORTANT — PROTECTED AREA: the bay is a breeding ground of the Mediterranean''s rare sandbar shark (Carcharhinus plumbeus); it has been closed to fishing since 2010 and is CLOSED to visits during the breeding season, in the months of APRIL, MAY and JUNE. The sharks are harmless to humans and timid. Outside the season a fee may be charged on entry (privately operated shore).' FROM locations WHERE slug = 'boncuk-koyu-camli'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala resguardada en el sureste de Gökova, cerca de Sedir Adası. IMPORTANTE — ZONA PROTEGIDA: la cala es zona de cría del raro tiburón trozo (Carcharhinus plumbeus) del Mediterráneo; está cerrada a la pesca desde 2010 y se CIERRA a las visitas durante la época de cría, en los meses de ABRIL, MAYO y JUNIO. Los tiburones son inofensivos para el ser humano y asustadizos. Fuera de temporada puede cobrarse una entrada (orilla de gestión privada).' FROM locations WHERE slug = 'boncuk-koyu-camli'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Защищённая бухта на юго-востоке Gökova, близ Sedir Adası. ВАЖНО — ОХРАНЯЕМАЯ ЗОНА: бухта является местом размножения редкой в Средиземном море песчаной акулы (Carcharhinus plumbeus); с 2010 года здесь запрещена рыбалка, а на период размножения — в АПРЕЛЕ, МАЕ и ИЮНЕ — бухта ЗАКРЫВАЕТСЯ для посещения. Акулы безобидны для человека и пугливы. Вне сезона на входе может взиматься плата (берег в частном управлении).' FROM locations WHERE slug = 'boncuk-koyu-camli'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'An islet off Selimiye, famous for the ruins of a 1.800-year-old Orthodox church and monastery; 20 min from Bozburun. In good weather its southern side is suitable for a LUNCH-STOP anchorage and snorkelling; it is not suitable for the night — Dirsek bay is recommended. Crowding (per sources): in season ~1.000 visitors come per day; the wish tree and the mosaics draw the crowds.' FROM locations WHERE slug = 'kameriye-adasi-selimiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Islote frente a Selimiye, famoso por las ruinas de una iglesia ortodoxa y un monasterio de 1.800 años; a 20 min de Bozburun. Con buen tiempo, su lado sur es apto para un fondeo de PARADA DE MEDIODÍA y para el esnórquel; no es adecuado para pasar la noche: se recomienda la cala de Dirsek. Aglomeración (según fuentes): en temporada llegan ~1.000 visitantes al día; el árbol de los deseos y los mosaicos atraen a las multitudes.' FROM locations WHERE slug = 'kameriye-adasi-selimiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Островок близ Selimiye, знаменитый руинами православной церкви и монастыря возрастом 1.800 лет; 20 мин от Bozburun. В хорошую погоду южная сторона подходит для якорной ОБЕДЕННОЙ СТОЯНКИ и снорклинга; для ночёвки не годится — рекомендуется бухта Dirsek. Загруженность (по источникам): в сезон приходит ~1.000 посетителей в день; дерево желаний и мозаики привлекают толпы.' FROM locations WHERE slug = 'kameriye-adasi-selimiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Bay east of Gazipaşa, west of the Kaledran stream; there are natural beaches in front of the village, which is surrounded by banana plantations. It is an intermediate stopover point on the Alanya-Anamur run.' FROM locations WHERE slug = 'yakacik-koyu-gazipasa'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala al este de Gazipaşa, al oeste del arroyo Kaledran; frente al pueblo, rodeado de plantaciones de plátano, hay playas naturales. Es un punto de escala intermedia en la ruta Alanya-Anamur.' FROM locations WHERE slug = 'yakacik-koyu-gazipasa'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта к востоку от Gazipaşa, к западу от реки Kaledran; перед деревней, окружённой банановыми плантациями, есть природные пляжи. Промежуточная стоянка на маршруте Alanya-Anamur.' FROM locations WHERE slug = 'yakacik-koyu-gazipasa'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Small bay just west of Aydıncık, where the Soğuksu stream flows into the sea. The Aydıncık fishing harbour (separate entry) is ~2 miles to the east.' FROM locations WHERE slug = 'soguksu-koyu-aydincik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Pequeña cala justo al oeste de Aydıncık, donde el arroyo Soğuksu desemboca en el mar. El puerto pesquero de Aydıncık (registro aparte) está a ~2 millas al este.' FROM locations WHERE slug = 'soguksu-koyu-aydincik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Небольшая бухта сразу к западу от Aydıncık, там, где река Soğuksu впадает в море. Рыбацкая гавань Aydıncık (отдельная запись) находится в ~2 милях к востоку.' FROM locations WHERE slug = 'soguksu-koyu-aydincik'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Bay on the Gülnar coast, on the eastern side of the stream mouth; the D-400 coastal road passes just behind it. It is an intermediate stopover point between Aydıncık and Taşucu.' FROM locations WHERE slug = 'sipahili-koyu-gulnar'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala en la costa de Gülnar, en la orilla oriental de la desembocadura del arroyo; la carretera costera D-400 pasa justo por detrás. Es un punto de escala intermedia entre Aydıncık y Taşucu.' FROM locations WHERE slug = 'sipahili-koyu-gulnar'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта на побережье Gülnar, на восточном берегу устья реки; прибрежная дорога D-400 проходит сразу за ней. Промежуточная стоянка между Aydıncık и Taşucu.' FROM locations WHERE slug = 'sipahili-koyu-gulnar'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The bay of the village of Büyükeceli in Gülnar; it is connected to the coast by a 3 km valley. To its east, the Bölükada lighthouse (two white flashes/5 s, 18 miles) serves as a navigational reference.' FROM locations WHERE slug = 'buyukeceli-koyu-gulnar'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La cala del pueblo de Büyükeceli, en Gülnar; se conecta con la costa por un valle de 3 km. Al este, el faro de Bölükada (dos destellos blancos/5 s, 18 millas) sirve de referencia para la navegación.' FROM locations WHERE slug = 'buyukeceli-koyu-gulnar'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта деревни Büyükeceli в Gülnar; с побережьем её связывает долина длиной 3 км. К востоку навигационным ориентиром служит маяк Bölükada (два белых проблеска/5 с, 18 миль).' FROM locations WHERE slug = 'buyukeceli-koyu-gulnar'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Restaurant-bar jetty in Hayıtbükü, Datça; FROM THE WAITING LIST: Hayıtbükü is recorded for the first time. 30 stern anchor moorings, maximum length 10 m. Call ''Ogun''s Place'' on VHF 16. There are drinking water, electricity, Wi-Fi and a laundry service; wintering (boat storage) is offered; studio/duplex accommodation is available. ~1,3 km walk to Ovabükü beach; a village market is held on Sundays.' FROM locations WHERE slug = 'oguns-place-hayitbuku'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Muelle de restaurante-bar en Hayıtbükü, Datça; DE LA LISTA DE ESPERA: Hayıtbükü figura por primera vez en el registro. 30 muertos para amarre de popa, eslora máxima 10 m. Se llama a ''Ogun''s Place'' por el VHF 16. Hay agua potable, electricidad, Wi-Fi y servicio de lavandería; se ofrece invernaje (custodia de embarcaciones); hay alojamiento en estudios/dúplex. Paseo de ~1,3 km hasta la playa de Ovabükü; los domingos se monta el mercado del pueblo.' FROM locations WHERE slug = 'oguns-place-hayitbuku'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Причал ресторана-бара в Hayıtbükü (Datça); ИЗ ЛИСТА ОЖИДАНИЯ: Hayıtbükü впервые в реестре. 30 стационарных швартовов для кормовой стоянки, максимальная длина 10 м. Вызывайте ''Ogun''s Place'' по VHF 16. Есть питьевая вода, электричество, Wi-Fi и прачечная; предлагается зимовка (отстой судов); есть размещение в студиях/дуплексах. Пешком ~1,3 км до пляжа Ovabükü; по воскресеньям работает деревенский рынок.' FROM locations WHERE slug = 'oguns-place-hayitbuku'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The historic lighthouse (1871) of Kızılada at the entrance to the Gulf of Fethiye has been converted into a restaurant and boutique hotel; a 100-seat restaurant + 9 rooms. You can come alongside the jetty or anchor off the island in 5-7 m on a SAND bottom. Famous for its sunset dinner, it is one of the special stops for boats.' FROM locations WHERE slug = 'kizilada-fener-restorani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El faro histórico (1871) de Kızılada, a la entrada del golfo de Fethiye, se ha convertido en un hotel boutique con restaurante; restaurante para 100 comensales + 9 habitaciones. Se puede atracar al muelle o fondear frente a la isla en 5-7 m sobre fondo de ARENA. Famoso por su cena al atardecer, es una de las paradas especiales de las embarcaciones.' FROM locations WHERE slug = 'kizilada-fener-restorani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Исторический маяк (1871) острова Kızılada у входа в залив Fethiye превращён в ресторан и бутик-отель; ресторан на 100 мест + 9 номеров. Можно ошвартоваться у причала или встать на якорь перед островом на глубине 5-7 м, грунт ПЕСОК. Знаменит ужином на закате; одна из особых стоянок для яхт.' FROM locations WHERE slug = 'kizilada-fener-restorani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Restaurant jetty in Selimiye bay; boat supplies are also sold. It is on Selimiye''s famous line of fish restaurants (sea bass, grouper, calamari, slipper lobster).' FROM locations WHERE slug = 'osmans-place-selimiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Muelle de restaurante en la cala de Selimiye; también se venden artículos náuticos. Está en la línea de famosos restaurantes de pescado de Selimiye (lubina, mero, calamar, cigarra de mar).' FROM locations WHERE slug = 'osmans-place-selimiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Ресторанный причал в бухте Selimiye; продаются также товары для яхт. Находится в ряду знаменитых рыбных ресторанов Selimiye (сибас, групер, кальмары, лангуст).' FROM locations WHERE slug = 'osmans-place-selimiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Beach restaurant jetty in Delikyol bay, Hisarönü; a 150-seat restaurant. Electricity and drinking water can be connected at the jetty; provisions can be taken on.' FROM locations WHERE slug = 'deniz-restaurant-delikyol'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Muelle del restaurante de playa en la cala Delikyol, en Hisarönü; restaurante para 150 comensales. En el muelle se pueden conectar electricidad y agua potable; se puede hacer avituallamiento.' FROM locations WHERE slug = 'deniz-restaurant-delikyol'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Причал пляжного ресторана в бухте Delikyol (Hisarönü); ресторан на 150 мест. На причале подключаются электричество и питьевая вода; можно пополнить запасы провизии.' FROM locations WHERE slug = 'deniz-restaurant-delikyol'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Small marina of the Letoonia holiday village at Paçariz Burnu in the Gulf of Fethiye; capacity 30 yachts. Water and electricity are connected; a restaurant-bar is on the premises. You can anchor in 10-15 m west of the facility. Fuel is supplied by tanker truck from Fethiye centre. Paçariz light: green flash/3 s, 4 miles.' FROM locations WHERE slug = 'letoonia-marinet-fethiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Pequeño puerto deportivo del complejo vacacional Letoonia en Paçariz Burnu, en el golfo de Fethiye; capacidad para 30 yates. Se conectan agua y electricidad; hay restaurante-bar dentro del complejo. Se puede fondear en 10-15 m al oeste de las instalaciones. El combustible se suministra en camión cisterna desde el centro de Fethiye. Faro de Paçariz: destello verde/3 s, 4 millas.' FROM locations WHERE slug = 'letoonia-marinet-fethiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Небольшая марина курортного посёлка Letoonia на мысе Paçariz Burnu в заливе Fethiye; вместимость 30 яхт. Подключаются вода и электричество; ресторан-бар на территории. К западу от комплекса можно встать на якорь на глубине 10-15 м. Топливо доставляется автоцистерной из центра Fethiye. Маяк Paçariz: зелёный проблеск/3 с, 4 мили.' FROM locations WHERE slug = 'letoonia-marinet-fethiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'At the mouth of the Gulf of Fethiye, the island of the 12 Adalar chain closest to the town; there are no vehicles and it is covered in pine forest. In the clear water, the underwater ruins (an ancient wall, a church, a Roman cistern) can be toured by canoe in ~1 hour. CAUTION: the EASTERN channel of the island is VERY SHALLOW for large boats. Sea taxi from Fethiye ~20 min.' FROM locations WHERE slug = 'sovalye-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'En la boca del golfo de Fethiye, la isla de la cadena 12 Adalar más cercana a la ciudad; no hay vehículos y está cubierta de pinar. En aguas cristalinas, los restos sumergidos (una muralla antigua, una iglesia, una cisterna romana) se recorren en canoa en ~1 hora. ATENCIÓN: el canal ESTE de la isla es MUY POCO PROFUNDO para embarcaciones grandes. Taxi acuático desde Fethiye: ~20 min.' FROM locations WHERE slug = 'sovalye-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'В устье залива Fethiye — ближайший к городу остров цепи 12 Adalar; машин нет, остров покрыт сосновым лесом. В прозрачной воде подводные руины (античная стена, церковь, римская цистерна) можно осмотреть с каноэ примерно за 1 час. ВНИМАНИЕ: ВОСТОЧНЫЙ пролив у острова ОЧЕНЬ МЕЛКИЙ для больших судов. Морское такси из Fethiye ~20 мин.' FROM locations WHERE slug = 'sovalye-adasi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Bay indenting northwards near Gemiler Adası; also called ''Soğuk Su Koyu'' — spring waters rising from the bottom noticeably cool the seawater (a surprise when swimming!). The water is deep; shelter is taken in the WESTERN and EASTERN creeks of the main bay. ~1 hour walk to Kayaköy (Byzantine churches and an abandoned village).' FROM locations WHERE slug = 'bestas-kalevezi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala que se adentra hacia el norte cerca de Gemiler Adası; también llamada ''Soğuk Su Koyu'': las aguas de manantial que brotan del fondo enfrían notablemente el agua del mar (¡sorprende al nadar!). El agua es profunda; se busca abrigo en las caletas OESTE y ESTE de la cala principal. Caminata de ~1 hora hasta Kayaköy (iglesias bizantinas y un pueblo abandonado).' FROM locations WHERE slug = 'bestas-kalevezi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта, вдающаяся к северу возле Gemiler Adası; её называют также ''Soğuk Su Koyu'' — родниковые воды, бьющие со дна, заметно охлаждают морскую воду (удивляет при купании!). Вода глубокая; укрываться следует в ЗАПАДНОМ и ВОСТОЧНОМ рукавах главной бухты. Прогулка ~1 час до Kayaköy (византийские церкви и заброшенная деревня).' FROM locations WHERE slug = 'bestas-kalevezi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Bay in the west of the Gulf of Fethiye, on the eastern side of the Bozdoğan (Kapıdağ) peninsula. The WESTERN end is the suitable anchorage: anchor in 10-15 m and take lines ashore to the SOUTHWEST. The prevailing winds send swell into the bay — prefer it in settled weather. The southern shore is forested and the water is turquoise.' FROM locations WHERE slug = 'darbogaz-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala en el oeste del golfo de Fethiye, al este de la península de Bozdoğan (Kapıdağ). El extremo OESTE es el fondeadero adecuado: fondee en 10-15 m y lleve cabos a tierra hacia el SUROESTE. Los vientos dominantes meten mar de fondo en la cala; prefiérala con tiempo asentado. La orilla sur está arbolada y el agua es turquesa.' FROM locations WHERE slug = 'darbogaz-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта в западной части залива Fethiye, к востоку от полуострова Bozdoğan (Kapıdağ). ЗАПАДНАЯ оконечность — подходящая якорная стоянка: встаньте на якорь на 10-15 м и заведите концы на берег к ЮГО-ЗАПАДУ. Господствующие ветры нагоняют в бухту зыбь — предпочитайте её при установившейся погоде. Южный берег лесистый, вода бирюзовая.' FROM locations WHERE slug = 'darbogaz-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Naturally sheltered small bay in the Gulf of Fethiye; it is rarely affected by rough, windy weather. On the shore there is a beach restaurant with palm trees; the beach operator may charge an entrance fee. Small ancient ruins and calm water — a haunt of locals at weekends, but quieter than the neighbouring beaches.' FROM locations WHERE slug = 'buyuk-boncuklu-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Pequeña cala de abrigo natural en el golfo de Fethiye; rara vez se ve afectada por el tiempo duro y ventoso. En la orilla hay un restaurante de playa con palmeras; la concesión de la playa puede cobrar entrada. Pequeños restos antiguos y aguas tranquilas: los fines de semana la frecuentan los lugareños, pero es más solitaria que las playas vecinas.' FROM locations WHERE slug = 'buyuk-boncuklu-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Небольшая естественно защищённая бухта в заливе Fethiye; редко страдает от свежей ветреной погоды. На берегу пляжный ресторан с пальмами; администрация пляжа может взимать плату за вход. Небольшие античные руины и спокойная вода — по выходным сюда приезжают местные жители, но здесь тише, чем на соседних пляжах.' FROM locations WHERE slug = 'buyuk-boncuklu-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Sister bay just north of Büyük Boncuklu; a continuation of the same sheltered stretch. It is smaller and more secluded.' FROM locations WHERE slug = 'kucuk-boncuklu-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala hermana justo al norte de Büyük Boncuklu; es la continuación de la misma línea abrigada. Es más pequeña y solitaria.' FROM locations WHERE slug = 'kucuk-boncuklu-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта-сестра сразу к северу от Büyük Boncuklu; продолжение той же защищённой линии берега. Она меньше и безлюднее.' FROM locations WHERE slug = 'kucuk-boncuklu-koyu'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Anchor in 5-10 m in the coastal openings below the Batıkkaya light, ~1 mile north of the town of Fethiye. It gives good shelter from the prevailing W/NW winds; it is OPEN TO THE EAST. A practical stop thanks to its closeness to the town (repair shops, restaurants, Monday/Wednesday market); the Amyntas rock tomb is within walking distance.' FROM locations WHERE slug = 'batikkaya-buku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Se fondea en 5-10 m en las ensenadas de la costa bajo el faro de Batıkkaya, a ~1 milla al norte de la ciudad de Fethiye. Ofrece buen abrigo de los vientos dominantes del W/NW; está ABIERTA AL ESTE. Es una parada práctica por su cercanía a la ciudad (talleres, restaurantes, mercado los lunes/miércoles); la tumba rupestre de Amyntas está a poca distancia a pie.' FROM locations WHERE slug = 'batikkaya-buku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Якорная стоянка на 5-10 м в прибрежных карманах под маяком Batıkkaya, в ~1 миле к северу от города Fethiye. Хорошо укрывает от господствующих W/NW ветров; ОТКРЫТА К ВОСТОКУ. Практичная остановка благодаря близости к городу (мастерские, рестораны, рынок по понедельникам/средам); скальная гробница Amyntas в пешей доступности.' FROM locations WHERE slug = 'batikkaya-buku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Yacht club in Kumlubükü bay — it was missing from the official marina list. 35 boats on the T-jetty (3,5-4,5 m depth) + 18 stern anchor moorings in 15 m depth. Electricity, water, professional mooring assistance, FREE Wi-Fi and showers; there is a security guard and food service to the boat. Restaurant (Turkish/Chinese/Japanese), terrace bar and sushi bar; a 100 m beach. Open every year from 1 April to mid-November.' FROM locations WHERE slug = 'kumlubuku-yacht-club'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Club náutico en la cala de Kumlubükü; faltaba en la lista oficial de puertos deportivos. 35 embarcaciones en el pantalán en T (3,5-4,5 m de profundidad) + 18 muertos de amarre en 15 m de fondo. Electricidad, agua, ayuda profesional al amarre, Wi-Fi GRATUITO y duchas; hay vigilante de seguridad y servicio de comida a bordo. Restaurante (turco/chino/japonés), bar en terraza y bar de sushi; playa de 100 m. Abre cada año del 1 de abril a mediados de noviembre.' FROM locations WHERE slug = 'kumlubuku-yacht-club'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Яхт-клуб в бухте Kumlubükü — отсутствовал в официальном списке марин. 35 судов у Т-образного пирса (глубины 3,5-4,5 м) + 18 стационарных швартовов на глубине 15 м. Электричество, вода, профессиональная помощь при швартовке, БЕСПЛАТНЫЙ Wi-Fi и душ; есть охранник и доставка еды на борт. Ресторан (турецкая/китайская/японская кухня), бар на террасе и суши-бар; пляж 100 м. Открыт ежегодно с 1 апреля до середины ноября.' FROM locations WHERE slug = 'kumlubuku-yacht-club'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Hotel marina in central Fethiye, a 5 min walk from the town — the ''Yacht Otel Club & Marina'' missing from the official list. 30 yachts on a modern T-jetty with a lazy line mooring arrangement. Fuel and provisions can be taken on; there are showers, a pool, a sauna, a hammam, a laundry and internet; Mori Restaurant and BluBar are on the premises. A well-known stop for crew changes; it has been in operation for a quarter of a century.' FROM locations WHERE slug = 'yacht-classic-marina-fethiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto deportivo de hotel en el centro de Fethiye, a 5 min a pie de la ciudad; es el ''Yacht Otel Club & Marina'' que faltaba en la lista oficial. 30 yates en un pantalán en T moderno con sistema de amarre con guía (lazy line). Se puede repostar y avituallarse; hay duchas, piscina, sauna, hamam, lavandería e internet; el Mori Restaurant y el BluBar están dentro del recinto. Es una parada conocida para los cambios de tripulación; lleva un cuarto de siglo en funcionamiento.' FROM locations WHERE slug = 'yacht-classic-marina-fethiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Отельная марина в центре Fethiye, в 5 мин ходьбы от города — тот самый ''Yacht Otel Club & Marina'', которого не хватало в официальном списке. 30 яхт у современного Т-образного пирса со швартовкой на мурингах (lazy line). Есть заправка топливом и пополнение провизии; душ, бассейн, сауна, хаммам, прачечная и интернет; Mori Restaurant и BluBar на территории. Известная остановка для смены экипажа; работает уже четверть века.' FROM locations WHERE slug = 'yacht-classic-marina-fethiye'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Guesthouse-restaurant jetty at the foot of the castle in Kaleköy (ancient Simena), with a view of Kekova. The restaurant is open every day 09:00-23:00 (Turkish/Mediterranean/seafood); 9 air-conditioned rooms + 1 detached house. There is no road from land — it can only be reached by sea.' FROM locations WHERE slug = 'kale-pansiyon-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Muelle de la pensión-restaurante al pie del castillo en Kaleköy (la antigua Simena), con vistas a Kekova. El restaurante abre todos los días de 09:00-23:00 (cocina turca/mediterránea/marisco); 9 habitaciones climatizadas + 1 casa independiente. No hay carretera por tierra: solo se llega por mar.' FROM locations WHERE slug = 'kale-pansiyon-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Причал пансиона-ресторана у подножия крепости в Kaleköy (античная Simena), с видом на Kekova. Ресторан открыт ежедневно 09:00-23:00 (турецкая/средиземноморская кухня/морепродукты); 9 номеров с кондиционером + 1 отдельный дом. Дороги по суше нет — добраться можно только морем.' FROM locations WHERE slug = 'kale-pansiyon-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Famous canyon bay south of Ölüdeniz, between sheer cliffs of 350-400 m; a wide sandy beach at the entrance. It has been a NATURE PROTECTION AREA since 1995 — permanent construction is forbidden; on the beach there are a summer restaurant-bar and tent/bungalow accommodation (~250 people); electricity comes from a generator during limited hours. From Ölüdeniz Belceğiz a boat service runs hourly during the day. Mobile phone coverage is limited.' FROM locations WHERE slug = 'kelebekler-vadisi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Famosa cala-cañón al sur de Ölüdeniz, entre acantilados verticales de 350-400 m; amplia playa de arena en la entrada. Desde 1995 es ÁREA DE PROTECCIÓN NATURAL: las construcciones permanentes están prohibidas; en la playa hay un restaurante-bar de verano y alojamiento en tiendas/bungalós (~250 personas); la electricidad, de generador, se limita a ciertas horas. Desde Ölüdeniz Belceğiz funciona un servicio de barco cada hora durante el día. La cobertura de teléfono móvil es limitada.' FROM locations WHERE slug = 'kelebekler-vadisi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Знаменитая каньонная бухта к югу от Ölüdeniz, между отвесными скалами высотой 350-400 м; у входа широкий песчаный пляж. С 1995 года это ПРИРОДООХРАННАЯ ЗОНА — капитальное строительство запрещено; на пляже есть летний ресторан-бар и размещение в палатках/бунгало (~250 человек); электричество от генератора и лишь в ограниченные часы. Из Ölüdeniz Belceğiz днём каждый час ходит катер. Сотовая связь ограничена.' FROM locations WHERE slug = 'kelebekler-vadisi-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The large island opposite Bodrum. The main anchorage is POYRAZ LİMANI: anchor in 7-8 m and take lines ashore — it is sheltered from the meltemi, but a strong northerly raises a chop. Other spots: off the village of Adalı (5-6 m, SAND bottom), Kaçakçı cove (narrow, limited room) and the thermal spring cave on the NW of the island (7-8 m, with a jetty, paid entrance — hot mineral water inside the cave). There are a restaurant and a small motel; around the island there are 8 dive sites, an artificial reef and wrecks (17-36 m).' FROM locations WHERE slug = 'kara-ada-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La gran isla frente a Bodrum. El fondeadero principal es POYRAZ LİMANI: fondee en 7-8 m y lleve cabos a tierra; queda abrigado del meltemi, pero con norte fuerte se levanta marejada. Otros puntos: frente al pueblo de Adalı (5-6 m, fondo de ARENA), la cala Kaçakçı (estrecha, con sitio limitado) y la cueva termal del NW de la isla (7-8 m, con muelle, entrada de pago; agua mineral caliente dentro de la cueva). Hay un restaurante y un pequeño motel; en los alrededores hay 8 puntos de buceo, un arrecife artificial y pecios (17-36 m).' FROM locations WHERE slug = 'kara-ada-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Большой остров напротив Bodrum. Основная якорная стоянка — POYRAZ LİMANI: встаньте на якорь на 7-8 м и заведите концы на берег — она укрыта от мельтеми, но при сильном северном ветре разводит волнение. Другие точки: перед деревней Adalı (5-6 м, грунт ПЕСОК), бухта Kaçakçı (узкая, мест мало) и пещера с термальным источником на СЗ острова (7-8 м, с причалом, вход платный — внутри пещеры горячая минеральная вода). Есть ресторан и небольшой мотель; вокруг острова 8 дайв-сайтов, искусственный риф и затонувшие объекты (17-36 м).' FROM locations WHERE slug = 'kara-ada-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The bay of Çökertme, a classic stop in Gökova. 2-5 m in the western part, 5-10 m in the north, 10-20 m at the entrance. CAUTION: the bottom is sand + weed — HOLDING IS PATCHY, take lines ashore. Sheltered from west-north-east winds; SOUTHERLIES send in waves — in a southerly gale move to the western cove. There are reefs around the central islet. In the bay there are 3 restaurant pontoons (with a line system); the village jetty is a separate entry.' FROM locations WHERE slug = 'cokertme-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La cala de Çökertme, parada clásica de Gökova. 2-5 m en la parte oeste, 5-10 m al norte, 10-20 m en la entrada. ATENCIÓN: el fondo es de arena + algas; el AGARRE ES DÉBIL A TRAMOS, lleve cabos a tierra. Abrigada de los vientos del oeste, norte y este; el viento del SUR mete oleaje: con temporal del sur pase a la cala del oeste. Hay arrecifes alrededor del islote central. En la cala hay 3 pontones de restaurante (con sistema de cabos); el muelle del pueblo es un registro aparte.' FROM locations WHERE slug = 'cokertme-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта Çökertme — классическая стоянка залива Gökova. В западной части 2-5 м, на севере 5-10 м, у входа 10-20 м. ВНИМАНИЕ: грунт песок + водоросли — ДЕРЖАЩАЯ СИЛА МЕСТАМИ СЛАБАЯ, заводите концы на берег. Укрыта от западных, северных и восточных ветров; ЮЖНЫЙ ветер нагоняет волну — при южном шторме переходите в западную бухту. Вокруг центрального островка есть рифы. В бухте 3 ресторанных понтона (со швартовными концами); деревенский причал — отдельная запись.' FROM locations WHERE slug = 'cokertme-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The jetty of the village of Çökertme; berthing for up to ~30 boats. There is sufficient depth at the head of the jetty; water and electricity are connected FOR A FEE. It is at the northern end of the bay — in southerly weather the warnings for the inside of the bay apply (see the bay entry).' FROM locations WHERE slug = 'cokertme-koy-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El muelle del pueblo de Çökertme; atraque para hasta ~30 embarcaciones. Hay calado suficiente en la cabecera del muelle; el agua y la electricidad se conectan DE PAGO. Está en el extremo norte de la cala; con tiempo del sur rigen las advertencias del interior de la cala (véase el registro de la cala).' FROM locations WHERE slug = 'cokertme-koy-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Причал деревни Çökertme; швартовка до ~30 судов. У оконечности причала достаточная глубина; вода и электричество подключаются ПЛАТНО. Находится в северной части бухты — при южной погоде действуют предупреждения по акватории бухты (см. запись о бухте).' FROM locations WHERE slug = 'cokertme-koy-iskelesi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Bay between Fethiye and Ölüdeniz, below the Af Kule monastery (carved into the rock) on the cliff. The water is VERY DEEP; off the bay there is an old coastguard boat sunk for diving, and fragments of ancient amphorae on the bottom. In settled weather it is a stop for a short break/dive.' FROM locations WHERE slug = 'afkule-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala entre Fethiye y Ölüdeniz, bajo el monasterio de Af Kule (excavado en la roca) del acantilado. El agua es MUY PROFUNDA; frente a la cala hay una antigua lancha de guardacostas hundida para el buceo y, en el fondo, fragmentos de ánforas antiguas. Con tiempo asentado es una parada para un descanso corto o una inmersión.' FROM locations WHERE slug = 'afkule-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта между Fethiye и Ölüdeniz, под высеченным в скале монастырём Af Kule на обрыве. Вода ОЧЕНЬ ГЛУБОКАЯ; на подходе к бухте затоплен старый катер береговой охраны для дайвинга, а на дне лежат фрагменты античных амфор. При установившейся погоде — место короткой остановки/погружения.' FROM locations WHERE slug = 'afkule-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'FROM THE WAITING LIST: the town quay of Poros, a Saronic classic. Inside the narrow strait, berth alongside the quay or stern-to on the southern quay; MUD bottom. Well sheltered from all directions; a strong westerly raises a short chop on the northern quay, and a strong southerly brings hard squalls down from the hills of the Peloponnese. CAUTION: in the strait there is normally a CURRENT of ~1 knot from west to east, and it can reverse — it pushes the boat during slow manoeuvres; ferries/hydrofoils pass close by, and at the southern entrance the Peloponnese side is shallow. Water and fuel are available; there is a chandler. At the southern anchorage bar music is heard at night; the north is quieter.' FROM locations WHERE slug = 'poros-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'DE LA LISTA DE ESPERA: el muelle del pueblo de Poros, un clásico del Sarónico. Dentro del estrecho angosto se amarra de costado al muelle o de popa al muelle sur; fondo de FANGO. Bien protegido de todas las direcciones; un oeste fuerte levanta ola corta en el muelle norte y un sur fuerte trae rachas duras desde las colinas del Peloponeso. ATENCIÓN: en el estrecho hay normalmente una CORRIENTE de ~1 nudo de oeste a este que puede invertirse; empuja al barco en las maniobras lentas; los ferris e hidroalas pasan muy cerca y, en la entrada sur, la orilla del Peloponeso es poco profunda. Se toman agua y combustible; hay efectos navales. En el fondeadero sur se oye música de bares por la noche; el norte es más tranquilo.' FROM locations WHERE slug = 'poros-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'ИЗ ЛИСТА ОЖИДАНИЯ: городская набережная Poros — классика Саронического залива. В узком проливе швартуются лагом к набережной или кормой к южной набережной; грунт ИЛ. Хорошо защищена со всех направлений; сильный западный ветер разводит короткую волну у северной набережной, сильный южный приносит резкие шквалы с холмов Пелопоннеса. ВНИМАНИЕ: в проливе обычно есть ТЕЧЕНИЕ ~1 узел с запада на восток, и оно может менять направление — на малом ходу оно сносит судно; паромы и суда на подводных крыльях проходят вплотную, у южного входа со стороны Пелопоннеса мелко. Есть вода и топливо; есть шипчандлер. На южной якорной стоянке ночью слышна музыка баров; север спокойнее.' FROM locations WHERE slug = 'poros-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'FROM THE WAITING LIST: the main harbour of İkarya. Berth at the jetties behind the inner breakwater; there is ~6 m at the end of the northern jetty and SHALLOW water at the roots of the jetties. Adequately sheltered from the meltemi; in a strong NORTHERLY hard squalls come down and a persistent swell on the quay is a nuisance — do not leave the boat unattended for long (source warning). Water and electricity from a private operator (ask the price beforehand); fuel by mini tanker. Evdilos harbour is 5,6 miles to the west.' FROM locations WHERE slug = 'agios-kirykos-limani-ikarya'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'DE LA LISTA DE ESPERA: el puerto principal de İkarya. Se amarra a los muelles detrás del rompeolas interior; hay ~6 m en el extremo del muelle norte y agua POCO PROFUNDA en el arranque de los muelles. Queda suficientemente abrigado del meltemi; con NORTE fuerte bajan rachas duras y una marejada persistente molesta en el muelle: no deje el barco mucho tiempo sin vigilancia (advertencia de la fuente). Agua y electricidad de una empresa privada (pregunte el precio antes); combustible con mini camión cisterna. El puerto de Evdilos está a 5,6 millas al oeste.' FROM locations WHERE slug = 'agios-kirykos-limani-ikarya'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'ИЗ ЛИСТА ОЖИДАНИЯ: главный порт острова İkarya. Швартуются к пирсам за внутренним молом; у оконечности северного пирса ~6 м, у основания пирсов МЕЛКО. Достаточно укрыт от мельтеми; при сильном СЕВЕРНОМ ветре сходят резкие шквалы, а у причала беспокоит постоянная зыбь — не оставляйте судно надолго без присмотра (предупреждение источника). Вода и электричество у частного оператора (уточняйте цену заранее); топливо мини-автоцистерной. Порт Evdilos находится в 5,6 мили к западу.' FROM locations WHERE slug = 'agios-kirykos-limani-ikarya'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'FROM THE WAITING LIST: small fishing harbour on the east coast of Paros; it faces the Naxos strait. The port authority can be reached on VHF 12/11. On the shore there are restaurants, shops and an ATM; there are road connections to Naoussa and Parikia.' FROM locations WHERE slug = 'piso-livadi-limani-paros'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'DE LA LISTA DE ESPERA: pequeño puerto pesquero en la costa este de Paros; mira al estrecho de Naxos. Se contacta con la autoridad portuaria por el VHF 12/11. En la orilla hay restaurantes, tiendas y un cajero automático; tiene conexión por carretera con Naoussa y Parikia.' FROM locations WHERE slug = 'piso-livadi-limani-paros'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'ИЗ ЛИСТА ОЖИДАНИЯ: небольшая рыбацкая гавань на восточном берегу Paros; выходит на пролив Naxos. Портовые власти вызываются по VHF 12/11. На берегу рестораны, магазины и банкомат; есть автодорожное сообщение с Naoussa и Parikia.' FROM locations WHERE slug = 'piso-livadi-limani-paros'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The main harbour of Milos; berth east of the ferry quay or on the small eastern quay — ~40 places for boats over 10 m. The bottom is a mixture of weed, rock and mud. Well sheltered from the meltemi; in meltemi conditions there is a confused sea at the entrance to the bay. CAUTION: in a strong SOUTHERLY anchoring is DANGEROUS; there are rocks and reefs along the eastern shore. VHF 12. Water on the ferry quay (NOT DRINKING WATER); fuel at the edge of town; there are a supermarket, restaurants and a bank.' FROM locations WHERE slug = 'adamas-limani-milos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El puerto principal de Milos; se amarra al este del muelle del ferri o al pequeño muelle oriental: ~40 plazas para embarcaciones de más de 10 m. El fondo es mixto de algas, roca y fango. Bien abrigado del meltemi; con meltemi hay mar confusa en la entrada de la bahía. ATENCIÓN: con SUR fuerte el fondeo es PELIGROSO; hay rocas y arrecifes a lo largo de la costa este. VHF 12. Agua en el muelle del ferri (NO ES AGUA POTABLE); combustible a la salida del pueblo; hay supermercado, restaurantes y banco.' FROM locations WHERE slug = 'adamas-limani-milos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Главный порт Milos; швартуются к востоку от паромного причала или к малому восточному причалу — ~40 мест для судов длиннее 10 м. Грунт смешанный: водоросли, камень, ил. Хорошо укрыт от мельтеми; при мельтеми у входа в залив беспорядочная волна. ВНИМАНИЕ: при сильном ЮЖНОМ ветре якорная стоянка ОПАСНА; вдоль восточного берега камни и рифы. VHF 12. Вода на паромном причале (НЕ ПИТЬЕВАЯ); заправка на выезде из города; есть супермаркет, рестораны, банк.' FROM locations WHERE slug = 'adamas-limani-milos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The only real marina at the southern tip of Santorini; ~200 places. In a storm this is the ONLY harbour on the island where you can berth; the eastern quay gives good protection from SE and westerly winds. VERY IMPORTANT WARNING: at the entrance the water is LESS THAN 1,7 m and it is dangerous — there is a sunken rock near the inner breakwater, so keep close to the OUTER breakwater when entering; deep-draught boats should call the harbour authority before entering. Floating volcanic pumice can accumulate in the northwest corner — when running the engine in the harbour it can block the cooling water intake. Water and electricity on the quay; fuel by mini tanker.' FROM locations WHERE slug = 'vlychada-marina-santorini'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El único puerto deportivo de verdad en el extremo sur de Santorini; ~200 plazas. Con temporal, este es el ÚNICO puerto de la isla donde se puede amarrar; el muelle este protege bien del SE y de los vientos del oeste. ADVERTENCIA MUY IMPORTANTE: en la entrada el agua tiene MENOS DE 1,7 m y es peligrosa; hay una roca sumergida cerca del rompeolas interior, así que al entrar navegue pegado al rompeolas EXTERIOR; las embarcaciones de mucho calado deben llamar a la autoridad portuaria antes de entrar. La piedra volcánica flotante puede acumularse en la esquina noroeste y, al tener el motor en marcha en el puerto, puede obstruir la toma de agua de refrigeración. Agua y electricidad en el muelle; combustible con mini camión cisterna.' FROM locations WHERE slug = 'vlychada-marina-santorini'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Единственная настоящая марина на южной оконечности Santorini; ~200 мест. В шторм это ЕДИНСТВЕННЫЙ порт острова, где можно ошвартоваться; восточный причал хорошо защищает от ЮВ и западных ветров. ОЧЕНЬ ВАЖНОЕ ПРЕДУПРЕЖДЕНИЕ: на входе глубина МЕНЕЕ 1,7 м, и вход опасен — возле внутреннего мола есть подводная скала, при входе держитесь ближе к ВНЕШНЕМУ молу; судам с большой осадкой перед входом следует связаться с администрацией порта. Плавучая вулканическая пемза может скапливаться в северо-западном углу — при работе двигателя в порту она может забить забор охлаждающей воды. Вода и электричество на причале; топливо мини-автоцистерной.' FROM locations WHERE slug = 'vlychada-marina-santorini'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'One of the best-loved stops in the Ionian; famous for its Venetian character untouched by the 1953 earthquake. Berth bow- or stern-to on the south/west quay, or at the pontoon on the western shore; sand-rock bottom. The harbour is well sheltered. Water and electricity on the quay; fuel by mini tanker; Wi-Fi (cafe) and plenty of restaurants. In season it gets VERY crowded with charter fleets — arrive early.' FROM locations WHERE slug = 'fiskardo-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Una de las paradas más queridas del Jónico; famoso por su trazado veneciano, que no fue afectado por el terremoto de 1953. Se amarra de proa o de popa al muelle sur/oeste, o al pontón de la orilla oeste; fondo de arena y roca. El puerto está bien abrigado. Agua y electricidad en el muelle; combustible con mini camión cisterna; hay Wi-Fi (cafetería) y abundantes restaurantes. En temporada se llena MUCHO con las flotas de chárter: llegue temprano.' FROM locations WHERE slug = 'fiskardo-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Одна из самых любимых стоянок Ионического моря; знаменит венецианским обликом, не пострадавшим от землетрясения 1953 года. Швартуются носом или кормой к южной/западной набережной либо к понтону у западного берега; грунт песок-камень. Гавань хорошо защищена. Вода и электричество на набережной; топливо мини-автоцистерной; есть Wi-Fi (кафе) и множество ресторанов. В сезон ОЧЕНЬ переполнена чартерными флотилиями — приходите пораньше.' FROM locations WHERE slug = 'fiskardo-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The capital of Paksos; a channel-harbour behind the islet of Agios Nikolaos. The NORTHERN entrance is deep (~15 m); the SOUTHERN entrance is ~2 m — SHALLOW, deep-draught boats should enter from the north. Mud bottom, good holding. Well sheltered from north and west winds. Water and fuel by tanker truck; restaurant-bars line the quay. Crowding (per source): VERY crowded in summer; ferry/tour boat traffic is heavy and anchor chains often get fouled — use a trip line.' FROM locations WHERE slug = 'gaios-limani-paksos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La capital de Paksos; un puerto-canal detrás del islote de Agios Nikolaos. La entrada NORTE es profunda (~15 m); la entrada SUR tiene ~2 m: es POCO PROFUNDA, las embarcaciones de mucho calado deben entrar por el norte. Fondo de fango, buen agarre. Bien abrigado de los vientos del norte y del oeste. Agua y combustible con camión cisterna; a lo largo del muelle se alinean restaurantes y bares. Afluencia (según la fuente): en verano está MUY concurrido; el tráfico de ferris y barcos de excursión es intenso y las cadenas de las anclas se enredan a menudo: use un orinque.' FROM locations WHERE slug = 'gaios-limani-paksos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Столица острова Paksos; гавань-канал за островком Agios Nikolaos. СЕВЕРНЫЙ вход глубокий (~15 м); ЮЖНЫЙ вход ~2 м — МЕЛКО, судам с большой осадкой входить с севера. Грунт ил, держит хорошо. Хорошо защищена от северных и западных ветров. Вода и топливо автоцистерной; вдоль набережной тянутся рестораны и бары. Загруженность (по данным источника): летом ОЧЕНЬ многолюдно; интенсивное движение паромов и экскурсионных судов, якорные цепи часто перепутываются — используйте буйреп.' FROM locations WHERE slug = 'gaios-limani-paksos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Charming bay at the northern tip of Paksos; anchor over the white-sand shallows, or take lines ashore in the northern part; there are only a few places on the quay. Well sheltered from northerly winds. CAUTION: the bottom is VERY COMPACT mud — if the anchor digs in well, it can become hard to break out. Water on the quay; in the village there are showers-WC (Seaside bar), restaurants, small markets, a butcher and a fish stall.' FROM locations WHERE slug = 'lakka-koyu-paksos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Encantadora cala en el extremo norte de Paksos; se fondea sobre los bajos de arena blanca o se llevan cabos a tierra en la parte norte; en el muelle hay pocas plazas. Bien abrigada de los vientos del norte. ATENCIÓN: el fondo es de limo MUY COMPACTO; si el ancla se entierra a fondo, puede resultar difícil levarla. Agua en el muelle; en el pueblo hay duchas y WC (Seaside bar), restaurantes, pequeños supermercados, carnicería y puesto de pescado.' FROM locations WHERE slug = 'lakka-koyu-paksos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Прелестная бухта на северной оконечности Paksos; встают на якорь над белопесчаными отмелями или заводят концы на берег в северной части; на причале мест мало. Хорошо защищена от северных ветров. ВНИМАНИЕ: грунт — ОЧЕНЬ ПЛОТНЫЙ ил; если якорь основательно зароется, поднять его может быть трудно. Вода на причале; в деревне есть душ и WC (Seaside bar), рестораны, маленькие магазины, мясная лавка и рыбный прилавок.' FROM locations WHERE slug = 'lakka-koyu-paksos'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
-- --- i18n_tur5.json (i18n-tur5) ---
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Adaboğazı (Akvaryum) Bay, located on the southern side of the Bodrum peninsula between the bays of Bitez and Gümbet, is an anchorage famous for its crystal-clear water. It provides adequate shelter from westerly winds; boats may swing at anchor or take stern lines ashore. The waters around the central islet are shallow, and the bay becomes very crowded during the day with daily excursion boats.' FROM locations WHERE slug = 'adabogazi-akvaryum-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La cala de Adaboğazı (Akvaryum), situada al sur de la península de Bodrum entre las calas de Bitez y Gümbet, es un fondeadero famoso por sus aguas cristalinas. Ofrece protección suficiente frente a los vientos del oeste; las embarcaciones pueden quedar fondeadas al borneo o amarrarse de popa con cabos a tierra. Las inmediaciones del islote central son poco profundas y la cala se llena mucho durante el día con los barcos de excursión.' FROM locations WHERE slug = 'adabogazi-akvaryum-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта Adaboğazı (Akvaryum), расположенная на южной стороне полуострова Bodrum между бухтами Bitez и Gümbet, — якорная стоянка, знаменитая своей прозрачной водой. Она обеспечивает достаточную защиту от западных ветров; яхты могут свободно стоять на якоре или швартоваться кормой к берегу с заведёнными на берег концами. Вокруг центрального островка мелководье, и днём бухта бывает очень переполнена прогулочными судами.' FROM locations WHERE slug = 'adabogazi-akvaryum-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Kissebükü (Alakışla Bükü), on the northern shore of the Gulf of Gökova in the Karaburun and Yıldız Adası area, is a bay surrounded by mountains and difficult to reach by land; it is one of the important ports of call for blue-cruise boats. The indentations along the shoreline provide shelter from westerly and northerly winds; the bay is open to the south and southeast. The bottom is sand and rock; you can anchor and take stern lines ashore. On the beach side there are ruins from the Byzantine period (Anastasiopolis).' FROM locations WHERE slug = 'kissebuku-alakisla-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Kissebükü (Alakışla Bükü), en la costa norte del golfo de Gökova, en la zona de Karaburun y Yıldız Adası, es una cala rodeada de montañas y de difícil acceso por tierra; es una de las escalas importantes de las goletas de crucero azul. Las entrantes del litoral ofrecen protección frente a los vientos del oeste y del norte; la cala está abierta al sur y al sureste. El fondo es de arena y roca; se puede fondear y amarrar de popa con cabos a tierra. En el lado de la playa hay ruinas de la época bizantina (Anastasiopolis).' FROM locations WHERE slug = 'kissebuku-alakisla-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Kissebükü (Alakışla Bükü) на северном берегу залива Gökova, в районе Karaburun и Yıldız Adası, — бухта, окружённая горами и труднодоступная с суши; это одна из важных стоянок яхт «голубого круиза». Изгибы береговой линии дают укрытие от западных и северных ветров; бухта открыта югу и юго-востоку. Грунт — песок и камни; можно встать на якорь с подачей кормовых концов на берег. Со стороны пляжа находятся руины византийской эпохи (Anastasiopolis).' FROM locations WHERE slug = 'kissebuku-alakisla-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'An archipelago of five small islands and two islets belonging to Marmaris, on the southern shore of the Gulf of Gökova; it is one of the principal anchoring areas on blue-cruise routes. Along its eastern side lie anchorages such as Küfre Koyu, Bekar Limanı and Uzun Liman; Güllü Ada is known as a good diving spot.' FROM locations WHERE slug = 'yedi-adalar-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Archipiélago formado por cinco islas pequeñas y dos islotes pertenecientes a Marmaris, en la costa sur del golfo de Gökova; es una de las principales zonas de fondeo de las rutas del crucero azul. En su lado oriental se suceden fondeaderos como Küfre Koyu, Bekar Limanı y Uzun Liman; Güllü Ada es conocida como un buen punto de buceo.' FROM locations WHERE slug = 'yedi-adalar-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Архипелаг из пяти небольших островов и двух островков, относящийся к Marmaris, на южном берегу залива Gökova; это один из главных якорных районов на маршрутах «голубого круиза». Вдоль восточной стороны расположены якорные стоянки Küfre Koyu, Bekar Limanı и Uzun Liman; Güllü Ada известен как хорошее место для дайвинга.' FROM locations WHERE slug = 'yedi-adalar-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'In Bitez Bay, on the southern side of the Bodrum peninsula, boats can anchor in depths of 4-10 m outside the mooring buoys. The northern side of the bay provides adequate shelter except from southerly winds. The quay on the eastern side is managed by the Bitez operator and has a berthing capacity of 12 boats.' FROM locations WHERE slug = 'bitez-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'En la cala de Bitez, al sur de la península de Bodrum, las embarcaciones pueden fondear en profundidades de 4-10 m por fuera de las boyas de amarre. La orilla norte de la cala ofrece protección suficiente salvo con vientos del sur. El muelle del lado este lo gestiona la empresa Bitez y tiene capacidad de atraque para 12 embarcaciones.' FROM locations WHERE slug = 'bitez-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'В бухте Bitez на южной стороне полуострова Bodrum яхты могут встать на якорь на глубинах 4-10 м мористее швартовных буёв. Северный берег бухты даёт достаточную защиту от всех ветров, кроме южных. Причал в восточной части находится в ведении оператора Bitez, вместимость у стенки — 12 судов.' FROM locations WHERE slug = 'bitez-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A shelter operated by the Gündoğan Fisheries Cooperative, with a 199 m main breakwater and capacity for 50 boats; the depth inside the harbour is 3 m. Boats can moor stern-to outside the breakwater in depths of 4-6 m, or anchor in the bay in 7-8 m; the bay is open to northerly winds, and attention must be paid to the reefs extending from the western tip of Karaca Burnu. Water, electricity, fuel, ice and gas bottles are available.' FROM locations WHERE slug = 'gundogan-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio gestionado por la Cooperativa Pesquera de Gündoğan, con un rompeolas principal de 199 m y capacidad para 50 embarcaciones; la profundidad dentro del puerto es de 3 m. Las embarcaciones pueden amarrarse de popa por fuera del rompeolas en profundidades de 4-6 m, o fondear en la cala en 7-8 m; la cala está abierta a los vientos del norte y hay que prestar atención a los arrecifes que se extienden desde el extremo occidental de Karaca Burnu. Hay agua, electricidad, combustible, hielo y bombonas de gas.' FROM locations WHERE slug = 'gundogan-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Укрытие, находящееся в ведении рыболовецкого кооператива Gündoğan, с главным молом длиной 199 м и вместимостью 50 судов; глубина внутри гавани — 3 м. Снаружи мола можно швартоваться кормой к берегу на глубинах 4-6 м либо встать на якорь в бухте на 7-8 м; бухта открыта северным ветрам, и следует остерегаться рифов, тянущихся от западной оконечности мыса Karaca Burnu. Есть вода, электричество, топливо, лёд и газовые баллоны.' FROM locations WHERE slug = 'gundogan-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A fishing shelter 22 km from the centre of Bodrum, operated by the Akyarlar Fisheries Cooperative, with a 120 m breakwater and capacity for 65 boats. Off the beach you can anchor on a sand bottom in depths of 4-8 m; it is sheltered from westerly winds but open to southerlies. Water and electricity are available.' FROM locations WHERE slug = 'akyarlar-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Refugio pesquero a 22 km del centro de Bodrum, gestionado por la Cooperativa Pesquera de Akyarlar, con un rompeolas de 120 m y capacidad para 65 embarcaciones. Frente a la playa se puede fondear sobre fondo de arena en profundidades de 4-8 m; está protegido de los vientos del oeste pero abierto a los del sur. Dispone de agua y electricidad.' FROM locations WHERE slug = 'akyarlar-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Рыбацкое укрытие в 22 км от центра Bodrum, находящееся в ведении рыболовецкого кооператива Akyarlar, с молом длиной 120 м и вместимостью 65 судов. Перед пляжем можно встать на якорь на песчаном грунте на глубинах 4-8 м; стоянка укрыта от западных ветров, но открыта южным. Есть вода и электричество.' FROM locations WHERE slug = 'akyarlar-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Mazı Bay, close to Bodrum, untouched by development and still green in character, is a calm anchorage with exceptionally clean water. Along its shore there are a few simple guesthouses and fish restaurants.' FROM locations WHERE slug = 'mazi-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La cala de Mazı, cercana a Bodrum, no urbanizada y que conserva su carácter verde, es un fondeadero tranquilo de aguas extraordinariamente limpias. En su orilla hay unas pocas pensiones sencillas y restaurantes de pescado.' FROM locations WHERE slug = 'mazi-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Бухта Mazı недалеко от Bodrum, не тронутая застройкой и сохранившая свою зелень, — спокойная якорная стоянка с исключительно чистой водой. На берегу есть несколько простых пансионов и рыбных ресторанов.' FROM locations WHERE slug = 'mazi-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A Petrol Ofisi (As-Mira) fuel station operates within D-Marin Turgutreis Marina. According to Asmira Marine''s station list, the fuel pier is 100 m long and has a capacity of 150.000 litres.' FROM locations WHERE slug = 'd-marin-turgutreis-yakit'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Dentro de D-Marin Turgutreis Marina opera una estación de combustible de Petrol Ofisi (As-Mira). Según la lista de estaciones de Asmira Marine, el pantalán de combustible tiene 100 m de longitud y una capacidad de 150.000 litros.' FROM locations WHERE slug = 'd-marin-turgutreis-yakit'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'На территории марины D-Marin Turgutreis работает топливная станция Petrol Ofisi (As-Mira). Согласно списку станций Asmira Marine, топливный пирс имеет длину 100 м и ёмкость 150.000 литров.' FROM locations WHERE slug = 'd-marin-turgutreis-yakit'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'At Palamutbükü, one of the most famous beaches of Datça, there is a shelter for yachts and fishing boats at the western end of the beach. The depth inside the shelter is around 4 m; the quay has capacity for about 30 boats, and outside you can anchor in 10 m and moor stern-to. The bay is open to southerly winds and sheltered from northerlies; keep clear of the outer breakwater on entry, as the water shoals at the end of the breakwater.' FROM locations WHERE slug = 'palamutbuku-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'En Palamutbükü, una de las playas más famosas de Datça, hay un refugio para yates y barcos de pesca al oeste de la playa. La profundidad dentro del refugio es de unos 4 m; el muelle tiene capacidad para unas 30 embarcaciones, y por fuera se puede fondear en 10 m y amarrarse de popa. La cala está abierta a los vientos del sur y protegida de los del norte; en la entrada hay que mantenerse apartado del rompeolas exterior, ya que el agua pierde fondo al final del rompeolas.' FROM locations WHERE slug = 'palamutbuku-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'В Palamutbükü, на одном из самых известных пляжей Datça, в западной части пляжа есть укрытие для яхт и рыбацких лодок. Глубина внутри укрытия — около 4 м; у причала могут разместиться примерно 30 судов, снаружи можно встать на якорь на 10 м и ошвартоваться кормой к берегу. Бухта открыта южным ветрам и укрыта от северных; при входе держитесь на расстоянии от внешнего мола — у его оконечности глубина резко уменьшается.' FROM locations WHERE slug = 'palamutbuku-balikci-barinagi'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The harbour quay in the centre of Datça is run by the municipality; the quay has a berthing capacity of 60 boats. Anchoring is in 5 m, on a bottom of dense weed and sand; the harbour is open to the south, and attention must be paid to the ''Datça meltemi'' descending through the mountain pass and to the violent squalls around Deveboynu (Krio) Point.' FROM locations WHERE slug = 'datca-yat-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'El muelle del puerto en el centro de Datça lo gestiona el ayuntamiento; el muelle tiene capacidad de atraque para 60 embarcaciones. Se fondea en 5 m, sobre fondo de arena con abundantes algas; el puerto está abierto al sur y hay que prestar atención al ''meltemi de Datça'' que baja por el paso de montaña y a los fuertes chubascos de viento en las inmediaciones del cabo Deveboynu (Krio).' FROM locations WHERE slug = 'datca-yat-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Причал гавани в центре Datça находится в ведении муниципалитета; вместимость причала — 60 судов. Якорная стоянка на глубине 5 м, грунт — густые водоросли и песок; гавань открыта югу, и следует остерегаться «датчинского мельтеми» (Datça meltemi), скатывающегося с горного перевала, а также жестоких шквалов у мыса Deveboynu (Krio).' FROM locations WHERE slug = 'datca-yat-limani'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'About 1,5 miles south of the centre of Datça, Kargı Bay, one of the bays closest to town, has clear turquoise water. It is an enclosed, calm bay unaffected by northerly and southwesterly winds.' FROM locations WHERE slug = 'kargi-koyu-datca-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'A aproximadamente 1,5 millas al sur del centro de Datça, la cala de Kargı, una de las más cercanas al pueblo, tiene aguas turquesas y cristalinas. Es una cala cerrada y tranquila, que no se ve afectada por los vientos del norte ni del suroeste.' FROM locations WHERE slug = 'kargi-koyu-datca-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Примерно в 1,5 мили к югу от центра Datça лежит бухта Kargı — одна из ближайших к городку, с прозрачной бирюзовой водой. Это закрытая спокойная бухта, не подверженная северным и юго-западным ветрам.' FROM locations WHERE slug = 'kargi-koyu-datca-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Bozuk Bükü, at the southern tip of the Bozburun Peninsula, is the natural harbour of the ancient city of Loryma; the ruins of ancient walls and a fortress stand on the hill commanding the entrance to the bay. The entire bay is a protected (SİT) area; inside there are three restaurant jetties named Ali Baba, Sailor''s Paradise and Loryma, none of which has water or electricity. Boats go alongside the jetties or anchor and take a stern line ashore. The depth at the jetties is about 8-10 m, and 12-15 m in the buoy/anchoring area; the bottom is weedy — the anchor should be dropped on a sandy patch and you must make sure it has dug in well. The coves within the bay give excellent shelter from the prevailing westerly winds.' FROM locations WHERE slug = 'bozukkale-loryma-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Bozuk Bükü, en el extremo sur de la península de Bozburun, es el puerto natural de la antigua ciudad de Loryma; en la colina que domina la entrada de la cala se alzan las ruinas de las murallas y la fortaleza antiguas. Toda la cala es zona protegida (SİT); en su interior hay tres pantalanes de restaurante llamados Ali Baba, Sailor''s Paradise y Loryma, ninguno de los cuales dispone de agua ni electricidad. Las embarcaciones atracan en los pantalanes o fondean y toman un cabo de popa a tierra. La profundidad en los pantalanes es de unos 8-10 m, y de 12-15 m en la zona de boyas y fondeo; el fondo tiene algas: el ancla debe echarse sobre una zona de arena y hay que asegurarse de que ha agarrado bien. Las ensenadas interiores de la cala ofrecen una protección excelente frente a los vientos dominantes del oeste.' FROM locations WHERE slug = 'bozukkale-loryma-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Bozuk Bükü на южной оконечности полуострова Bozburun — естественная гавань античного города Loryma; на холме, господствующем над входом в бухту, стоят руины древних стен и крепости. Вся бухта является охраняемой зоной (SİT); внутри расположены три ресторанных причала — Ali Baba, Sailor''s Paradise и Loryma, ни на одном из них нет ни воды, ни электричества. Яхты швартуются к причалам либо встают на якорь с подачей кормового конца на берег. Глубина у причалов около 8-10 м, на буйно-якорной акватории — 12-15 м; грунт заросший водорослями — якорь следует отдавать на песчаном пятне и убедиться, что он хорошо забрал. Внутренние бухточки залива дают отличную защиту от господствующих западных ветров.' FROM locations WHERE slug = 'bozukkale-loryma-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'Near Datça, this pine-covered bay is properly named Parmak Bükü, though the locals call it Domuz Çukuru. You can anchor in depths of 6-7 m along the southeastern shore; the bay is open to southerly winds.' FROM locations WHERE slug = 'domuz-cukuru-parmak-buku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cerca de Datça, esta cala cubierta de pinares se llama en realidad Parmak Bükü, aunque los lugareños la conocen como Domuz Çukuru. Se puede fondear en profundidades de 6-7 m a lo largo de la costa sureste; la cala está abierta a los vientos del sur.' FROM locations WHERE slug = 'domuz-cukuru-parmak-buku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Недалеко от Datça лежит покрытая сосновыми лесами бухта, настоящее название которой Parmak Bükü, хотя местные жители зовут её Domuz Çukuru. Вдоль юго-восточного берега можно встать на якорь на глубинах 6-7 м; бухта открыта южным ветрам.' FROM locations WHERE slug = 'domuz-cukuru-parmak-buku-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The harbour on the northern coast of Datça facing the Aegean (towards Gökova); the pier used by the Bodrum ferry is here. In the small inner basin the depth is 4-6 m, the bottom is mostly sand and weed with good holding; the harbour gives shelter from the wind all year round, but in heavy weather beware of the confused sea at the entrance to the large basin.' FROM locations WHERE slug = 'kormen-limani-datca'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Puerto en la costa norte de Datça, orientado al Egeo (hacia Gökova); aquí está el muelle donde atraca el ferry de Bodrum. En la pequeña dársena interior la profundidad es de 4-6 m, con fondo mayoritariamente de arena y algas de buen agarre; el puerto ofrece abrigo del viento todo el año, pero con mal tiempo hay que tener cuidado con la mar confusa en la entrada de la dársena grande.' FROM locations WHERE slug = 'kormen-limani-datca'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Гавань на северном берегу Datça, обращённом к Эгейскому морю (в сторону Gökova); здесь находится пирс, к которому подходит паром из Bodrum. В маленьком внутреннем бассейне глубина 4-6 м, грунт преимущественно песок с водорослями, держит хорошо; гавань круглый год даёт укрытие от ветра, однако в свежую погоду у входа в большой бассейн следует остерегаться толчеи.' FROM locations WHERE slug = 'kormen-limani-datca'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'The wide bay (Limanağzı/Bayındır) 1 mile south of Kaş can only be reached by sea; a finger-like point in the middle divides the bay in two, and both sides give adequate shelter from the prevailing wind. Off the beach, anchor in 5-8 m for a short stop or in 12-15 m for an overnight stay; close inshore the bottom is dense weed and sand. The bay is open to northerly winds, but in the summer months this is usually not a problem. There are three small beaches and a few small restaurants in the bay.' FROM locations WHERE slug = 'bayindir-limanagzi-kas-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'La amplia bahía (Limanağzı/Bayındır), a 1 milla al sur de Kaş, solo es accesible por mar; una punta en forma de dedo en el centro divide la bahía en dos, y ambas orillas ofrecen protección suficiente frente al viento dominante. Frente a la playa se fondea en 5-8 m para una parada corta y en 12-15 m para pasar la noche; cerca de la orilla el fondo es de arena con abundantes algas. La bahía está abierta a los vientos del norte, pero en los meses de verano esto no suele ser un problema. En la bahía hay tres pequeñas playas y algunos restaurantes pequeños.' FROM locations WHERE slug = 'bayindir-limanagzi-kas-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Просторная бухта (Limanağzı/Bayındır) в 1 миле к югу от Kaş доступна только с моря; выступающий посередине узкий мыс делит бухту надвое, и обе стороны дают достаточную защиту от господствующего ветра. У пляжа для короткой остановки встают на якорь на 5-8 м, для ночёвки — на 12-15 м; вблизи берега грунт — густые водоросли и песок. Бухта открыта северным ветрам, но летом это обычно не создаёт проблем. В бухте три маленьких пляжа и несколько небольших ресторанов.' FROM locations WHERE slug = 'bayindir-limanagzi-kas-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'These are the bays around the three natural harbours of the ancient city of Phaselis (the North Harbour, the War Harbour and the Sheltered Harbour), north of Tekirova; the area lies within the boundaries of the Beydağları/Olimpos national park and archaeological site. Under circular no. 2026/5 of the Governorship of Antalya, daily tour boats operating around Phaselis are required to use virtual anchoring or mooring buoys.' FROM locations WHERE slug = 'phaselis-koylari-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Son las calas situadas en torno a los tres puertos naturales de la antigua ciudad de Phaselis (el Puerto Norte, el Puerto de Guerra y el Puerto Abrigado), al norte de Tekirova; la zona se encuentra dentro de los límites del parque nacional y del yacimiento arqueológico de Beydağları/Olimpos. Mediante la circular n.º 2026/5 de la Gobernación de Antalya se ha impuesto a los barcos de excursiones diarias que operan en los alrededores de Phaselis la obligación de usar anclaje virtual o boyas de amarre.' FROM locations WHERE slug = 'phaselis-koylari-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Это бухты вокруг трёх естественных гаваней античного города Phaselis (Северной гавани, Военной гавани и Защищённой гавани) к северу от Tekirova; район находится в границах национального парка Beydağları/Olimpos и археологического памятника. Циркуляром губернаторства Antalya № 2026/5 для судов однодневных экскурсий, работающих в окрестностях Phaselis, введено требование использовать виртуальную якорную стоянку или швартовные буи.' FROM locations WHERE slug = 'phaselis-koylari-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A sheltered cove between Kemer and Adrasan, at the foot of the steep slopes of Musa Dağı, surrounded by mountains on three sides; there is no access by land — the cove can only be reached from the sea. It lies within the boundaries of the Beydağları Coastal National Park and is a first-degree natural protected area; it is the first stop of the day-tour boats departing from Adrasan harbour. It is 2,5 miles northeast of Çavuş Burnu; anchor wherever a free spot is found in 5-10 m of water, and off the beach the bottom drops to 6-13 m. The bottom is sand with good holding; strong northerly winds send swell inside, so mooring stern-to with lines ashore on the western side is recommended. The above-water rocks at the cove entrance and in the southwest corner must be avoided.' FROM locations WHERE slug = 'ceneviz-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala abrigada entre Kemer y Adrasan, al pie de las escarpadas laderas del Musa Dağı, rodeada de montañas por tres lados; no hay acceso por tierra y a la cala solo se puede llegar por mar. Se encuentra dentro de los límites del Parque Nacional Costero de Beydağları y es un espacio natural protegido de primer grado; es la primera escala de los barcos de excursión diaria que salen del puerto de Adrasan. Está a 2,5 millas al nordeste de Çavuş Burnu; se fondea en cualquier lugar libre en 5-10 m de agua, y frente a la playa el fondo desciende hasta 6-13 m. El fondo es de arena y el agarre es bueno; los vientos fuertes del norte meten mar de fondo en la cala, por lo que se recomienda amarrar de popa con cabos a tierra en la orilla oeste. Deben evitarse las rocas emergentes de la entrada de la cala y de su rincón suroeste.' FROM locations WHERE slug = 'ceneviz-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Защищённая бухта между Kemer и Adrasan, у подножия крутых склонов горы Musa Dağı, с трёх сторон окружённая горами; сообщения по суше нет — попасть в бухту можно только с моря. Находится в границах прибрежного национального парка Beydağları и является природоохранной зоной первой категории; это первая остановка прогулочных судов, выходящих в однодневные туры из гавани Adrasan. Расположена в 2,5 милях к северо-востоку от мыса Çavuş Burnu; встать на якорь можно на любом свободном месте на глубине 5-10 м, перед пляжем дно опускается до 6-13 м. Грунт — песок, держит хорошо; сильные северные ветры заводят в бухту зыбь, поэтому у западного берега рекомендуется швартоваться кормой с заводкой концов на берег. Следует остерегаться надводных камней у входа в бухту и в её юго-западном углу.' FROM locations WHERE slug = 'ceneviz-limani-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A secluded cove on the slopes of Musa Dağı, within the western boundaries of the Beydağları Coastal National Park; by land it can only be reached with off-road vehicles. It is one of the indispensable stops of the daily boat tours departing from Adrasan, and the boats take a swimming break here. It lies hidden among high mountains 1,5 miles northwest of Çavuş Burnu; you can anchor in 5-6 m of water and swing freely, the bottom is sand. The cove gives protection from all directions except northerly winds; the wide entrance between the two rocky headlands is free of obstructions.' FROM locations WHERE slug = 'sazak-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Cala solitaria en las laderas del Musa Dağı, dentro de los límites occidentales del Parque Nacional Costero de Beydağları; por tierra solo se puede llegar con vehículos todoterreno. Es una de las escalas imprescindibles de las excursiones diarias en barco que salen de Adrasan, y las embarcaciones hacen aquí una pausa para el baño. Está escondida entre altas montañas, a 1,5 millas al noroeste de Çavuş Burnu; se puede fondear en 5-6 m de agua y quedar borneando; el fondo es de arena. La cala ofrece protección de todas las direcciones salvo de los vientos del norte; la amplia bocana entre las dos puntas rocosas está libre de obstáculos.' FROM locations WHERE slug = 'sazak-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Уединённая бухта на склонах горы Musa Dağı, в западных границах прибрежного национального парка Beydağları; по суше добраться сюда можно только на внедорожнике. Это одна из обязательных остановок однодневных прогулочных туров, выходящих из Adrasan, — суда делают здесь купальную стоянку. Бухта скрыта среди высоких гор в 1,5 милях к северо-западу от мыса Çavuş Burnu; можно встать на якорь на глубине 5-6 м и свободно отстаиваться с разворотом на якоре; грунт — песок. Бухта защищена со всех направлений, кроме северных ветров; широкий вход между двумя скалистыми мысами свободен от препятствий.' FROM locations WHERE slug = 'sazak-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'en', NULL, 'A wide bay in the Kumluca district on Turkey''s southern coast, stretching for more than 2,5 km; Adrasan, with its back against the Beydağları mountains, is surrounded by pine trees. The daily boat tours to Suluada and to the coves of Sazak, Ceneviz and Korsan depart from the harbour in this bay.' FROM locations WHERE slug = 'adrasan-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'es', NULL, 'Amplia bahía en el distrito de Kumluca, en la costa sur de Turquía, que se extiende a lo largo de más de 2,5 km; Adrasan, respaldada por los montes Beydağları, está rodeada de pinos. Del puerto de esta bahía salen las excursiones diarias en barco a Suluada y a las calas de Sazak, Ceneviz y Korsan.' FROM locations WHERE slug = 'adrasan-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO location_i18n (location_id, locale, name, description)
SELECT id, 'ru', NULL, 'Широкая бухта в районе Kumluca на южном побережье Турции, протянувшаяся более чем на 2,5 км; Adrasan, прикрытый с тыла горами Beydağları, окружён сосновыми лесами. Из гавани этой бухты отправляются однодневные прогулочные туры на Suluada и в бухты Sazak, Ceneviz и Korsan.' FROM locations WHERE slug = 'adrasan-koyu-demirleme'
ON CONFLICT (location_id, locale) DO UPDATE SET description = EXCLUDED.description;
